import React from 'react';

interface LogoProps {
  variant?: 'default' | 'white' | 'dark';
  className?: string;
}

export const Logo: React.FC<LogoProps> = ({ variant = 'default', className = '' }) => {
  const isWhite = variant === 'white';

  const mainColor = isWhite ? '#FFFFFF' : '#E0621B';
  const subColor = isWhite ? 'rgba(255,255,255,0.6)' : '#1A1A1A';

  return (
    <div className={`flex items-center gap-3 group transition-all duration-300 ${className}`}>
      <div className="flex flex-col">
        <div className="flex items-baseline gap-1">
          <span 
            className="text-2xl md:text-3xl font-bold tracking-tighter font-display leading-none" 
            style={{ color: mainColor }}
          >
            MASUMA
          </span>
          <div className="w-2 h-2 rounded-full bg-masuma-orange group-hover:animate-ping" style={{ backgroundColor: mainColor }}></div>
        </div>
        <span 
          className="text-[0.6rem] md:text-[0.65rem] font-bold tracking-[0.25em] uppercase leading-none mt-1 whitespace-nowrap" 
          style={{ color: subColor }}
        >
          AUTOPARTS EAST AFRICA
        </span>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { 
  LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { ShoppingCart, Users, TrendingUp, AlertTriangle, Loader2, Activity, Clock, Plane, RefreshCw, Database } from 'lucide-react';
import { apiClient, formatCurrency } from '../../utils/apiClient';
import { DashboardStats } from '../../types';

const COLORS = ['#E0621B', '#1A1A1A', '#F59E0B', '#10B981', '#6366F1', '#EC4899'];

interface DashboardHomeProps {
    onNavigate: (module: string) => void;
}

const DashboardHome: React.FC<DashboardHomeProps> = ({ onNavigate }) => {
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [activityLog, setActivityLog] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [sourcingCount, setSourcingCount] = useState(0);

  const fetchData = async () => {
    setIsLoading(true);
    setError(null);
    try {
      // Use standard Promise.allSettled to handle partial failures
      const results = await Promise.allSettled([
          apiClient.get('/admin/stats'),
          apiClient.get('/audit-logs'),
          apiClient.get('/quotes')
      ]);

      if (results[0].status === 'fulfilled') {
          setStats(results[0].value.data);
      } else {
          console.error("Stats fetch error:", results[0].reason);
      }

      if (results[1].status === 'fulfilled') {
          setActivityLog(results[1].value.data.slice(0, 6));
      }

      if (results[2].status === 'fulfilled') {
          const quotes = Array.isArray(results[2].value.data) ? results[2].value.data : [];
          const sourcing = quotes.filter((q: any) => q.type === 'SOURCING' && q.status === 'DRAFT').length;
          setSourcingCount(sourcing);
      }

      // If all failed, show error
      if (results.every(r => r.status === 'rejected')) {
          throw new Error("Could not connect to the database. Please check your internet or server status.");
      }

    } catch (err: any) {
      console.error("Dashboard fetch error", err);
      setError(err.message || "An error occurred while loading dashboard data.");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 60000); 
    return () => clearInterval(interval);
  }, []);

  if (isLoading && !stats) {
    return (
      <div className="flex flex-col items-center justify-center h-96">
        <Loader2 size={48} className="animate-spin text-masuma-orange mb-4" />
        <p className="text-sm font-bold uppercase tracking-widest text-gray-400">Synchronizing ERP Data...</p>
      </div>
    );
  }

  if (error) {
      return (
          <div className="flex flex-col items-center justify-center h-96 text-center max-w-md mx-auto">
              <div className="p-4 bg-red-50 text-red-600 rounded-full mb-4">
                  <Database size={40} />
              </div>
              <h2 className="text-xl font-bold text-masuma-dark mb-2 uppercase">Data Synchronization Failed</h2>
              <p className="text-gray-500 text-sm mb-6">{error}</p>
              <button 
                onClick={fetchData}
                className="flex items-center gap-2 bg-masuma-dark text-white px-6 py-2 rounded font-bold text-sm uppercase hover:bg-masuma-orange transition"
              >
                  <RefreshCw size={16} /> Retry Sync
              </button>
          </div>
      )
  }

  const lineData = stats?.monthlyRevenue?.length ? stats.monthlyRevenue : [{ name: 'No Data', value: 0 }];
  const pieData = stats?.categorySales?.length ? stats.categorySales : [{ name: 'Empty', value: 1 }];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase tracking-tight">Executive Dashboard</h2>
            <p className="text-xs text-gray-500 font-medium">Real-time performance metrics for East Africa Operations</p>
        </div>
        <div className="flex items-center gap-4">
            <button onClick={fetchData} className="p-2 bg-white border border-gray-200 rounded hover:bg-gray-50 text-gray-400 hover:text-masuma-orange transition">
                <RefreshCw size={18} className={isLoading ? 'animate-spin' : ''} />
            </button>
            <div className="text-[10px] text-gray-400 font-bold uppercase tracking-widest border-l pl-4 border-gray-200">
                Live: {new Date().toLocaleTimeString()}
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
        {[
          { label: 'Total Revenue', value: formatCurrency(stats?.totalSales || 0), icon: TrendingUp, color: 'bg-green-500', change: 'Lifetime', link: 'sales_history' },
          { label: 'Sales Today', value: stats?.todaysOrders || 0, icon: ShoppingCart, color: 'bg-blue-500', change: 'Transactions', link: 'sales_history' },
          { label: 'Low Stock', value: stats?.lowStockItems || 0, icon: AlertTriangle, color: 'bg-red-500', change: 'Alerts', link: 'inventory' },
          { label: 'Open Quotes', value: stats?.pendingQuotes || 0, icon: Users, color: 'bg-gray-600', change: 'Sales Pipe', link: 'quotes' },
          { label: 'Sourcing Queue', value: sourcingCount, icon: Plane, color: 'bg-purple-600', change: 'Import Req', link: 'quotes' },
        ].map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link)}
            className="bg-white p-5 rounded-lg shadow-sm border border-gray-100 transition-all duration-300 hover:shadow-xl cursor-pointer hover:border-masuma-orange group overflow-hidden relative"
          >
            <div className="flex justify-between items-start mb-4 relative z-10">
              <div className={`p-3 rounded-xl text-white shadow-lg ${stat.color} group-hover:scale-110 transition-transform duration-300`}>
                <stat.icon size={20} />
              </div>
              <span className={`text-[9px] font-bold px-2 py-0.5 rounded-full uppercase tracking-tighter ${stat.change === 'Import Req' ? 'bg-purple-100 text-purple-700' : 'bg-gray-100 text-gray-600'}`}>
                {stat.change}
              </span>
            </div>
            <div className="relative z-10">
              <div className="text-2xl font-bold text-masuma-dark tracking-tight leading-none mb-1">{stat.value}</div>
              <div className="text-[10px] text-gray-500 uppercase font-bold tracking-widest">{stat.label}</div>
            </div>
            {/* Design accents */}
            <div className="absolute -bottom-4 -right-4 w-16 h-16 bg-gray-50 rounded-full group-hover:bg-masuma-orange/10 transition-colors duration-300"></div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-lg shadow-sm border border-gray-100 flex flex-col">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest flex items-center gap-2">
                <Activity size={16} className="text-masuma-orange" /> Revenue Velocity (6 Mo)
            </h3>
          </div>
          <div className="h-[320px] flex-1">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={lineData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#9CA3AF'}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#9CA3AF'}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1)', fontSize: '12px' }}
                  formatter={(value: number) => [formatCurrency(value), 'Revenue']}
                />
                <Line type="monotone" dataKey="value" stroke="#E0621B" strokeWidth={4} dot={{r: 6, fill: '#E0621B', strokeWidth: 2, stroke: '#fff'}} activeDot={{r: 8, strokeWidth: 0}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-100 flex flex-col">
           <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest mb-8">Inventory Mix</h3>
           <div className="h-[320px] flex-1">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={95}
                    paddingAngle={8}
                    dataKey="value"
                  >
                    {pieData.map((entry: any, index: number) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)' }} />
                  <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{ fontSize: '10px', fontWeight: 'bold', textTransform: 'uppercase' }} />
                </PieChart>
              </ResponsiveContainer>
           </div>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-6 border-b border-gray-50 flex justify-between items-center">
              <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest flex items-center gap-2">
                  <Activity size={18} className="text-masuma-orange" /> Operational Audit Trail
              </h3>
              <button 
                onClick={() => onNavigate('audit')}
                className="text-[10px] font-bold text-gray-400 hover:text-masuma-orange uppercase tracking-wider underline underline-offset-4"
              >
                  View Full Logs
              </button>
          </div>
          <div className="divide-y divide-gray-50">
              {activityLog.length === 0 ? (
                  <div className="p-12 text-center text-gray-400">
                      <Clock size={32} className="mx-auto mb-3 opacity-20" />
                      <p className="text-sm font-medium">No recent ERP activity detected.</p>
                  </div>
              ) : (
                  activityLog.map((log, i) => (
                      <div key={i} className="p-4 px-6 flex items-center justify-between hover:bg-gray-50 transition group">
                          <div className="flex items-center gap-4">
                              <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs font-bold shadow-inner ${
                                  log.type === 'error' ? 'bg-red-50 text-red-600' : 
                                  log.type === 'warning' ? 'bg-orange-50 text-orange-600' : 'bg-gray-100 text-gray-600'
                              }`}>
                                  {log.user.charAt(0)}
                              </div>
                              <div>
                                  <p className="text-sm font-bold text-gray-800 group-hover:text-masuma-orange transition-colors">{log.action.replace(/_/g, ' ')}</p>
                                  <p className="text-[11px] text-gray-400 font-medium">{log.detail}</p>
                              </div>
                          </div>
                          <div className="text-right">
                              <div className="flex items-center justify-end gap-1 text-[10px] font-bold text-gray-400 uppercase">
                                  <Clock size={10} /> {log.time}
                              </div>
                              <div className="text-[9px] font-bold text-masuma-orange uppercase tracking-widest mt-1 opacity-60 group-hover:opacity-100 transition-opacity">{log.user}</div>
                          </div>
                      </div>
                  ))
              )}
          </div>
      </div>
    </div>
  );
};

export default DashboardHome;

import axios from 'axios';

// Robust base URL detection
const getBaseUrl = () => {
  try {
      // @ts-ignore - Vite specific
      const metaEnv = import.meta.env;
      if (metaEnv && metaEnv.VITE_API_URL) {
        return metaEnv.VITE_API_URL;
      }
  } catch (e) {
      // Ignore
  }
  // Default to same origin /api if not specified
  return '/api';
};

export const apiClient = axios.create({
  baseURL: getBaseUrl(),
  timeout: 30000,
});

// Request Interceptor
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('masuma_auth_token');
    if (token) {
      if (!config.headers) {
        config.headers = {} as any;
      }
      (config.headers as any).Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response Interceptor
apiClient.interceptors.response.use(
  (response) => {
      // Validate response structure
      if (response.config.responseType === 'json' && typeof response.data === 'string') {
          try {
              response.data = JSON.parse(response.data);
          } catch (e) {
              console.error("API returned malformed JSON:", response.data);
          }
      }
      return response;
  },
  async (error) => {
    if (error.response?.status === 401) {
        const isLoginRequest = error.config?.url?.includes('/login');
        const isHealthCheck = error.config?.url?.includes('/health');

        if (!isLoginRequest && !isHealthCheck) {
            console.warn("Unauthorized request detected. Clearing local session.");
            localStorage.removeItem('masuma_auth_token');
            localStorage.removeItem('masuma_user');
            if (window.location.pathname !== '/' && !window.location.pathname.includes('login')) {
                 window.location.href = '/?view=LOGIN';
            }
        }
    }
    return Promise.reject(error);
  }
);

export const formatCurrency = (amount: number) => {
  const val = Number(amount);
  if (isNaN(val)) return 'KES 0';

  return new Intl.NumberFormat('en-KE', {
    style: 'currency',
    currency: 'KES',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(val);
};

/**
 * Converts a string into a URL-friendly slug
 */
export const slugify = (text: string): string => {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-')     // Replace spaces with -
    .replace(/[^\w\-]+/g, '') // Remove all non-word chars
    .replace(/\-\-+/g, '-')   // Replace multiple - with single -
    .replace(/^-+/, '')       // Trim - from start of text
    .replace(/-+$/, '');      // Trim - from end of text
};

import React, { useState, useEffect, useRef } from 'react';
import { ArrowRight, ShieldCheck, TrendingUp, Wrench, ChevronLeft, ChevronRight } from 'lucide-react';
import { ViewState, HeroSlide } from '../types';
import { apiClient } from '../utils/apiClient';

interface HeroProps {
    setView: (view: ViewState) => void;
}

const DEFAULT_SLIDES: HeroSlide[] = [
    {
        id: 'default-1',
        title: 'JAPANESE\nPRECISION.\nKENYAN ROADS.',
        subtitle: 'Official Distributor of Masuma Japan. Engineering you can trust for Nairobi\'s toughest driving conditions.',
        image: 'https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?ixlib=rb-1.2.1&auto=format&fit=crop&w=1950&q=80',
        ctaText: 'Explore Catalog',
        ctaLink: 'CATALOG'
    }
];

const Hero: React.FC<HeroProps> = ({ setView }) => {
  const [slides, setSlides] = useState<HeroSlide[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [announcement, setAnnouncement] = useState('');
  const [announcementColor, setAnnouncementColor] = useState('#E0621B');
  const timeoutRef = useRef<any>(null);

  useEffect(() => {
      const fetchSettings = async () => {
          try {
              const res = await apiClient.get('/settings');
              const s = res.data;

              if (s) {
                  if (s.CMS_HERO_SLIDES) {
                      try {
                          const parsed = JSON.parse(s.CMS_HERO_SLIDES);
                          if (Array.isArray(parsed) && parsed.length > 0) {
                              setSlides(parsed);
                          } else {
                              setSlides(DEFAULT_SLIDES);
                          }
                      } catch (e) { 
                          setSlides(DEFAULT_SLIDES);
                      }
                  } else {
                      setSlides(DEFAULT_SLIDES);
                  }

                  if (s.CMS_ANNOUNCEMENT_ENABLED === 'true') {
                      setAnnouncement(s.CMS_ANNOUNCEMENT_TEXT || '');
                      setAnnouncementColor(s.CMS_ANNOUNCEMENT_COLOR || '#E0621B');
                  }
              } else {
                  setSlides(DEFAULT_SLIDES);
              }
          } catch (error) {
              setSlides(DEFAULT_SLIDES);
          }
      };
      fetchSettings();
  }, []);

  const resetTimeout = () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
  };

  useEffect(() => {
      resetTimeout();
      if (slides.length > 1) {
        timeoutRef.current = setTimeout(() => {
            setCurrentSlide((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
        }, 8000); 
      }
      return () => resetTimeout();
  }, [currentSlide, slides]);

  const nextSlide = () => {
      setCurrentSlide(prev => (prev === slides.length - 1 ? 0 : prev + 1));
  };

  const prevSlide = () => {
      setCurrentSlide(prev => (prev === 0 ? slides.length - 1 : prev - 1));
  };

  const getYoutubeEmbedUrl = (url: string) => {
      if (!url) return '';
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      if (!id) return '';

      const origin = typeof window !== 'undefined' ? window.location.origin : '';
      return `https://www.youtube.com/embed/${id}?autoplay=1&mute=1&controls=0&loop=1&playlist=${id}&playsinline=1&rel=0&showinfo=0&iv_load_policy=3&modestbranding=1&enablejsapi=1&origin=${origin}`;
  };

  if (slides.length === 0) {
      return (
        <div className="h-[600px] bg-masuma-dark animate-pulse flex items-center justify-center">
            <div className="text-gray-600 font-bold uppercase tracking-widest">Loading Presentation...</div>
        </div>
      );
  }

  return (
    <>
    {announcement && (
        <div style={{ backgroundColor: announcementColor }} className="text-white text-center text-[10px] md:text-xs font-bold py-2.5 uppercase tracking-[0.2em] relative z-20 shadow-lg">
            {announcement}
        </div>
    )}
    <div className="relative bg-masuma-dark overflow-hidden h-[600px] md:h-[750px] 2xl:h-[850px] group">

      {slides.map((slide, index) => (
          <div 
            key={slide.id}
            className={`absolute inset-0 transition-opacity duration-[1500ms] ease-in-out ${index === currentSlide ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}
          >
             {/* MEDIA BACKGROUND */}
             <div className="absolute inset-0 bg-black">
                 {slide.mediaType === 'youtube' && slide.videoUrl ? (
                     <div className="absolute inset-0 pointer-events-none overflow-hidden">
                        <iframe 
                            src={getYoutubeEmbedUrl(slide.videoUrl)} 
                            className="w-[300%] h-[300%] -ml-[100%] -mt-[100%] md:w-full md:h-full md:ml-0 md:mt-0 object-cover opacity-50"
                            allow="autoplay; encrypted-media; gyroscope; picture-in-picture"
                            title="Background Video"
                        ></iframe>
                     </div>
                 ) : slide.mediaType === 'video' && slide.videoUrl ? (
                     <video 
                        src={slide.videoUrl} 
                        autoPlay 
                        muted 
                        loop 
                        className="absolute inset-0 w-full h-full object-cover opacity-60"
                     ></video>
                 ) : (
                     <div 
                        className="absolute inset-0 bg-cover bg-center transition-transform duration-[20000ms] ease-out opacity-60"
                        style={{ 
                            backgroundImage: `url('${slide.image}')`,
                            transform: index === currentSlide ? 'scale(1.1) rotate(0.02deg)' : 'scale(1)'
                        }}
                     ></div>
                 )}
             </div>

             {/* Gradient Overlays */}
             <div className="absolute inset-0 bg-gradient-to-r from-masuma-dark via-masuma-dark/60 to-transparent"></div>
             <div className="absolute inset-0 bg-gradient-to-t from-masuma-dark via-transparent to-transparent"></div>

             {/* Content */}
             <div className="absolute inset-0 flex items-center">
                <div className="max-w-screen-2xl mx-auto px-6 lg:px-12 w-full">
                    <div className={`lg:w-2/3 transform transition-all duration-1000 delay-500 ${index === currentSlide ? 'translate-y-0 opacity-100' : 'translate-y-12 opacity-0'}`}>

                        <div className="inline-flex items-center gap-3 bg-masuma-orange/10 border border-masuma-orange/30 text-white text-[10px] font-bold px-4 py-2 mb-8 uppercase tracking-[0.3em] backdrop-blur-xl rounded-full">
                            <span className="w-2 h-2 bg-masuma-orange rounded-full animate-pulse shadow-[0_0_10px_#E0621B]"></span>
                            Direct Authorized Distributor
                        </div>

                        <h1 
                            className="text-5xl md:text-7xl 2xl:text-8xl font-bold text-white leading-[0.9] mb-8 font-display whitespace-pre-line tracking-tighter"
                            dangerouslySetInnerHTML={{ 
                                __html: slide.title.replace(/\\n/g, '\n').replace(/KENYAN ROADS\./, '<span class="text-transparent bg-clip-text bg-gradient-to-r from-masuma-orange to-orange-400">KENYAN ROADS.</span>') 
                            }}
                        />

                        <p className="text-lg md:text-xl 2xl:text-2xl text-gray-300 mb-12 max-w-xl 2xl:max-w-3xl font-light leading-relaxed drop-shadow-lg">
                            {slide.subtitle}
                        </p>

                        <div className="flex flex-col sm:flex-row gap-5">
                            <button 
                                onClick={() => setView(slide.ctaLink as any || 'CATALOG')}
                                className="group/btn bg-masuma-orange hover:bg-white text-white hover:text-masuma-orange font-bold py-5 px-12 rounded-full flex items-center justify-center transition-all duration-500 shadow-[0_20px_50px_rgba(224,98,27,0.3)] hover:shadow-[0_20px_50px_rgba(255,255,255,0.2)] transform hover:-translate-y-1 uppercase tracking-[0.2em] text-xs"
                            >
                                {slide.ctaText || 'Learn More'} 
                                <ArrowRight className="ml-3 group-hover/btn:translate-x-2 transition-transform" size={18} />
                            </button>
                            <button 
                                onClick={() => setView('CONTACT')}
                                className="bg-transparent border border-white/20 text-white hover:bg-white/10 font-bold py-5 px-12 rounded-full flex items-center justify-center transition-all duration-300 uppercase tracking-[0.2em] text-xs backdrop-blur-md"
                            >
                                Technical Support
                            </button>
                        </div>
                    </div>
                </div>
             </div>
          </div>
      ))}

      {/* Navigation Indicators */}
      {slides.length > 1 && (
          <>
            <div className="absolute bottom-32 left-0 right-0 z-20 flex justify-center gap-3">
                {slides.map((_, idx) => (
                    <button 
                        key={idx}
                        onClick={() => setCurrentSlide(idx)}
                        className={`h-1 transition-all duration-700 ${idx === currentSlide ? 'bg-masuma-orange w-12' : 'bg-white/20 w-6 hover:bg-white/40'}`}
                    ></button>
                ))}
            </div>

            <button 
                onClick={prevSlide}
                className="absolute top-1/2 left-8 z-20 p-4 rounded-full border border-white/10 bg-white/5 hover:bg-masuma-orange text-white backdrop-blur-md transition-all transform -translate-y-1/2 opacity-0 group-hover:opacity-100 hover:scale-110"
            >
