            <button 
                onClick={nextSlide}
                className="absolute top-1/2 right-8 z-20 p-4 rounded-full border border-white/10 bg-white/5 hover:bg-masuma-orange text-white backdrop-blur-md transition-all transform -translate-y-1/2 opacity-0 group-hover:opacity-100 hover:scale-110"
            >
                <ChevronRight size={24} />
            </button>
          </>
      )}

      {/* Trust Banner */}
      <div className="absolute bottom-0 left-0 right-0 z-20 hidden lg:block">
          <div className="max-w-screen-2xl mx-auto px-12 pb-10">
