                {[
                    { icon: ShieldCheck, title: "12 Month Warranty", desc: "No-hassle replacement on all parts" },
                    { icon: Wrench, title: "Precision Engineering", desc: "OEM spec matched Japanese quality" },
                    { icon: TrendingUp, title: "Maximum Performance", desc: "Optimized for East African terrain" }
                ].map((feature, idx) => (
                    <div key={idx} className="p-8 flex items-center space-x-6 hover:bg-gray-50 transition-colors group cursor-default">
