import React, { useEffect, useState } from 'react';
import { 
  LineChart, Line, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { ShoppingCart, Users, TrendingUp, AlertTriangle, Loader2, Activity, Clock, Plane, RefreshCw } from 'lucide-react';
import { apiClient, formatCurrency } from '../../utils/apiClient';
import { DashboardStats } from '../../types';

const COLORS = ['#E0621B', '#1A1A1A', '#F59E0B', '#10B981', '#6366F1', '#EC4899'];

interface DashboardHomeProps {
    onNavigate: (module: string) => void;
}

const DashboardHome: React.FC<DashboardHomeProps> = ({ onNavigate }) => {
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [activityLog, setActivityLog] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [sourcingCount, setSourcingCount] = useState(0);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      // Fetch stats, logs, and quotes concurrently
      const [statsRes, logsRes, quotesRes] = await Promise.allSettled([
          apiClient.get('/admin/stats'),
          apiClient.get('/audit-logs'),
          apiClient.get('/quotes')
      ]);

      if (statsRes.status === 'fulfilled') {
          setStats(statsRes.value.data);
      }

      if (logsRes.status === 'fulfilled') {
          setActivityLog(Array.isArray(logsRes.value.data) ? logsRes.value.data.slice(0, 6) : []);
      }

      if (quotesRes.status === 'fulfilled') {
          const quotes = Array.isArray(quotesRes.value.data) ? quotesRes.value.data : [];
          const sourcing = quotes.filter((q: any) => q.type === 'SOURCING' && q.status === 'DRAFT').length;
          setSourcingCount(sourcing);
      }

    } catch (err) {
      console.error("Dashboard primary fetch error", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 60000); // Auto-refresh every minute
    return () => clearInterval(interval);
  }, []);

  if (isLoading && !stats) {
    return (
      <div className="flex flex-col items-center justify-center h-96 text-masuma-dark">
        <Loader2 size={40} className="animate-spin text-masuma-orange mb-4" />
        <p className="text-xs font-bold uppercase tracking-widest opacity-50">Loading Dashboard Data...</p>
      </div>
    );
  }

  // Ensure default data for charts if API returns empty
  const lineData = stats?.monthlyRevenue?.length ? stats.monthlyRevenue : [{ name: 'No Data', value: 0 }];
  const pieData = stats?.categorySales?.length ? stats.categorySales : [{ name: 'Empty', value: 1 }];

  return (
    <div className="space-y-6 animate-fade-in">
      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase tracking-tight">Admin Overview</h2>
            <p className="text-xs text-gray-500 font-medium">Real-time business performance</p>
        </div>
        <button 
            onClick={fetchData} 
            className="p-2 bg-white border border-gray-200 rounded text-gray-400 hover:text-masuma-orange transition"
            title="Refresh Data"
        >
            <RefreshCw size={18} className={isLoading ? 'animate-spin' : ''} />
        </button>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
        {[
          { label: 'Total Revenue', value: formatCurrency(stats?.totalSales || 0), icon: TrendingUp, color: 'bg-green-500', link: 'sales_history' },
          { label: 'Orders Today', value: stats?.todaysOrders || 0, icon: ShoppingCart, color: 'bg-blue-500', link: 'sales_history' },
          { label: 'Low Stock', value: stats?.lowStockItems || 0, icon: AlertTriangle, color: 'bg-red-500', link: 'inventory' },
          { label: 'Open Quotes', value: stats?.pendingQuotes || 0, icon: Users, color: 'bg-gray-600', link: 'quotes' },
          { label: 'Sourcing', value: sourcingCount, icon: Plane, color: 'bg-purple-600', link: 'quotes' },
        ].map((stat, i) => (
          <div 
            key={i} 
            onClick={() => onNavigate(stat.link)}
            className="bg-white p-5 rounded-lg shadow-sm border border-gray-100 transition hover:shadow-md cursor-pointer hover:border-masuma-orange group"
          >
            <div className="flex justify-between items-start mb-4">
              <div className={`p-2 rounded-lg text-white shadow-sm ${stat.color} group-hover:scale-110 transition-transform`}>
                <stat.icon size={20} />
              </div>
            </div>
            <div>
              <div className="text-2xl font-bold text-masuma-dark tracking-tight">{stat.value}</div>
              <div className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mt-1">{stat.label}</div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-lg shadow-sm border border-gray-100">
          <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest mb-6">Revenue Trend</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={lineData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#9CA3AF'}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fill: '#9CA3AF'}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                  formatter={(value: number) => [formatCurrency(value), 'Revenue']}
                />
                <Line type="monotone" dataKey="value" stroke="#E0621B" strokeWidth={3} dot={{r: 4, fill: '#E0621B'}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-100">
           <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest mb-6">Inventory Share</h3>
           <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={pieData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {pieData.map((entry: any, index: number) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }} />
                  <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{ fontSize: '10px' }} />
                </PieChart>
              </ResponsiveContainer>
           </div>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-5 border-b border-gray-100 flex justify-between items-center bg-gray-50/50">
              <h3 className="text-sm font-bold text-masuma-dark uppercase tracking-widest flex items-center gap-2">
                  <Activity size={18} className="text-masuma-orange" /> Recent Activity
              </h3>
          </div>
          <div className="divide-y divide-gray-50">
              {activityLog.length === 0 ? (
                  <div className="p-10 text-center text-gray-400 text-sm italic">No recent activity.</div>
              ) : (
                  activityLog.map((log, i) => (
                      <div key={i} className="p-4 flex items-center justify-between hover:bg-gray-50 transition group">
                          <div className="flex items-center gap-4">
                              <div className={`w-10 h-10 rounded-full flex items-center justify-center text-xs font-bold ${
                                  log.type === 'error' ? 'bg-red-50 text-red-600' : 
                                  log.type === 'warning' ? 'bg-orange-50 text-orange-600' : 'bg-gray-100 text-gray-600'
                              }`}>
                                  {log.user ? log.user.charAt(0) : 'S'}
                              </div>
                              <div>
                                  <p className="text-sm font-bold text-gray-800 group-hover:text-masuma-orange transition-colors">{log.action ? log.action.replace(/_/g, ' ') : 'System Action'}</p>
                                  <p className="text-xs text-gray-500">{log.detail}</p>
                              </div>
                          </div>
                          <div className="text-right">
                              <div className="flex items-center gap-1 text-[10px] text-gray-400 font-bold uppercase">
                                  <Clock size={10} /> {log.time}
                              </div>
                              <div className="text-[10px] text-masuma-orange font-bold uppercase mt-1">{log.user || 'SYSTEM'}</div>
                          </div>
                      </div>
                  ))
              )}
          </div>
      </div>
    </div>
  );
};

export default DashboardHome;

