import React, { useState, useEffect, useRef } from 'react';
import { ArrowRight, ShieldCheck, TrendingUp, Wrench, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';
import { ViewState, HeroSlide } from '../types';
import { apiClient } from '../utils/apiClient';

interface HeroProps {
    setView: (view: ViewState) => void;
}

const DEFAULT_SLIDES: HeroSlide[] = [
    {
        id: 'default-1',
        title: 'JAPANESE\nPRECISION.\nKENYAN GRIT.',
        subtitle: 'Upgrade your ride with parts engineered to survive Nairobi\'s toughest roads.',
        image: 'https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?ixlib=rb-1.2.1&auto=format&fit=crop&w=1950&q=80',
        ctaText: 'Browse Catalog',
        ctaLink: 'CATALOG'
    }
];

const Hero: React.FC<HeroProps> = ({ setView }) => {
  const [slides, setSlides] = useState<HeroSlide[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [announcement, setAnnouncement] = useState('');
  const [announcementColor, setAnnouncementColor] = useState('#E0621B');
  const timeoutRef = useRef<any>(null);

  useEffect(() => {
      const fetchSettings = async () => {
          try {
              const res = await apiClient.get('/settings');
              const s = res.data;

              if (s) {
                  if (s.CMS_HERO_SLIDES) {
                      try {
                          const parsed = JSON.parse(s.CMS_HERO_SLIDES);
                          if (Array.isArray(parsed) && parsed.length > 0) {
                              setSlides(parsed);
                          } else {
                              setSlides(DEFAULT_SLIDES);
                          }
                      } catch (e) { 
                          setSlides(DEFAULT_SLIDES);
                      }
                  } else {
                      setSlides(DEFAULT_SLIDES);
                  }

                  if (s.CMS_ANNOUNCEMENT_ENABLED === 'true') {
                      setAnnouncement(s.CMS_ANNOUNCEMENT_TEXT || '');
                      setAnnouncementColor(s.CMS_ANNOUNCEMENT_COLOR || '#E0621B');
                  }
              } else {
                  setSlides(DEFAULT_SLIDES);
              }
          } catch (error) {
              setSlides(DEFAULT_SLIDES);
          }
      };
      fetchSettings();
  }, []);

  const resetTimeout = () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
  };

  useEffect(() => {
      resetTimeout();
      if (slides.length > 1) {
        timeoutRef.current = setTimeout(() => {
            setCurrentSlide((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
        }, 8000); 
      }
      return () => resetTimeout();
  }, [currentSlide, slides]);

  const nextSlide = () => {
      setCurrentSlide(prev => (prev === slides.length - 1 ? 0 : prev + 1));
  };

  const prevSlide = () => {
      setCurrentSlide(prev => (prev === 0 ? slides.length - 1 : prev - 1));
  };

  const getYoutubeEmbedUrl = (url: string) => {
      if (!url) return '';
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      if (!id) return '';

      const origin = typeof window !== 'undefined' ? window.location.origin : '';
      return `https://www.youtube.com/embed/${id}?autoplay=1&mute=1&controls=0&loop=1&playlist=${id}&playsinline=1&rel=0&showinfo=0&iv_load_policy=3&modestbranding=1&enablejsapi=1&origin=${origin}`;
  };

  if (slides.length === 0) {
      return (
        <div className="h-[600px] md:h-[700px] bg-masuma-dark flex items-center justify-center">
            <Loader2 className="animate-spin text-masuma-orange" size={48} />
        </div>
      );
  }

  return (
    <>
    {announcement && (
        <div style={{ backgroundColor: announcementColor }} className="text-white text-center text-xs font-bold py-2 uppercase tracking-wider relative z-20">
            {announcement}
        </div>
    )}
    <div className="relative bg-masuma-dark overflow-hidden h-[600px] md:h-[700px] 2xl:h-[850px] group">

      {slides.map((slide, index) => (
          <div 
            key={slide.id}
            className={`absolute inset-0 transition-opacity duration-1000 ${index === currentSlide ? 'opacity-100 z-10' : 'opacity-0 z-0'}`}
          >
             <div className="absolute inset-0 bg-black">
                 {slide.mediaType === 'youtube' && slide.videoUrl ? (
                     <div className="absolute inset-0 pointer-events-none overflow-hidden">
                        <iframe 
                            src={getYoutubeEmbedUrl(slide.videoUrl)} 
                            className="w-full h-full object-cover opacity-60"
                            allow="autoplay; encrypted-media; gyroscope; picture-in-picture"
                            title="Background Video"
                        ></iframe>
                     </div>
                 ) : (
                     <div 
                        className="absolute inset-0 bg-cover bg-center opacity-60"
                        style={{ backgroundImage: `url('${slide.image}')` }}
                     ></div>
                 )}
             </div>

             <div className="absolute inset-0 bg-gradient-to-r from-masuma-dark via-masuma-dark/70 to-transparent"></div>

             <div className="absolute inset-0 flex items-center">
                <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
                    <div className="max-w-2xl">
                        <h1 
                            className="text-5xl md:text-7xl font-bold text-white leading-tight mb-8 font-display whitespace-pre-line"
                            dangerouslySetInnerHTML={{ __html: slide.title.replace(/\\n/g, '\n') }}
                        />
                        <p className="text-lg md:text-xl text-gray-300 mb-10 max-w-xl font-light">
                            {slide.subtitle}
                        </p>
                        <div className="flex gap-4">
                            <button 
                                onClick={() => setView(slide.ctaLink || 'CATALOG')}
                                className="bg-masuma-orange hover:bg-white hover:text-masuma-orange text-white font-bold py-4 px-10 rounded-none flex items-center justify-center transition uppercase tracking-wider text-sm"
                            >
                                {slide.ctaText || 'Learn More'} <ArrowRight className="ml-3" size={18} />
                            </button>
                        </div>
                    </div>
                </div>
             </div>
          </div>
      ))}

      {slides.length > 1 && (
          <div className="absolute bottom-10 left-0 right-0 z-20 flex justify-center gap-2">
              {slides.map((_, idx) => (
                  <button 
                      key={idx}
                      onClick={() => setCurrentSlide(idx)}
                      className={`h-1 transition-all ${idx === currentSlide ? 'bg-masuma-orange w-8' : 'bg-white/30 w-4'}`}
                  ></button>
              ))}
          </div>
      )}
    </div>
    </>
  );
};

