import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { AuditLog } from '../entities/AuditLog';
import { authenticate, authorize } from '../middleware/auth';

const router = Router();
const repo = AppDataSource.getRepository(AuditLog);

// GET /api/audit-logs
// Managers need access to this for the Dashboard summary
router.get('/', authenticate, authorize(['ADMIN', 'MANAGER']), async (req, res) => {
    try {
        const logs = await repo.find({
            order: { createdAt: 'DESC' },
            take: 100,
            relations: ['user']
        });

        const formatted = logs.map(l => ({
            id: l.id,
            action: l.action,
            user: l.user?.fullName || 'System',
            detail: l.details || '',
            time: l.createdAt.toLocaleString(),
            type: l.action.includes('DELETE') || l.action.includes('FAIL') ? 'error' : 
                  l.action.includes('UPDATE') ? 'warning' : 'info'
        }));

        res.json(formatted);
    } catch (error) {
        console.error("Audit Log Fetch Error:", error);
        res.status(500).json({ error: 'Failed to fetch logs' });
    }
});

export default router;

