import React, { useState, useEffect, useCallback } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductList from './components/ProductList';
import CartDrawer from './components/CartDrawer';
import AIAssistant from './components/AIAssistant';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import DashboardLayout from './components/admin/DashboardLayout';
import DashboardHome from './components/admin/DashboardHome';
import ProductManager from './components/admin/ProductManager';
import InventoryManager from './components/admin/InventoryManager';
import OrderManager from './components/admin/OrderManager';
import SalesHistory from './components/admin/SalesHistory';
import CustomerManager from './components/admin/CustomerManager';
import MpesaLogs from './components/admin/MpesaLogs';
import UserManager from './components/admin/UserManager';
import AuditLogs from './components/admin/AuditLogs';
import SettingsManager from './components/admin/SettingsManager';
import QuoteManager from './components/admin/QuoteManager';
import ReportsManager from './components/admin/ReportsManager';
import BranchManager from './components/admin/BranchManager';
import PosTerminal from './components/admin/PosTerminal';
import BlogManager from './components/admin/BlogManager';
import CmsManager from './components/admin/CmsManager';
import Profile from './components/admin/Profile';
import B2BPortal from './components/admin/B2BPortal';
import ShippingManager from './components/admin/ShippingManager';
import FinanceManager from './components/admin/FinanceManager';
import CategoryManager from './components/admin/CategoryManager';
import PartFinder from './components/PartFinder';
import Blog from './components/Blog';
import Contact from './components/Contact';
import About from './components/About';
import WarrantyPolicy from './components/WarrantyPolicy';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { CheckCircle, MessageCircle } from 'lucide-react';
import ReactGA from "react-ga4";
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const handleRouting = useCallback(async () => {
      const params = new URLSearchParams(window.location.search);
      const viewParam = params.get('view');
      const productParam = params.get('product');
      const postParam = params.get('post');

      // 1. Handle Product Deep Link
      if (productParam) {
          if (!selectedProduct || selectedProduct.id !== productParam) {
              try {
                  const res = await apiClient.get(`/products/${productParam}`);
                  if (res.data) setSelectedProduct(res.data);
              } catch (e) {
                  console.error("Deep link product not found");
              }
          }
      } else {
          setSelectedProduct(null);
      }

      // 2. Handle Blog Deep Link
      if (postParam) {
          setActivePostId(postParam);
          setView('BLOG');
      } else {
          setActivePostId(null);
          if (viewParam) {
              setView(viewParam as ViewState);
          } else if (!productParam && view === 'BLOG') {
              // If we were in blog and param cleared, stay in blog but initial load handled in Blog.tsx
          } else if (!productParam && !viewParam) {
              // Only default to HOME if we aren't in a specific non-home view already
              if (['HOME', 'CATALOG', 'PART_FINDER', 'BLOG', 'ABOUT', 'CONTACT', 'WARRANTY'].includes(view)) {
                  // Keep current view unless it was explicitly cleared
              } else {
                  setView('HOME');
              }
          }
      }
  }, [selectedProduct, view]);

  useEffect(() => {
      const init = async () => {
          try {
              const res = await apiClient.get('/settings');
              const gaId = res.data.GOOGLE_ANALYTICS_ID;
              if (gaId) {
                  ReactGA.initialize(gaId);
                  ReactGA.send({ hitType: "pageview", page: window.location.pathname });
              }
          } catch (e) {}
          handleRouting();
      };

      init();

      const storedToken = localStorage.getItem('masuma_auth_token');
      const storedUser = localStorage.getItem('masuma_user');
      if (storedToken && storedUser) {
          setToken(storedToken);
          setUser(JSON.parse(storedUser));
      }

      const storedCart = localStorage.getItem('masuma_cart');
      if (storedCart) setCart(JSON.parse(storedCart));

      window.addEventListener('popstate', handleRouting);
      return () => window.removeEventListener('popstate', handleRouting);
  }, [handleRouting]);

  const navigate = (newView: ViewState, params?: Record<string, string>) => {
      setView(newView);
      const urlParams = new URLSearchParams();
      if (newView !== 'HOME') urlParams.set('view', newView);
      if (params) {
          Object.entries(params).forEach(([k, v]) => urlParams.set(k, v));
      }
      const newQuery = urlParams.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo(0, 0);
  };

  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      const params = new URLSearchParams(window.location.search);
      params.set('product', product.id);
      const newUrl = `${window.location.pathname}?${params.toString()}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
      setSelectedProduct(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      const newQuery = params.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  useEffect(() => {
      if (typeof window !== 'undefined') {
          try {
            setTimeout(() => {
                ReactGA.send({ hitType: "pageview", page: window.location.pathname + window.location.search, title: document.title });
            }, 500);
          } catch(e) {}
      }
  }, [view, selectedProduct, activePostId]);

  useEffect(() => {
      localStorage.setItem('masuma_cart', JSON.stringify(cart));
  }, [cart]);

  const showToast = (message: string, type: ToastType = 'success') => {
      setToast({ message, type });
  };

  const addToCart = (product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
    showToast(`Added ${product.name} to cart`);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
      if (quantity < 1) return;
      setCart(prev => prev.map(item => item.id === id ? { ...item, quantity } : item));
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      showToast('Order placed successfully!');
  };

  const handleLoginSuccess = (userData: any, authToken: string) => {
      setUser(userData);
      setToken(authToken);
      localStorage.setItem('masuma_auth_token', authToken);
      localStorage.setItem('masuma_user', JSON.stringify(userData));
      setView('DASHBOARD');
  };

  const handleLogout = () => {
      setUser(null);
      setToken(null);
      localStorage.removeItem('masuma_auth_token');
      localStorage.removeItem('masuma_user');
      setView('HOME');
  };

  const renderContent = () => {
    if (view === 'DASHBOARD' && user) {
        const renderModule = () => {
            switch(adminModule) {
                case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                case 'products': return <ProductManager />;
                case 'inventory': return <InventoryManager />;
                case 'orders': return <OrderManager />;
                case 'sales_history': return <SalesHistory />;
                case 'customers': return <CustomerManager />;
                case 'mpesa': return <MpesaLogs />;
                case 'users': return <UserManager />;
                case 'audit': return <AuditLogs />;
                case 'settings': return <SettingsManager />;
                case 'quotes': return <QuoteManager />;
                case 'reports': return <ReportsManager />;
                case 'branches': return <BranchManager />;
                case 'pos': return <PosTerminal />;
                case 'blog': return <BlogManager />;
                case 'cms': return <CmsManager />;
                case 'profile': return <Profile />;
                case 'b2b': return <B2BPortal />;
                case 'shipping': return <ShippingManager />;
                case 'finance': return <FinanceManager />;
                case 'categories': return <CategoryManager />;
                default: return <DashboardHome onNavigate={setAdminModule} />;
            }
        };

        return (
            <DashboardLayout 
                activeModule={adminModule} 
                onNavigate={setAdminModule} 
                onLogout={handleLogout}
            >
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {renderModule()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return (
            <>
                <SEO title="Staff Login" description="Secure access for Masuma Autoparts Staff" />
                <AdminLogin onLoginSuccess={handleLoginSuccess} onBack={() => setView('HOME')} />
            </>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar 
                cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
                setView={navigate} 
                toggleCart={() => setIsCartOpen(true)}
                toggleAi={() => setIsAiOpen(true)}
            />

            <main className="flex-grow">
            {view === 'HOME' && (
                <>
                <SEO 
                    title="Home" 
                    description="Official distributor of Masuma automotive parts in Kenya. High-quality Japanese engineered parts for Toyota, Nissan, Subaru, and more."
                    schema={{
                        "@context": "https://schema.org",
                        "@type": "AutoPartsStore",
                        "name": "Masuma Autoparts East Africa",
                        "image": "https://masuma.africa/logo.png",
                        "url": "https://masuma.africa",
                        "telephone": "+254792506590",
                        "address": {
                            "@type": "PostalAddress",
                            "streetAddress": "Ruby Mall, Accra Road",
                            "addressLocality": "Nairobi",
                            "addressCountry": "KE"
                        },
                        "priceRange": "$$"
                    }}
                />
                <Hero setView={navigate} />
                <ProductList addToCart={addToCart} onProductClick={openProduct} />

                <div className="bg-masuma-dark text-white py-24 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-5 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white via-transparent to-transparent"></div>
                    <div className="max-w-7xl mx-auto px-4 grid md:grid-cols-2 gap-16 items-center relative z-10">
                        <div>
                            <h3 className="text-3xl md:text-4xl font-bold font-display uppercase mb-6 leading-tight">Why <span className="text-masuma-orange">Masuma?</span></h3>
                            <p className="text-gray-300 mb-8 text-lg leading-relaxed font-light">The Kenyan market is flooded with counterfeits. Masuma Autoparts EA is your firewall against fake parts.</p>
                            <ul className="space-y-4">
                                <li className="flex items-start gap-4"><div className="bg-masuma-orange/20 p-2 rounded-full text-masuma-orange"><CheckCircle size={24} /></div><div><h4 className="font-bold text-white uppercase">12-Month Warranty</h4><p className="text-sm text-gray-400">No questions asked.</p></div></li>
                                <li className="flex items-start gap-4"><div className="bg-masuma-orange/20 p-2 rounded-full text-masuma-orange"><CheckCircle size={24} /></div><div><h4 className="font-bold text-white uppercase">Locally Stocked</h4><p className="text-sm text-gray-400">Immediate availability.</p></div></li>
                            </ul>
                        </div>
                        <div className="h-[400px] rounded-lg overflow-hidden relative shadow-2xl border-4 border-white/10 group bg-white flex items-center justify-center">
                            <img 
                                src="/media/why_masuma.jpg" 
                                onError={(e) => { (e.target as HTMLImageElement).src = 'https://masuma.com/wp-content/uploads/2021/09/MFC-112_1.jpg'; }}
                                alt="Masuma Quality Parts" 
                                className="w-full h-full object-contain p-8 transition duration-700 group-hover:scale-105 group-hover:opacity-90" 
                            />
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] opacity-0 group-hover:opacity-100 transition-all duration-500">
                                <h4 className="text-2xl font-display font-bold text-white mb-4 uppercase">Need Advice?</h4>
                                <button onClick={() => setIsAiOpen(true)} className="bg-masuma-orange text-white px-8 py-3 font-bold uppercase tracking-widest hover:bg-white hover:text-masuma-orange transition"><div className="flex items-center gap-2"><MessageCircle size={20} /> Chat Now</div></button>
                            </div>
                        </div>
                    </div>
                </div>
                </>
            )}
            {view === 'CATALOG' && (
                <>
                    <SEO title="Product Catalog" description="Browse filters, brakes, suspension, and engine parts." />
                    <ProductList addToCart={addToCart} onProductClick={openProduct} />
                </>
            )}
            {view === 'PART_FINDER' && (
                <>
                    <SEO title="Part Finder" description="Check local stock availability by SKU or Part Number." />
                    <PartFinder addToCart={addToCart} />
                </>
            )}
            {view === 'BLOG' && <Blog addToCart={addToCart} initialPostId={activePostId} onProductClick={openProduct} />}
            {view === 'ABOUT' && <About setView={navigate} />}
            {view === 'CONTACT' && (
                <>
                    <SEO title="Contact Us" description="Get in touch with Masuma East Africa. Phone, Email, and Location." />
                    <Contact />
                </>
            )}
            {view === 'WARRANTY' && (
                <>
                    <SEO title="Warranty Policy" description="Our 12-month warranty details and return policy." />
                    <WarrantyPolicy />
                </>
            )}
            </main>

            <Footer setView={navigate} />

            <CartDrawer 
                isOpen={isCartOpen} 
                onClose={() => setIsCartOpen(false)} 
                cartItems={cart} 
                removeFromCart={removeFromCart} 
                onCheckout={clearCart}
                updateQuantity={updateQuantity}
            />

            <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />

            <QuickView 
                product={selectedProduct} 
                isOpen={!!selectedProduct} 
                onClose={closeProduct}
                addToCart={addToCart}
                onSwitchProduct={openProduct}
            />
        </div>
    );
  };

  return (
    <>
        {renderContent()}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Clock, Calendar, Share2, ArrowRight, BookOpen, Loader2, ChevronLeft, ChevronRight, Check } from 'lucide-react';
import { BlogPost, Product } from '../types';
import { apiClient } from '../utils/apiClient';
import SEO from './SEO';

interface BlogProps {
  addToCart: (product: Product) => void;
  initialPostId?: string | null;
  onProductClick?: (product: Product) => void;
}

const Blog: React.FC<BlogProps> = ({ addToCart, initialPostId, onProductClick }) => {
  const [selectedPost, setSelectedPost] = useState<BlogPost | null>(null);
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [pagination, setPagination] = useState({ page: 1, limit: 6, total: 0, pages: 1 });
  const [copied, setCopied] = useState(false);

  // 1. Initial Data Fetch & Deep Link Check
  useEffect(() => {
      const init = async () => {
          if (initialPostId) {
              setIsLoading(true);
              try {
                  const res = await apiClient.get(`/blog/${initialPostId}`);
                  setSelectedPost(res.data);
              } catch (e) {
                  console.error("Deep link post not found");
                  setSelectedPost(null);
              }
              setIsLoading(false);
          } else {
              // IMPORTANT: Clear selected post if initialPostId prop is cleared
              setSelectedPost(null);
          }

          // Always fetch the list for navigation if empty
          if (posts.length === 0) {
              await fetchPosts(1);
          }
      };

      init();
  }, [initialPostId]);

  const fetchPosts = async (page: number) => {
      try {
          const res = await apiClient.get(`/blog?page=${page}&limit=${pagination.limit}`);

          if (res.data && res.data.data) {
              setPosts(res.data.data);
              setPagination(res.data.meta);
          } else if (Array.isArray(res.data)) {
              setPosts(res.data);
          }
      } catch (error) {
          console.error('Failed to fetch blog posts');
      } finally {
          setIsLoading(false);
      }
  };

  // 2. Handle Post Selection (Update URL)
  const handleSelectPost = (e: React.MouseEvent, post: BlogPost) => {
      e.preventDefault();
      setSelectedPost(post);
      const newUrl = `${window.location.pathname}?post=${post.id}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // 3. Handle Back Navigation (Clean URL)
  const handleBack = () => {
      setSelectedPost(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('post');
      const newQuery = params.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          setIsLoading(true);
          fetchPosts(newPage).then(() => {
              setIsLoading(false);
              window.scrollTo({ top: 0, behavior: 'smooth' });
          });
      }
  };

  useEffect(() => {
      if (selectedPost) {
          const fetchRelated = async () => {
              try {
                  const res = await apiClient.get(`/products?category=${selectedPost.relatedProductCategory}`);
                  const productsData = res.data.data || res.data; 
                  setRelatedProducts(Array.isArray(productsData) ? productsData.slice(0, 4) : []);
              } catch (e) {
                  setRelatedProducts([]);
              }
          };
          fetchRelated();
      }
  }, [selectedPost]);

  const handleShare = async () => {
    if (!selectedPost) return;
    const shareUrl = window.location.href; 
    const shareData = {
        title: selectedPost.title,
        text: selectedPost.excerpt,
        url: shareUrl
    };

    if (navigator.share) {
        try {
            await navigator.share(shareData);
        } catch (err) {
            console.log('Share canceled');
        }
    } else {
        try {
            await navigator.clipboard.writeText(shareUrl);
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        } catch (err) {
            console.error('Failed to copy');
        }
    }
  };

  if (selectedPost) {
    const articleSchema = {
        "@context": "https://schema.org",
        "@type": "Article",
        "headline": selectedPost.title,
        "image": selectedPost.image,
        "datePublished": selectedPost.date,
        "author": {
            "@type": "Organization",
            "name": "Masuma Autoparts EA"
        },
        "description": selectedPost.excerpt
    };

    return (
      <div className="animate-fade-in bg-white min-h-screen">
        <SEO 
            title={selectedPost.title} 
            description={selectedPost.excerpt} 
            image={selectedPost.image} 
            type="article" 
            schema={articleSchema}
        />
        <div className="relative h-[50vh] md:h-[60vh] w-full overflow-hidden">
          <div className="absolute inset-0 bg-masuma-dark/50 z-10"></div>
          <img src={selectedPost.image} alt={selectedPost.title} className="w-full h-full object-cover" />
          <div className="absolute inset-0 z-20 flex flex-col justify-end p-6 md:p-12 max-w-screen-2xl mx-auto">
            <button 
              onClick={handleBack}
              className="absolute top-6 left-6 md:left-12 text-white hover:text-masuma-orange transition flex items-center gap-2 font-bold uppercase text-sm tracking-wider bg-black/20 backdrop-blur-md px-4 py-2 rounded-full"
            >
              <ArrowLeft size={16} /> Back to Blog
            </button>

            <span className="text-masuma-orange font-bold uppercase tracking-widest text-xs mb-3 bg-black/60 w-fit px-3 py-1 backdrop-blur-sm">
              {selectedPost.category}
            </span>
            <h1 className="text-3xl md:text-5xl font-bold text-white font-display max-w-4xl leading-tight mb-4">
              {selectedPost.title}
            </h1>
            <div className="flex items-center gap-6 text-gray-300 text-sm font-medium">
               <span className="flex items-center gap-2"><Calendar size={16} className="text-masuma-orange" /> {selectedPost.date}</span>
               <span className="flex items-center gap-2"><Clock size={16} className="text-masuma-orange" /> {selectedPost.readTime}</span>
            </div>
          </div>
        </div>

        <div className="max-w-screen-2xl mx-auto px-4 py-12 grid grid-cols-1 lg:grid-cols-3 gap-12">

          <div className="lg:col-span-2">
             <div className="prose prose-lg prose-headings:font-display prose-headings:uppercase prose-headings:text-masuma-dark prose-a:text-masuma-orange max-w-none text-gray-600">
                <div dangerouslySetInnerHTML={{ __html: selectedPost.content }} />
             </div>

             <div className="mt-12 border-t border-gray-200 pt-8 flex flex-col sm:flex-row items-center justify-between gap-4">
                <p className="font-bold text-masuma-dark uppercase text-sm">Share this article:</p>
                <div className="flex items-center gap-4">
                   <button 
                    onClick={handleShare}
                    className="flex items-center gap-2 px-4 py-2 bg-gray-100 rounded-full hover:bg-masuma-orange hover:text-white transition font-bold text-xs uppercase tracking-wider"
                   >
                       {copied ? <Check size={16} /> : <Share2 size={16} />}
                       {copied ? 'Link Copied' : 'Share Link'}
                   </button>
                </div>
             </div>
          </div>

          <div className="lg:col-span-1">
             <div className="sticky top-24">
                <div className="bg-gray-50 p-6 border-t-4 border-masuma-orange shadow-lg rounded-sm">
                   <h3 className="text-xl font-bold text-masuma-dark font-display uppercase mb-6 flex items-center gap-2">
                      <BookOpen size={20} className="text-masuma-orange" />
                      Related Parts
                   </h3>
                   <p className="text-sm text-gray-500 mb-6">
                      Based on this article, we recommend these verified Masuma components for your vehicle.
                   </p>

                   <div className="space-y-4">
                      {relatedProducts.length > 0 ? relatedProducts.map(product => (
                         <div 
                            key={product.id} 
                            onClick={(e) => {
                                if (onProductClick) {
                                    e.preventDefault();
                                    onProductClick(product);
                                }
                            }}
                            className="bg-white p-3 flex gap-3 shadow-sm hover:shadow-md transition border border-gray-100 group cursor-pointer"
                         >
                            <div className="w-16 h-16 bg-gray-100 shrink-0 overflow-hidden">
                               <img src={product.image} alt={product.name} className="w-full h-full object-cover group-hover:scale-110 transition duration-500" />
                            </div>
                            <div className="flex-1">
                               <h4 className="font-bold text-masuma-dark text-xs uppercase leading-tight mb-1 group-hover:text-masuma-orange transition">{product.name}</h4>
                               <p className="text-masuma-orange font-bold text-sm">KES {product.price.toLocaleString()}</p>
                               <button 
                                  onClick={(e) => {
                                      e.stopPropagation(); 
                                      addToCart(product);
                                  }}
                                  className="mt-2 text-[10px] font-bold uppercase bg-masuma-dark text-white px-3 py-1 hover:bg-masuma-orange transition w-full text-center"
                               >
                                  Add to Cart
                               </button>
                            </div>
                         </div>
                      )) : (
                          <p className="text-xs text-gray-400 italic">Loading suggestions...</p>
                      )}
                   </div>
                </div>
             </div>
          </div>

        </div>
      </div>
    );
  }

  return (
    <div className="animate-fade-in bg-white min-h-screen">
      <SEO title="Blog & Insights" description="Automotive maintenance tips and Masuma product news for Kenya." />
      <div className="bg-masuma-dark text-white py-20 relative overflow-hidden">
         <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
         <div className="max-w-screen-2xl mx-auto px-4 relative z-10 text-center">
            <span className="text-masuma-orange font-bold uppercase tracking-[0.2em] text-xs mb-4 block">Masuma Knowledge Center</span>
            <h1 className="text-4xl md:text-6xl font-bold font-display uppercase tracking-tight mb-6">Expert Insights</h1>
            <div className="h-1 w-24 bg-masuma-orange mx-auto mb-6"></div>
            <p className="text-gray-400 max-w-2xl mx-auto text-lg font-light">
               Technical advice, maintenance tips, and industry news from the engineers who know your car best.
            </p>
         </div>
      </div>

      <div className="max-w-screen-2xl mx-auto px-4 py-16">
         {isLoading ? (
             <div className="flex justify-center items-center h-64">
                 <Loader2 className="animate-spin text-masuma-orange" size={48} />
             </div>
         ) : (
         <>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {posts.map((post) => (
                   <a 
                      key={post.id}
                      href={`/?post=${post.id}`} 
                      className="group bg-white border border-gray-200 hover:shadow-2xl transition-all duration-300 flex flex-col h-full cursor-pointer transform hover:-translate-y-1 block"
                      onClick={(e) => handleSelectPost(e, post)}
                   >
                      <div className="relative h-56 overflow-hidden">
                         <div className="absolute top-4 left-4 z-10">
                            <span className="bg-masuma-orange text-white text-[10px] font-bold uppercase px-2 py-1 shadow-md">
                               {post.category}
                            </span>
                         </div>
                         <img 
                            src={post.image} 
                            alt={post.title} 
                            className="w-full h-full object-cover transform group-hover:scale-110 transition duration-700 ease-out"
                         />
                         <div className="absolute inset-0 bg-black/20 group-hover:bg-black/0 transition"></div>
                      </div>

                      <div className="p-6 flex-1 flex flex-col">
                         <div className="flex items-center gap-4 text-xs text-gray-400 mb-3 font-medium uppercase tracking-wide">
                            <span className="flex items-center gap-1"><Calendar size={12} /> {post.date}</span>
                            <span className="flex items-center gap-1"><Clock size={12} /> {post.readTime}</span>
                         </div>
                         <h3 className="text-xl font-bold text-masuma-dark font-display mb-3 leading-tight group-hover:text-masuma-orange transition-colors">
                            {post.title}
                         </h3>
                         <p className="text-gray-600 text-sm line-clamp-3 mb-6 flex-1 leading-relaxed">
                            {post.excerpt}
                         </p>
                         <div className="flex items-center text-masuma-dark font-bold uppercase text-xs tracking-widest group-hover:text-masuma-orange transition mt-auto">
                            Read Article <ArrowRight size={16} className="ml-2 transform group-hover:translate-x-2 transition" />
                         </div>
                      </div>
                   </a>
                ))}
             </div>

             {pagination.pages > 1 && (
                 <div className="mt-16 flex justify-center items-center gap-4">
                    <button 
                        onClick={() => handlePageChange(pagination.page - 1)}
                        disabled={pagination.page === 1}
                        className="flex items-center gap-2 px-4 py-2 border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition font-bold text-xs uppercase tracking-wider text-gray-600"
                    >
                        <ChevronLeft size={16} /> Previous
                    </button>

                    <div className="flex items-center gap-1">
                        {Array.from({ length: Math.min(5, pagination.pages) }, (_, i) => {
                            let pNum = i + 1;
                            if (pagination.pages > 5) {
                                if (pagination.page > 3) pNum = pagination.page - 2 + i;
                                if (pNum > pagination.pages) pNum = pagination.pages - (4 - i);
                            }
                            return (
                                <button
                                    key={pNum}
                                    onClick={() => handlePageChange(pNum)}
                                    className={`w-8 h-8 flex items-center justify-center rounded text-xs font-bold transition ${
                                        pagination.page === pNum 
                                        ? 'bg-masuma-dark text-white' 
                                        : 'bg-white text-gray-600 hover:bg-gray-100'
                                    }`}
                                >
                                    {pNum}
                                </button>
                            );
                        })}
                    </div>

                    <button 
                        onClick={() => handlePageChange(pagination.page + 1)}
                        disabled={pagination.page === pagination.pages}
                        className="flex items-center gap-2 px-4 py-2 border border-gray-300 rounded hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed transition font-bold text-xs uppercase tracking-wider text-gray-600"
                    >
                        Next <ChevronRight size={16} />
                    </button>
                 </div>
             )}
         </>
         )}
      </div>
    </div>
  );
};

