import React, { useState, useEffect, useCallback } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductList from './components/ProductList';
import CartDrawer from './components/CartDrawer';
import AIAssistant from './components/AIAssistant';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import DashboardLayout from './components/admin/DashboardLayout';
import DashboardHome from './components/admin/DashboardHome';
import ProductManager from './components/admin/ProductManager';
import InventoryManager from './components/admin/InventoryManager';
import OrderManager from './components/admin/OrderManager';
import SalesHistory from './components/admin/SalesHistory';
import CustomerManager from './components/admin/CustomerManager';
import MpesaLogs from './components/admin/MpesaLogs';
import UserManager from './components/admin/UserManager';
import AuditLogs from './components/admin/AuditLogs';
import SettingsManager from './components/admin/SettingsManager';
import QuoteManager from './components/admin/QuoteManager';
import ReportsManager from './components/admin/ReportsManager';
import BranchManager from './components/admin/BranchManager';
import PosTerminal from './components/admin/PosTerminal';
import BlogManager from './components/admin/BlogManager';
import CmsManager from './components/admin/CmsManager';
import Profile from './components/admin/Profile';
import B2BPortal from './components/admin/B2BPortal';
import ShippingManager from './components/admin/ShippingManager';
import FinanceManager from './components/admin/FinanceManager';
import CategoryManager from './components/admin/CategoryManager';
import PartFinder from './components/PartFinder';
import Blog from './components/Blog';
import Contact from './components/Contact';
import About from './components/About';
import WarrantyPolicy from './components/WarrantyPolicy';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { CheckCircle, MessageCircle, Loader2 } from 'lucide-react';
import ReactGA from "react-ga4";
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);
  const [isRouting, setIsRouting] = useState(true);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Core Routing Logic: Resolves URLs to State
  const handleRouting = useCallback(async () => {
      const params = new URLSearchParams(window.location.search);
      const viewParam = params.get('view');
      const productParam = params.get('product');
      const postParam = params.get('post');

      // 1. Handle Product Deep Link (Modal)
      if (productParam) {
          // Only fetch if not already selected to avoid redundant API calls
          if (!selectedProduct || selectedProduct.id !== productParam) {
              try {
                  const res = await apiClient.get(`/products/${productParam}`);
                  if (res.data) setSelectedProduct(res.data);
              } catch (e) {
                  console.error("Deep link product not found", e);
                  setSelectedProduct(null);
              }
          }
      } else {
          setSelectedProduct(null);
      }

      // 2. Handle View & Blog Deep Link
      if (postParam) {
          setActivePostId(postParam);
          setView('BLOG');
      } else {
          setActivePostId(null);
          if (viewParam) {
              setView(viewParam as ViewState);
          } else if (!productParam) {
              // Only reset to HOME if we aren't deep-linked into a specific state
              // This allows the user to click a product while on Catalog and stay on Catalog
          }
      }
      setIsRouting(false);
  }, [selectedProduct]);

  // Initial Bootup
  useEffect(() => {
      const init = async () => {
          // Analytics Setup
          try {
              const res = await apiClient.get('/settings');
              const gaId = res.data.GOOGLE_ANALYTICS_ID;
              if (gaId) {
                  ReactGA.initialize(gaId);
                  ReactGA.send({ hitType: "pageview", page: window.location.pathname });
              }
          } catch (e) {}

          // Auth Setup
          const storedToken = localStorage.getItem('masuma_auth_token');
          const storedUser = localStorage.getItem('masuma_user');
          if (storedToken && storedUser) {
              setToken(storedToken);
              setUser(JSON.parse(storedUser));
          }

          // Cart Setup
          const storedCart = localStorage.getItem('masuma_cart');
          if (storedCart) setCart(JSON.parse(storedCart));

          // Run Routing
          await handleRouting();
      };

      init();

      // Listen for Browser Back/Forward
      window.addEventListener('popstate', handleRouting);
      return () => window.removeEventListener('popstate', handleRouting);
  }, [handleRouting]);

  const navigate = (newView: ViewState, params?: Record<string, string>) => {
      setView(newView);
      const urlParams = new URLSearchParams();
      if (newView !== 'HOME') urlParams.set('view', newView);
      if (params) {
          Object.entries(params).forEach(([k, v]) => urlParams.set(k, v));
      }
      const newQuery = urlParams.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo(0, 0);
  };

  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      const params = new URLSearchParams(window.location.search);
      params.set('product', product.id);
      const newUrl = `${window.location.pathname}?${params.toString()}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
      setSelectedProduct(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      const newQuery = params.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  useEffect(() => {
      if (typeof window !== 'undefined') {
          try {
            setTimeout(() => {
                ReactGA.send({ 
                    hitType: "pageview", 
                    page: window.location.pathname + window.location.search, 
                    title: document.title 
                });
            }, 500);
          } catch(e) {}
      }
  }, [view, selectedProduct, activePostId]);

  useEffect(() => {
      localStorage.setItem('masuma_cart', JSON.stringify(cart));
  }, [cart]);

  const showToast = (message: string, type: ToastType = 'success') => {
      setToast({ message, type });
  };

  const addToCart = (product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
    showToast(`Added ${product.name} to cart`);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
      if (quantity < 1) return;
      setCart(prev => prev.map(item => item.id === id ? { ...item, quantity } : item));
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      showToast('Order placed successfully!');
  };

  const handleLoginSuccess = (userData: any, authToken: string) => {
      setUser(userData);
      setToken(authToken);
      localStorage.setItem('masuma_auth_token', authToken);
      localStorage.setItem('masuma_user', JSON.stringify(userData));
      setView('DASHBOARD');
  };

  const handleLogout = () => {
      setUser(null);
      setToken(null);
      localStorage.removeItem('masuma_auth_token');
      localStorage.removeItem('masuma_user');
      setView('HOME');
  };

  const renderContent = () => {
    if (view === 'DASHBOARD' && user) {
        const renderModule = () => {
            switch(adminModule) {
                case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                case 'products': return <ProductManager />;
                case 'inventory': return <InventoryManager />;
                case 'orders': return <OrderManager />;
                case 'sales_history': return <SalesHistory />;
                case 'customers': return <CustomerManager />;
                case 'mpesa': return <MpesaLogs />;
                case 'users': return <UserManager />;
                case 'audit': return <AuditLogs />;
                case 'settings': return <SettingsManager />;
                case 'quotes': return <QuoteManager />;
                case 'reports': return <ReportsManager />;
                case 'branches': return <BranchManager />;
                case 'pos': return <PosTerminal />;
                case 'blog': return <BlogManager />;
                case 'cms': return <CmsManager />;
                case 'profile': return <Profile />;
                case 'b2b': return <B2BPortal />;
                case 'shipping': return <ShippingManager />;
                case 'finance': return <FinanceManager />;
                case 'categories': return <CategoryManager />;
                default: return <DashboardHome onNavigate={setAdminModule} />;
            }
        };

        return (
            <DashboardLayout 
                activeModule={adminModule} 
                onNavigate={setAdminModule} 
                onLogout={handleLogout}
            >
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {renderModule()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return (
            <>
                <SEO title="Staff Login" description="Secure access for Masuma Autoparts Staff" />
                <AdminLogin onLoginSuccess={handleLoginSuccess} onBack={() => setView('HOME')} />
            </>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar 
                cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
                setView={navigate} 
                toggleCart={() => setIsCartOpen(true)}
                toggleAi={() => setIsAiOpen(true)}
            />

            <main className="flex-grow">
            {isRouting && !selectedProduct && (
                <div className="fixed inset-0 bg-white z-[9999] flex flex-col items-center justify-center">
                    <Loader2 className="animate-spin text-masuma-orange mb-4" size={48} />
                    <p className="text-xs font-bold uppercase tracking-widest text-gray-400">Initializing Masuma Network...</p>
                </div>
            )}

            {view === 'HOME' && (
                <>
                <SEO 
                    title="Home" 
                    description="Official distributor of Masuma automotive parts in Kenya. High-quality Japanese engineered parts for Toyota, Nissan, Subaru, and more."
                    schema={{
                        "@context": "https://schema.org",
                        "@type": "AutoPartsStore",
                        "name": "Masuma Autoparts East Africa",
                        "image": "https://masuma.africa/logo.png",
                        "url": "https://masuma.africa",
                        "telephone": "+254792506590",
                        "address": {
                            "@type": "PostalAddress",
                            "streetAddress": "Ruby Mall, Accra Road",
