import WarrantyPolicy from './components/WarrantyPolicy';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { CheckCircle, MessageCircle, Loader2 } from 'lucide-react';
import ReactGA from "react-ga4";
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);
  const [isRouting, setIsRouting] = useState(true);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Core Routing Logic: Resolves current URL to App State
  const handleRouting = useCallback(async () => {
      const params = new URLSearchParams(window.location.search);
      const viewParam = params.get('view');
      const productParam = params.get('product');
      const postParam = params.get('post');

      // 1. Prioritize Product Deep Link (Opens Modal)
      if (productParam) {
          // Prevent infinite fetch if already selected
          if (!selectedProduct || selectedProduct.id !== productParam) {
              try {
                  const res = await apiClient.get(`/products/${productParam}`);
                  if (res.data) {
                      setSelectedProduct(res.data);
                  }
              } catch (e) {
                  console.error("Deep link product not found", e);
                  setSelectedProduct(null);
                  // Clean URL if invalid product to prevent stuck loader
                  const cleanParams = new URLSearchParams(window.location.search);
                  cleanParams.delete('product');
                  window.history.replaceState({}, '', `${window.location.pathname}?${cleanParams.toString()}`);
              }
          }
      } else {
          setSelectedProduct(null);
      }

      // 2. Handle View & Blog Deep Link
      if (postParam) {
          setActivePostId(postParam);
          setView('BLOG');
      } else if (viewParam) {
          if (['HOME', 'CATALOG', 'PART_FINDER', 'ABOUT', 'CONTACT', 'BLOG', 'WARRANTY'].includes(viewParam)) {
            setView(viewParam as ViewState);
          }
      } else {
          setActivePostId(null);
          // Only default to HOME if no other view state is set
          // (This preserves background view when a product modal is closed)
      }

      setIsRouting(false);
  }, [selectedProduct]);

  // Handle Initial Load and Browser Back/Forward
  useEffect(() => {
      const init = async () => {
          // Auth & Settings Setup
          try {
              const res = await apiClient.get('/settings');
              const gaId = res.data.GOOGLE_ANALYTICS_ID;
              if (gaId) {
                  ReactGA.initialize(gaId);
              }
          } catch (e) {}

          const storedToken = localStorage.getItem('masuma_auth_token');
          const storedUser = localStorage.getItem('masuma_user');
          if (storedToken && storedUser) {
              setToken(storedToken);
              setUser(JSON.parse(storedUser));
          }

          const storedCart = localStorage.getItem('masuma_cart');
          if (storedCart) setCart(JSON.parse(storedCart));

          // Run Routing logic once dependencies are ready
          await handleRouting();
      };

      init();

      window.addEventListener('popstate', handleRouting);
      return () => window.removeEventListener('popstate', handleRouting);
  }, [handleRouting]);

  // Navigate function for internal links
  const navigate = (newView: ViewState, params?: Record<string, string>) => {
      setView(newView);
      const urlParams = new URLSearchParams();
      if (newView !== 'HOME') urlParams.set('view', newView);
      if (params) {
          Object.entries(params).forEach(([k, v]) => urlParams.set(k, v));
      }
      const newQuery = urlParams.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo(0, 0);
  };

  // Helper to open a product modal and update URL for sharing
  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      const params = new URLSearchParams(window.location.search);
      params.set('product', product.id);
      const newUrl = `${window.location.pathname}?${params.toString()}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
      setSelectedProduct(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      const newQuery = params.toString();
      const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  useEffect(() => {
      localStorage.setItem('masuma_cart', JSON.stringify(cart));
  }, [cart]);

  const showToast = (message: string, type: ToastType = 'success') => {
      setToast({ message, type });
  };

  const addToCart = (product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
    showToast(`Added ${product.name} to cart`);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
      if (quantity < 1) return;
      setCart(prev => prev.map(item => item.id === id ? { ...item, quantity } : item));
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      showToast('Order placed successfully!');
  };

  const handleLoginSuccess = (userData: any, authToken: string) => {
      setUser(userData);
      setToken(authToken);
      localStorage.setItem('masuma_auth_token', authToken);
      localStorage.setItem('masuma_user', JSON.stringify(userData));
      setView('DASHBOARD');
  };

  const handleLogout = () => {
      setUser(null);
      setToken(null);
      localStorage.removeItem('masuma_auth_token');
      localStorage.removeItem('masuma_user');
      setView('HOME');
  };

  const renderContent = () => {
    if (view === 'DASHBOARD' && user) {
        const renderModule = () => {
            switch(adminModule) {
                case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                case 'products': return <ProductManager />;
                case 'inventory': return <InventoryManager />;
                case 'orders': return <OrderManager />;
                case 'sales_history': return <SalesHistory />;
                case 'customers': return <CustomerManager />;
                case 'mpesa': return <MpesaLogs />;
                case 'users': return <UserManager />;
                case 'audit': return <AuditLogs />;
                case 'settings': return <SettingsManager />;
                case 'quotes': return <QuoteManager />;
                case 'reports': return <ReportsManager />;
                case 'branches': return <BranchManager />;
                case 'pos': return <PosTerminal />;
                case 'blog': return <BlogManager />;
                case 'cms': return <CmsManager />;
                case 'profile': return <Profile />;
                case 'b2b': return <B2BPortal />;
                case 'shipping': return <ShippingManager />;
                case 'finance': return <FinanceManager />;
                case 'categories': return <CategoryManager />;
                default: return <DashboardHome onNavigate={setAdminModule} />;
            }
        };

        return (
            <DashboardLayout 
                activeModule={adminModule} 
                onNavigate={setAdminModule} 
                onLogout={handleLogout}
            >
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {renderModule()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return (
            <>
                <SEO title="Staff Login" description="Secure access for Masuma Autoparts Staff" />
                <AdminLogin onLoginSuccess={handleLoginSuccess} onBack={() => setView('HOME')} />
            </>
        );
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar 
                cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
                setView={navigate} 
                toggleCart={() => setIsCartOpen(true)}
                toggleAi={() => setIsAiOpen(true)}
            />

            <main className="flex-grow">
            {/* Global Loader for initial deep-link routing */}
            {isRouting && (
                <div className="fixed inset-0 bg-white z-[9999] flex flex-col items-center justify-center">
                    <Loader2 className="animate-spin text-masuma-orange mb-4" size={48} />
                    <p className="text-xs font-bold uppercase tracking-widest text-gray-400">Loading your part details...</p>
                </div>
            )}

            {view === 'HOME' && (
                <>
                <SEO 
                    title="Home" 
                    description="Official distributor of Masuma automotive parts in Kenya. High-quality Japanese engineered parts for Toyota, Nissan, Subaru, and more."
                />
                <Hero setView={navigate} />
                <ProductList addToCart={addToCart} onProductClick={openProduct} />

                <div className="bg-masuma-dark text-white py-24 relative overflow-hidden">
                    <div className="absolute inset-0 opacity-5 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white via-transparent to-transparent"></div>
                    <div className="max-w-7xl mx-auto px-4 grid md:grid-cols-2 gap-16 items-center relative z-10">
                        <div>
                            <h3 className="text-3xl md:text-4xl font-bold font-display uppercase mb-6 leading-tight">Why <span className="text-masuma-orange">Masuma?</span></h3>
                            <p className="text-gray-300 mb-8 text-lg leading-relaxed font-light">The Kenyan market is flooded with counterfeits. Masuma Autoparts EA is your firewall against fake parts.</p>
                            <ul className="space-y-4">
                                <li className="flex items-start gap-4"><div className="bg-masuma-orange/20 p-2 rounded-full text-masuma-orange"><CheckCircle size={24} /></div><div><h4 className="font-bold text-white uppercase">12-Month Warranty</h4><p className="text-sm text-gray-400">No questions asked.</p></div></li>
                                <li className="flex items-start gap-4"><div className="bg-masuma-orange/20 p-2 rounded-full text-masuma-orange"><CheckCircle size={24} /></div><div><h4 className="font-bold text-white uppercase">Locally Stocked</h4><p className="text-sm text-gray-400">Immediate availability.</p></div></li>
                            </ul>
                        </div>
                        <div className="h-[400px] rounded-lg overflow-hidden relative shadow-2xl border-4 border-white/10 group bg-white flex items-center justify-center">
                            <img 
                                src="/media/why_masuma.jpg" 
                                onError={(e) => { (e.target as HTMLImageElement).src = 'https://masuma.com/wp-content/uploads/2021/09/MFC-112_1.jpg'; }}
                                alt="Masuma Quality Parts" 
                                className="w-full h-full object-contain p-8 transition duration-700 group-hover:scale-105 group-hover:opacity-90" 
                            />
                            <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] opacity-0 group-hover:opacity-100 transition-all duration-500">
                                <h4 className="text-2xl font-display font-bold text-white mb-4 uppercase">Need Advice?</h4>
                                <button onClick={() => setIsAiOpen(true)} className="bg-masuma-orange text-white px-8 py-3 font-bold uppercase tracking-widest hover:bg-white hover:text-masuma-orange transition"><div className="flex items-center gap-2"><MessageCircle size={20} /> Chat Now</div></button>
                            </div>
                        </div>
                    </div>
                </div>
                </>
            )}
            {view === 'CATALOG' && (
                <>
                    <SEO title="Product Catalog" description="Browse filters, brakes, suspension, and engine parts." />
                    <ProductList addToCart={addToCart} onProductClick={openProduct} />
                </>
            )}
            {view === 'PART_FINDER' && (
                <>
                    <SEO title="Part Finder" description="Check local stock availability by SKU or Part Number." />
                    <PartFinder addToCart={addToCart} />
                </>
            )}
            {view === 'BLOG' && <Blog addToCart={addToCart} initialPostId={activePostId} onProductClick={openProduct} />}
            {view === 'ABOUT' && <About setView={navigate} />}
            {view === 'CONTACT' && (
                <>
                    <SEO title="Contact Us" description="Get in touch with Masuma East Africa. Phone, Email, and Location." />
                    <Contact />
                </>
            )}
            {view === 'WARRANTY' && (
                <>
                    <SEO title="Warranty Policy" description="Our 12-month warranty details and return policy." />
                    <WarrantyPolicy />
                </>
            )}
            </main>

            <Footer setView={navigate} />

            <CartDrawer 
                isOpen={isCartOpen} 
                onClose={() => setIsCartOpen(false)} 
                cartItems={cart} 
                removeFromCart={removeFromCart} 
                onCheckout={clearCart}
                updateQuantity={updateQuantity}
            />

            <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />

            <QuickView 
                product={selectedProduct} 
                isOpen={!!selectedProduct} 
                onClose={closeProduct}
                addToCart={addToCart}
                onSwitchProduct={openProduct}
            />
        </div>
    );
  };

  return (
    <>
        {renderContent()}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

