import { CheckCircle, MessageCircle, Loader2 } from 'lucide-react';
import ReactGA from "react-ga4";
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  // 1. Initial State from URL (Production-Ready Synchronous Resolution)
  const getInitialParams = () => {
    const params = new URLSearchParams(window.location.search);
    return {
      view: (params.get('view') as ViewState) || 'HOME',
      productId: params.get('product'),
      postId: params.get('post')
    };
  };

  const initialParams = getInitialParams();

  const [view, setView] = useState<ViewState>(initialParams.view);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(initialParams.postId);
  const [isInitializing, setIsInitializing] = useState(true);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // 2. Specialized Fetcher for Deep-Linked Products
  const loadDeepLinkProduct = useCallback(async (id: string) => {
    try {
      const res = await apiClient.get(`/products/${id}`);
      if (res.data) {
        setSelectedProduct(res.data);
      }
    } catch (e) {
      console.error("Deep link product not found or server error", e);
      // Clean URL if product invalid to prevent stuck states
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      window.history.replaceState({}, '', `${window.location.pathname}?${params.toString()}`);
    }
  }, []);

  // 3. Routing Lifecycle Manager
  useEffect(() => {
    const bootstrap = async () => {
      // Load standard site data
      try {
        const res = await apiClient.get('/settings');
        if (res.data.GOOGLE_ANALYTICS_ID) {
          ReactGA.initialize(res.data.GOOGLE_ANALYTICS_ID);
        }
      } catch (e) {}

      // Auth & Cart restoration
      const storedToken = localStorage.getItem('masuma_auth_token');
      const storedUser = localStorage.getItem('masuma_user');
      if (storedToken && storedUser) {
        setToken(storedToken);
        setUser(JSON.parse(storedUser));
      }
      const storedCart = localStorage.getItem('masuma_cart');
      if (storedCart) setCart(JSON.parse(storedCart));

      // Resolve Intent
      if (initialParams.productId) {
        await loadDeepLinkProduct(initialParams.productId);
      }

      setIsInitializing(false);
    };

    bootstrap();

    // Listen for Browser Back/Forward buttons
    const handlePopState = () => {
      const p = getInitialParams();
      setView(p.view);
      setActivePostId(p.postId);
      if (p.productId) {
        loadDeepLinkProduct(p.productId);
      } else {
        setSelectedProduct(null);
      }
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, [loadDeepLinkProduct]);

  // Navigation Helper
  const navigate = (newView: ViewState, params?: Record<string, string>) => {
    setView(newView);
    const urlParams = new URLSearchParams(window.location.search);
    if (newView === 'HOME') {
      urlParams.delete('view');
    } else {
      urlParams.set('view', newView);
    }
    if (params) {
      Object.entries(params).forEach(([k, v]) => urlParams.set(k, v));
    }
    const newQuery = urlParams.toString();
    const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
    window.history.pushState({ path: newUrl }, '', newUrl);
    window.scrollTo(0, 0);
  };

  // Product Modal Controls (Updates URL for sharing)
  const openProduct = (product: Product) => {
    setSelectedProduct(product);
    const params = new URLSearchParams(window.location.search);
    params.set('product', product.id);
    const newUrl = `${window.location.pathname}?${params.toString()}`;
    window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
    setSelectedProduct(null);
    const params = new URLSearchParams(window.location.search);
    params.delete('product');
    const newQuery = params.toString();
    const newUrl = window.location.pathname + (newQuery ? `?${newQuery}` : '');
    window.history.replaceState({ path: newUrl }, '', newUrl);
  };

  useEffect(() => {
    localStorage.setItem('masuma_cart', JSON.stringify(cart));
  }, [cart]);

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const addToCart = (product: Product, quantity = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item =>
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });
    showToast(`Added ${product.name} to cart`);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, quantity: number) => {
    if (quantity < 1) return;
    setCart(prev => prev.map(item => item.id === id ? { ...item, quantity } : item));
  };

  const clearCart = () => {
    setCart([]);
    localStorage.removeItem('masuma_cart');
    showToast('Order placed successfully!');
  };

  const handleLoginSuccess = (userData: any, authToken: string) => {
    setUser(userData);
    setToken(authToken);
    localStorage.setItem('masuma_auth_token', authToken);
    localStorage.setItem('masuma_user', JSON.stringify(userData));
    setView('DASHBOARD');
  };

  const handleLogout = () => {
    setUser(null);
    setToken(null);
    localStorage.removeItem('masuma_auth_token');
    localStorage.removeItem('masuma_user');
    setView('HOME');
  };

  const renderContent = () => {
    if (view === 'DASHBOARD' && user) {
      const renderModule = () => {
        switch(adminModule) {
          case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
          case 'products': return <ProductManager />;
          case 'inventory': return <InventoryManager />;
          case 'orders': return <OrderManager />;
          case 'sales_history': return <SalesHistory />;
          case 'customers': return <CustomerManager />;
          case 'mpesa': return <MpesaLogs />;
          case 'users': return <UserManager />;
          case 'audit': return <AuditLogs />;
          case 'settings': return <SettingsManager />;
          case 'quotes': return <QuoteManager />;
          case 'reports': return <ReportsManager />;
          case 'branches': return <BranchManager />;
          case 'pos': return <PosTerminal />;
          case 'blog': return <BlogManager />;
          case 'cms': return <CmsManager />;
          case 'profile': return <Profile />;
          case 'b2b': return <B2BPortal />;
          case 'shipping': return <ShippingManager />;
          case 'finance': return <FinanceManager />;
          case 'categories': return <CategoryManager />;
          default: return <DashboardHome onNavigate={setAdminModule} />;
        }
      };

      return (
        <DashboardLayout activeModule={adminModule} onNavigate={setAdminModule} onLogout={handleLogout}>
          <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
          {renderModule()}
        </DashboardLayout>
      );
    }

    if (view === 'LOGIN') {
      return (
        <>
          <SEO title="Staff Login" description="Secure access for Masuma Autoparts Staff" />
          <AdminLogin onLoginSuccess={handleLoginSuccess} onBack={() => setView('HOME')} />
        </>
      );
    }

    return (
      <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
        <Navbar 
          cartCount={cart.reduce((a, b) => a + b.quantity, 0)} 
          setView={navigate} 
          toggleCart={() => setIsCartOpen(true)}
          toggleAi={() => setIsAiOpen(true)}
        />

        <main className="flex-grow">
          {/* Synchronous Initializing Screen for Deep Links */}
          {isInitializing && (
            <div className="fixed inset-0 bg-white z-[9999] flex flex-col items-center justify-center">
              <Loader2 className="animate-spin text-masuma-orange mb-4" size={48} />
              <p className="text-xs font-bold uppercase tracking-widest text-gray-400">Loading Product Data...</p>
            </div>
          )}

          {view === 'HOME' && (
            <>
              <SEO 
                title="Home" 
                description="Official distributor of Masuma automotive parts in Kenya. Japanese quality parts including filters, brakes, and suspension."
              />
              <Hero setView={navigate} />
              <ProductList addToCart={addToCart} onProductClick={openProduct} />

              <div className="bg-masuma-dark text-white py-24 relative overflow-hidden">
                <div className="absolute inset-0 opacity-5 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white via-transparent to-transparent"></div>
                <div className="max-w-7xl mx-auto px-4 grid md:grid-cols-2 gap-16 items-center relative z-10">
                  <div>
                    <h3 className="text-3xl md:text-4xl font-bold font-display uppercase mb-6 leading-tight">Why <span className="text-masuma-orange">Masuma?</span></h3>
                    <p className="text-gray-300 mb-8 text-lg leading-relaxed font-light">Masuma Autoparts EA is your firewall against fake parts in Kenya.</p>
                    <ul className="space-y-4">
                      <li className="flex items-start gap-4"><div className="bg-masuma-orange/20 p-2 rounded-full text-masuma-orange"><CheckCircle size={24} /></div><div><h4 className="font-bold text-white uppercase">12-Month Warranty</h4><p className="text-sm text-gray-400">Trusted durability.</p></div></li>
                    </ul>
                  </div>
                  <div className="h-[400px] rounded-lg overflow-hidden relative shadow-2xl border-4 border-white/10 group bg-white flex items-center justify-center">
                    <img 
                      src="https://masuma.com/wp-content/uploads/2021/09/MFC-112_1.jpg" 
                      alt="Quality Parts" 
                      className="w-full h-full object-contain p-8 transition duration-700" 
                    />
                  </div>
                </div>
              </div>
            </>
          )}
          {view === 'CATALOG' && (
            <>
              <SEO title="Catalog" description="Browse our complete list of genuine Masuma parts." />
              <ProductList addToCart={addToCart} onProductClick={openProduct} />
            </>
          )}
          {view === 'PART_FINDER' && <PartFinder addToCart={addToCart} />}
          {view === 'BLOG' && <Blog addToCart={addToCart} initialPostId={activePostId} onProductClick={openProduct} />}
          {view === 'ABOUT' && <About setView={navigate} />}
          {view === 'CONTACT' && <Contact />}
          {view === 'WARRANTY' && <WarrantyPolicy />}
        </main>

        <Footer setView={navigate} />
        <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} cartItems={cart} removeFromCart={removeFromCart} onCheckout={clearCart} updateQuantity={updateQuantity} />
        <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />

        {/* Modal rendered OUTSIDE view logic for deep-link persistence */}
        <QuickView 
          product={selectedProduct} 
          isOpen={!!selectedProduct} 
          onClose={closeProduct}
          addToCart={addToCart}
          onSwitchProduct={openProduct}
        />
      </div>
    );
  };

  return (
    <>
      {renderContent()}
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

