import React from 'react';
import { useCurrency } from '../contexts/CurrencyContext';

interface PriceProps {
    amount: number;
    className?: string;
    showExclusive?: boolean; // Option to show base price without VAT
}

const Price: React.FC<PriceProps> = ({ amount, className = '', showExclusive = false }) => {
    const { format } = useCurrency();

    // KENYA VAT LOGIC: 
    // Uploaded prices are exclusive. 
    // We multiply by 1.16 to get the inclusive price for the customer.
    const finalAmount = showExclusive ? amount : amount * 1.16;

    return <span className={className}>{format(finalAmount)}</span>;
};

export default Price;

