import { AppDataSource } from '../config/database';
import { Sale } from '../entities/Sale';
import { ProductStock } from '../entities/ProductStock';
import { User } from '../entities/User';
import { Branch } from '../entities/Branch';
import { Customer } from '../entities/Customer';
import { Order } from '../entities/Order';
import { EtimsService } from './etimsService';

interface SaleItemDto {
  productId: string;
  name: string;
  quantity: number;
  price: number; // Input is Exclusive Base Price
  sku?: string; 
  oem?: string; 
}

interface CreateSaleDto {
  items: SaleItemDto[];
  totalAmount: number; // This will be calculated as (Base * 1.16)
  paymentMethod: string;
  branchId: string;
  cashierId: string;
  customerId?: string;
  customerName?: string;
  paymentDetails?: any;
  discount?: number;
  discountType?: string;
}

export class SaleService {
  static async createSale(data: CreateSaleDto) {
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      const stockRepo = queryRunner.manager.getRepository(ProductStock);

      for (const item of data.items) {
        const stockEntry = await stockRepo.findOne({
            where: { product: { id: item.productId } as any, branch: { id: data.branchId } as any },
            lock: { mode: 'pessimistic_write' }
        });

        if (stockEntry) {
            stockEntry.quantity -= item.quantity;
            await stockRepo.save(stockEntry);
        } else {
            const newStock = new ProductStock();
            newStock.product = { id: item.productId } as any;
            newStock.branch = { id: data.branchId } as any;
            newStock.quantity = -item.quantity;
            await stockRepo.save(newStock);
        }
      }

      // VAT LOGIC (Exclusive prices):
      // The frontend sends totalAmount as (Base * 1.16).
      // We explicitly derive the net and tax from this for KRA compliance.
      const totalPayable = Number(data.totalAmount);
      const netAmount = totalPayable / 1.16;
      const taxAmount = totalPayable - netAmount;

      const sale = new Sale();
      sale.receiptNumber = `RCP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
      sale.branch = { id: data.branchId } as Branch;
      sale.cashier = { id: data.cashierId } as User;

      if (data.customerId) {
          const customer = await queryRunner.manager.findOneBy(Customer, { id: data.customerId });
          if (customer) {
              sale.customer = customer;
              sale.customerName = customer.name;
          }
      } else {
          sale.customerName = data.customerName || "Walk-in Customer";
      }

      // Store snapshots with inclusive prices for display consistency
      sale.itemsSnapshot = data.items.map(i => ({ ...i, price: i.price * 1.16 }));
      sale.itemsCount = data.items.length;

      sale.totalAmount = totalPayable;
      sale.netAmount = parseFloat(netAmount.toFixed(2));
      sale.taxAmount = parseFloat(taxAmount.toFixed(2));
      sale.discount = data.discount || 0;
      sale.discountType = data.discountType || 'FIXED';
      sale.paymentMethod = data.paymentMethod;
      sale.paymentDetails = data.paymentDetails;

      if (totalPayable > 0) {
          const fiscalData = await EtimsService.signInvoice(
            sale.receiptNumber, 
            data.items.map(i => ({
                hsCode: '8708.99.00',
                name: i.name,
                qty: i.quantity,
                unitPrice: i.price, // KRA expects exclusive price in item lines
                taxRate: 16
            })),
            totalPayable
          );

          if (fiscalData) {
              sale.kraControlCode = fiscalData.controlCode;
              sale.kraQrCodeUrl = fiscalData.qrCode;
              sale.kraSignature = fiscalData.signature;
              sale.kraDate = fiscalData.fiscalDate;
          }
      }

      await queryRunner.manager.save(sale);
      await queryRunner.commitTransaction();
      return sale;

    } catch (error) {
      await queryRunner.rollbackTransaction();
      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  static async createSaleFromOrder(order: Order, cashierUser?: User) {
    const existingSale = await AppDataSource.getRepository(Sale).createQueryBuilder("sale")
        .where("JSON_EXTRACT(sale.paymentDetails, '$.orderReference') = :orderRef", { orderRef: order.orderNumber })
        .getOne();

    if (existingSale) return existingSale;

    const defaultBranchId = (cashierUser?.branch?.id) || (await AppDataSource.getRepository(Branch).findOne({where: {code: 'NBI-HQ'}}))?.id;
    const systemUserId = cashierUser?.id || (await AppDataSource.getRepository(User).findOne({where: {role: 'ADMIN' as any}}))?.id;

    if (!defaultBranchId || !systemUserId) throw new Error("Configuration Error");

    const orderRepo = AppDataSource.getRepository(Order);
    const fullOrder = await orderRepo.findOne({
        where: { id: order.id },
        relations: ['items', 'items.product', 'items.product.oemNumbers']
    });

    if (!fullOrder) throw new Error("Order not found");

    const saleItems: SaleItemDto[] = fullOrder.items.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        quantity: item.quantity,
        price: Number(item.price), // Exclusive price from DB
        sku: item.product.sku,
        oem: item.product.oemNumbers?.[0]?.code || ''
    }));

    return this.createSale({
        items: saleItems,
        totalAmount: Number(order.totalAmount) * 1.16, // Add VAT
        paymentMethod: 'ORDER_PAYMENT',
        paymentDetails: { orderReference: order.orderNumber },
        branchId: defaultBranchId,
        cashierId: systemUserId,
        customerName: order.customerName,
        discount: 0,
        discountType: 'FIXED'
    });
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { ArrowRight, ShieldCheck, TrendingUp, Wrench, ChevronLeft, ChevronRight, Loader2 } from 'lucide-react';
import { ViewState, HeroSlide } from '../types';
import { apiClient } from '../utils/apiClient';

interface HeroProps {
    setView: (view: ViewState) => void;
}

const DEFAULT_SLIDES: HeroSlide[] = [
    {
        id: 'default-1',
        title: 'JAPANESE PRECISION.\nEAST AFRICAN GRIT.',
        subtitle: 'The official source for genuine Masuma components in Kenya. Engineered in Japan to survive Nairobi\'s toughest roads.',
        image: 'https://images.unsplash.com/photo-1486262715619-67b85e0b08d3?ixlib=rb-1.2.1&auto=format&fit=crop&w=1950&q=80',
        ctaText: 'Explore Catalog',
        ctaLink: 'CATALOG'
    }
];

const Hero: React.FC<HeroProps> = ({ setView }) => {
  const [slides, setSlides] = useState<HeroSlide[]>([]);
  const [currentSlide, setCurrentSlide] = useState(0);
  const [announcement, setAnnouncement] = useState('');
  const [announcementColor, setAnnouncementColor] = useState('#E0621B');
  const timeoutRef = useRef<any>(null);

  useEffect(() => {
      const fetchSettings = async () => {
          try {
              const res = await apiClient.get('/settings');
              const s = res.data;

              if (s) {
                  if (s.CMS_HERO_SLIDES) {
                      try {
                          const parsed = JSON.parse(s.CMS_HERO_SLIDES);
                          if (Array.isArray(parsed) && parsed.length > 0) {
                              setSlides(parsed);
                          } else {
                              setSlides(DEFAULT_SLIDES);
                          }
                      } catch (e) { 
                          setSlides(DEFAULT_SLIDES);
                      }
                  } else {
                      setSlides(DEFAULT_SLIDES);
                  }

                  if (s.CMS_ANNOUNCEMENT_ENABLED === 'true') {
                      setAnnouncement(s.CMS_ANNOUNCEMENT_TEXT || '');
                      setAnnouncementColor(s.CMS_ANNOUNCEMENT_COLOR || '#E0621B');
                  }
              } else {
                  setSlides(DEFAULT_SLIDES);
              }
          } catch (error) {
              setSlides(DEFAULT_SLIDES);
          }
      };
      fetchSettings();
  }, []);

  const resetTimeout = () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
  };

  useEffect(() => {
      resetTimeout();
      if (slides.length > 1) {
        timeoutRef.current = setTimeout(() => {
            setCurrentSlide((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
        }, 8000); 
      }
      return () => resetTimeout();
  }, [currentSlide, slides]);

  const nextSlide = () => {
      setCurrentSlide(prev => (prev === slides.length - 1 ? 0 : prev + 1));
  };

  const prevSlide = () => {
      setCurrentSlide(prev => (prev === 0 ? slides.length - 1 : prev - 1));
  };

  /**
   * Generates a YouTube URL optimized for background playback.
   * FIX: Removed widgetid and added strict origin to solve Error 153.
   */
  const getYoutubeEmbedUrl = (url: string) => {
      if (!url) return '';
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      if (!id) return '';

      const origin = typeof window !== 'undefined' ? `${window.location.protocol}//${window.location.host}` : '';

      const params = new URLSearchParams({
          autoplay: '1',
          mute: '1',
          controls: '0',
          loop: '1',
          playlist: id, // Required for loop=1 to function
          playsinline: '1',
          rel: '0',
          showinfo: '0',
          iv_load_policy: '3',
          modestbranding: '1',
          enablejsapi: '1',
          origin: origin
      });

      return `https://www.youtube.com/embed/${id}?${params.toString()}`;
  };

  if (slides.length === 0) {
      return (
        <div className="h-[600px] bg-masuma-dark flex items-center justify-center">
            <Loader2 className="animate-spin text-masuma-orange" size={48} />
