                  <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
                      <div className="max-w-3xl">
                          <div className="inline-flex items-center gap-2 bg-masuma-orange/40 border border-masuma-orange text-white text-[10px] font-bold px-3 py-1 mb-8 uppercase tracking-[0.2em] backdrop-blur-md">
                              <span className="w-2 h-2 bg-masuma-orange rounded-full animate-pulse"></span>
                              <span>Premium Japanese Quality</span>
                          </div>

                          <h1 
                            className="text-5xl md:text-7xl font-bold text-white mb-6 font-display uppercase tracking-tight whitespace-pre-line leading-[1.1]"
                            style={{ textShadow: '0 2px 10px rgba(0,0,0,0.5)' }}
                          >
