import React, { useEffect, useRef, useState } from 'react';

interface VideoBackgroundProps {
    url: string;
    isActive: boolean;
    poster: string;
}

declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const VideoBackground: React.FC<VideoBackgroundProps> = ({ url, isActive, poster }) => {
    const containerRef = useRef<HTMLDivElement>(null);
    const playerRef = useRef<any>(null);
    const [isReady, setIsReady] = useState(false);
    const [hasError, setHasError] = useState(false);

    // Extract ID
    const videoId = (url: string) => {
        const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
        const match = url.match(regExp);
        return (match && match[2].length === 11) ? match[2] : null;
    };

    const id = videoId(url);

    useEffect(() => {
        if (!id || !isActive) return;

        // 1. Load API Script if not exists
        if (!window.YT) {
            const tag = document.createElement('script');
            tag.src = "https://www.youtube.com/iframe_api";
            const firstScriptTag = document.getElementsByTagName('script')[0];
            firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
        }

        // 2. Initialize Player
        const initPlayer = () => {
            if (playerRef.current) return;

            playerRef.current = new window.YT.Player(`yt-player-${id}`, {
                videoId: id,
                host: 'https://www.youtube-nocookie.com',
                playerVars: {
                    autoplay: 1,
                    mute: 1,
                    controls: 0,
                    showinfo: 0,
                    modestbranding: 1,
                    loop: 1,
                    playlist: id,
                    fs: 0,
                    cc_load_policy: 0,
                    iv_load_policy: 3,
                    autohide: 1,
                    enablejsapi: 1,
                    origin: window.location.origin
                },
                events: {
                    onReady: (event: any) => {
                        event.target.mute();
                        event.target.playVideo();
                        setIsReady(true);
                    },
                    onStateChange: (event: any) => {
                        // Ensure looping works reliably
                        if (event.data === window.YT.PlayerState.ENDED) {
                            event.target.playVideo();
                        }
                    },
                    onError: () => {
                        setHasError(true);
                    }
                }
            });
        };

        if (window.YT && window.YT.Player) {
            initPlayer();
        } else {
            window.onYouTubeIframeAPIReady = initPlayer;
        }

        return () => {
            if (playerRef.current) {
                playerRef.current.destroy();
                playerRef.current = null;
            }
        };
    }, [id, isActive]);

    // Handle play/pause on slide change
    useEffect(() => {
        if (playerRef.current && isReady) {
            if (isActive) {
                playerRef.current.playVideo();
            } else {
                playerRef.current.pauseVideo();
            }
        }
    }, [isActive, isReady]);

    if (!id || hasError) {
        return (
            <div 
                className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000"
                style={{ backgroundImage: `url('${poster}')` }}
            />
        );
    }

    return (
        <div className="absolute inset-0 overflow-hidden bg-black">
            {/* Poster shows while video is buffering or if it fails */}
            <div 
                className={`absolute inset-0 bg-cover bg-center transition-opacity duration-1000 z-0 ${isReady ? 'opacity-0' : 'opacity-100'}`}
                style={{ backgroundImage: `url('${poster}')` }}
            />

            {/* The Cinematic Player Wrapper */}
            <div className="absolute inset-0 z-10 pointer-events-none">
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[120%]">
                    <div id={`yt-player-${id}`} className="w-full h-full"></div>
                </div>
            </div>
        </div>
    );
};

