import React, { useEffect, useRef, useState } from 'react';

interface VideoBackgroundProps {
    url: string;
    isActive: boolean;
    poster: string;
}

// Global script loading state to prevent multiple injections
let apiLoaded = false;
let apiLoadingPromise: Promise<void> | null = null;

const loadYouTubeAPI = (): Promise<void> => {
    if (apiLoaded) return Promise.resolve();
    if (apiLoadingPromise) return apiLoadingPromise;

    apiLoadingPromise = new Promise((resolve) => {
        const tag = document.createElement('script');
        tag.src = "https://www.youtube.com/iframe_api";
        const firstScriptTag = document.getElementsByTagName('script')[0];
        firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);

        (window as any).onYouTubeIframeAPIReady = () => {
            apiLoaded = true;
            resolve();
        };
    });

    return apiLoadingPromise;
};

const VideoBackground: React.FC<VideoBackgroundProps> = ({ url, isActive, poster }) => {
    const playerRef = useRef<any>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [isBuffering, setIsBuffering] = useState(true);
    const [hasError, setHasError] = useState(false);

    // Generate a truly unique ID for this instance
    const instanceId = useRef(`yt-player-${Math.random().toString(36).substr(2, 9)}`);

    const videoId = (url: string) => {
        const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
        const match = url.match(regExp);
        return (match && match[2].length === 11) ? match[2] : null;
    };

    const id = videoId(url);

    useEffect(() => {
        if (!id) return;

        let mounted = true;

        const init = async () => {
            await loadYouTubeAPI();

            if (!mounted || !containerRef.current || playerRef.current) return;

            playerRef.current = new (window as any).YT.Player(instanceId.current, {
                videoId: id,
                host: 'https://www.youtube-nocookie.com',
                playerVars: {
                    autoplay: 1,
                    mute: 1,
                    controls: 0,
                    disablekb: 1,
                    fs: 0,
                    rel: 0,
                    modestbranding: 1,
                    iv_load_policy: 3,
                    autohide: 1,
                    enablejsapi: 1,
                    playsinline: 1,
                    playlist: id,
                    loop: 1,
                    origin: window.location.origin,
                    widget_referrer: window.location.origin
                },
                events: {
                    onReady: (event: any) => {
                        event.target.mute();
                        if (isActive) {
                            event.target.playVideo();
                        }
                    },
                    onStateChange: (event: any) => {
                        // YT.PlayerState.PLAYING = 1
                        if (event.data === 1) {
                            setIsBuffering(false);
                        }
                        // YT.PlayerState.ENDED = 0
                        if (event.data === 0) {
                            event.target.playVideo(); // Force loop
                        }
                    },
                    onError: () => {
                        setHasError(true);
                    }
                }
            });
        };

        init();

        return () => {
            mounted = false;
            if (playerRef.current) {
                try {
                    playerRef.current.destroy();
                } catch (e) {
                    console.error("Cleanup error", e);
                }
                playerRef.current = null;
            }
        };
    }, [id]);

    // Secondary sync for visibility changes
    useEffect(() => {
        if (playerRef.current && playerRef.current.playVideo) {
            if (isActive) {
                playerRef.current.playVideo();
            } else {
                playerRef.current.pauseVideo();
            }
        }
    }, [isActive]);

    if (!id || hasError) {
        return (
            <div 
                className="absolute inset-0 bg-cover bg-center"
                style={{ backgroundImage: `url('${poster}')` }}
            />
        );
    }

    return (
        <div ref={containerRef} className="absolute inset-0 overflow-hidden bg-black">
            {/* Cinematic Overlay - Poster remains until video is actually playing */}
            <div 
                className={`absolute inset-0 bg-cover bg-center transition-opacity duration-1000 z-10 ${!isBuffering ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}
                style={{ backgroundImage: `url('${poster}')` }}
            />

            {/* Standard YouTube CSS "Object-Fit: Cover" hack */}
            <div className="absolute inset-0 pointer-events-none z-0">
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[110vw] h-[110vh] min-w-[177.77vh] min-h-[56.25vw]">
                    <div id={instanceId.current} className="w-full h-full"></div>
                </div>
