import React, { useState } from 'react';

interface VideoBackgroundProps {
    url: string;
    isActive: boolean;
    poster: string;
}

const VideoBackground: React.FC<VideoBackgroundProps> = ({ url, isActive, poster }) => {
    const [isLoaded, setIsLoaded] = useState(false);

    const videoId = (url: string) => {
        const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
        const match = url.match(regExp);
        return (match && match[2].length === 11) ? match[2] : null;
    };

    const id = videoId(url);

    if (!id) {
        return <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url('${poster}')` }} />;
    }

    // Build the most resilient URL possible
    // playlist=[ID] + loop=1 is the only way to loop without the JS API
    const embedParams = new URLSearchParams({
        autoplay: '1',
        mute: '1',
        controls: '0',
        showinfo: '0',
        rel: '0',
        iv_load_policy: '3',
        modestbranding: '1',
        playsinline: '1',
        enablejsapi: '1',
        loop: '1',
        playlist: id 
    });

    const embedUrl = `https://www.youtube-nocookie.com/embed/${id}?${embedParams.toString()}`;

    return (
        <div className="absolute inset-0 overflow-hidden bg-masuma-dark">
            {/* Fallback/Poster Layer */}
            <div 
                className={`absolute inset-0 bg-cover bg-center transition-opacity duration-1000 z-10 ${isLoaded ? 'opacity-0' : 'opacity-100'}`}
                style={{ backgroundImage: `url('${poster}')` }}
            />

            {/* The Video Layer */}
            {isActive && (
                <div className="absolute inset-0 pointer-events-none">
                    <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[115vw] h-[115vh] min-w-[177.77vh] min-h-[56.25vw]">
                        <iframe
                            src={embedUrl}
                            className="w-full h-full border-none"
                            allow="autoplay; encrypted-media"
                            onLoad={() => setTimeout(() => setIsLoaded(true), 1500)}
                            title="Background Video"
                        />
                    </div>
                </div>
            )}

            {/* Cinematic contrast overlay */}
            <div className="absolute inset-0 bg-black/40 z-[5]"></div>
        </div>
    );
};

