import { AppDataSource } from '../config/database';
import { Sale } from '../entities/Sale';
import { ProductStock } from '../entities/ProductStock';
import { User } from '../entities/User';
import { Branch } from '../entities/Branch';
import { Customer } from '../entities/Customer';
import { Order } from '../entities/Order';
import { EtimsService } from './etimsService';

interface SaleItemDto {
  productId: string;
  name: string;
  quantity: number;
  price: number; // Unit Base Price (Exclusive)
  sku?: string; 
}

interface CreateSaleDto {
  items: SaleItemDto[];
  totalAmount: number; // Final Gross Amount collected from customer (Inclusive of VAT)
  paymentMethod: string;
  branchId: string;
  cashierId: string;
  customerId?: string;
  customerName?: string;
  paymentDetails?: any;
  discount?: number;
  discountType?: string;
}

export class SaleService {
  static async createSale(data: CreateSaleDto) {
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      const stockRepo = queryRunner.manager.getRepository(ProductStock);

      // 1. Deduct Stock
      for (const item of data.items) {
        const stockEntry = await stockRepo.findOne({
            where: { product: { id: item.productId } as any, branch: { id: data.branchId } as any },
            lock: { mode: 'pessimistic_write' }
        });

        if (stockEntry) {
            stockEntry.quantity -= item.quantity;
            await stockRepo.save(stockEntry);
        }
      }

      // 2. KENYA VAT BREAKDOWN LOGIC
      // We take the final paid amount (Gross) and work backwards to find Net and Tax.
      const totalPayable = Number(data.totalAmount);
      const netAmount = totalPayable / 1.16;
      const taxAmount = totalPayable - netAmount;

      const sale = new Sale();
      sale.receiptNumber = `RCP-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
      sale.branch = { id: data.branchId } as Branch;
      sale.cashier = { id: data.cashierId } as User;

      if (data.customerId) {
          const customer = await queryRunner.manager.findOneBy(Customer, { id: data.customerId });
          if (customer) {
              sale.customer = customer;
              sale.customerName = customer.name;
          }
      } else {
          sale.customerName = data.customerName || "Walk-in Customer";
      }

      // Store descriptive snapshot for the invoice template
      sale.itemsSnapshot = data.items.map(i => ({ 
          ...i, 
          price: i.price, // Exclusive Base
          taxedPrice: i.price * 1.16 // Inclusive for display
      }));

      sale.itemsCount = data.items.length;
      sale.totalAmount = totalPayable;
      sale.netAmount = parseFloat(netAmount.toFixed(2));
      sale.taxAmount = parseFloat(taxAmount.toFixed(2));
      sale.discount = data.discount || 0;
      sale.discountType = data.discountType || 'FIXED';
      sale.paymentMethod = data.paymentMethod;
      sale.paymentDetails = data.paymentDetails;

      // 3. KRA eTIMS Integration
      if (totalPayable > 0) {
          const fiscalData = await EtimsService.signInvoice(
            sale.receiptNumber, 
            data.items.map(i => ({
                hsCode: '8708.99.00',
                name: i.name,
                qty: i.quantity,
                unitPrice: i.price, // KRA expects Base Price in item lines
                taxRate: 16
            })),
            totalPayable
          );

          if (fiscalData) {
              sale.kraControlCode = fiscalData.controlCode;
              sale.kraQrCodeUrl = fiscalData.qrCode;
              sale.kraSignature = fiscalData.signature;
              sale.kraDate = fiscalData.fiscalDate;
          }
      }

      await queryRunner.manager.save(sale);
      await queryRunner.commitTransaction();
      return sale;

    } catch (error) {
      await queryRunner.rollbackTransaction();
      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  static async createSaleFromOrder(order: Order, cashierUser?: User) {
    // Check for existing to prevent duplicates
    const existingSale = await AppDataSource.getRepository(Sale).createQueryBuilder("sale")
        .where("JSON_EXTRACT(sale.paymentDetails, '$.orderReference') = :orderRef", { orderRef: order.orderNumber })
        .getOne();

    if (existingSale) return existingSale;

    // Default configuration for background processing
    const defaultBranchId = (cashierUser?.branch?.id) || (await AppDataSource.getRepository(Branch).findOne({where: {code: 'NBI-HQ'}}))?.id;
    const systemUserId = cashierUser?.id || (await AppDataSource.getRepository(User).findOne({where: {role: 'ADMIN' as any}}))?.id;

    if (!defaultBranchId || !systemUserId) throw new Error("Finance Configuration Error");

    const orderRepo = AppDataSource.getRepository(Order);
    const fullOrder = await orderRepo.findOne({
        where: { id: order.id },
        relations: ['items', 'items.product']
    });

    if (!fullOrder) throw new Error("Order not found");

    const saleItems: SaleItemDto[] = fullOrder.items.map(item => ({
        productId: item.product.id,
        name: item.product.name,
        quantity: item.quantity,
        price: Number(item.price), // Exclusive price from DB
        sku: item.product.sku,
    }));

    return this.createSale({
        items: saleItems,
        totalAmount: Number(order.totalAmount) * 1.16, // Ensure VAT is added to the base order total
        paymentMethod: 'WEBSITE_ORDER',
        paymentDetails: { orderReference: order.orderNumber },
        branchId: defaultBranchId,
        cashierId: systemUserId,
        customerName: order.customerName,
    });
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { Search, Trash2, Plus, Minus, CreditCard, Printer, Save, CheckCircle, QrCode, User, X, Loader2, Smartphone, FileText, Banknote, AlertTriangle, Send, Tag, Percent } from 'lucide-react';
import { Product, Customer, Sale } from '../../types';
import { apiClient } from '../../utils/apiClient';
import InvoiceTemplate from './InvoiceTemplate';

interface PosItem {
    id: string;
    name: string;
    sku: string;
    price: number; // Base price from DB (Exclusive)
    wholesalePrice?: number;
    quantity?: number;
    oemNumbers?: string[];
    qty: number;
    appliedPrice: number; // Base unit price applied (Exclusive)
    [key: string]: any;
}

type PaymentMethod = 'CASH' | 'MPESA' | 'CHEQUE' | 'CARD';

const PosTerminal: React.FC = () => {
    const [cart, setCart] = useState<PosItem[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [searchResults, setSearchResults] = useState<Product[]>([]);
    const [lastSale, setLastSale] = useState<Sale | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isSearching, setIsSearching] = useState(false);
    const [currentUser, setCurrentUser] = useState<any>(null);

    // Payment & Discount State
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('CASH');
    const [paymentReference, setPaymentReference] = useState('');
    const [discountValue, setDiscountValue] = useState<string>(''); 
    const [discountType, setDiscountType] = useState<'PERCENTAGE' | 'FIXED'>('FIXED');

    // M-Pesa State
    const [mpesaPhone, setMpesaPhone] = useState('');
    const [pollingOrderId, setPollingOrderId] = useState<string | null>(null);
    const [pollingOrderNumber, setPollingOrderNumber] = useState<string | null>(null);
    const [waitingForPayment, setWaitingForPayment] = useState(false);

    const [customer, setCustomer] = useState<Customer | null>(null);
    const [isCustomerSearchOpen, setIsCustomerSearchOpen] = useState(false);
    const [customerSearchTerm, setCustomerSearchTerm] = useState('');
    const [foundCustomers, setFoundCustomers] = useState<Customer[]>([]);

    const searchInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        const u = localStorage.getItem('masuma_user');
        if (u) {
            try { setCurrentUser(JSON.parse(u)); } catch (e) {}
        }
    }, []);

    // --- KENYA VAT CALCULATIONS ---
    // 1. Calculate the raw subtotal (Exclusive)
    const exclusiveSubtotal = cart.reduce((sum, item) => sum + (item.appliedPrice * item.qty), 0);

    // 2. Add 16% VAT to the subtotal
    const inclusiveSubtotal = exclusiveSubtotal * 1.16;

    // 3. Calculate Discount on the Inclusive amount
    let discountAmount = 0;
    const numDiscount = parseFloat(discountValue) || 0;
    if (numDiscount > 0) {
        if (discountType === 'PERCENTAGE') {
            discountAmount = inclusiveSubtotal * (Math.min(numDiscount, 100) / 100);
        } else {
            discountAmount = Math.min(numDiscount, inclusiveSubtotal);
        }
    }

    // 4. Final Final Total (Inclusive of VAT, Minus Discount)
    const finalTotal = Math.max(0, inclusiveSubtotal - discountAmount);
    const vatComponent = finalTotal - (finalTotal / 1.16);

    // Polling Logic
    useEffect(() => {
        let interval: any;
        if (waitingForPayment && pollingOrderId && pollingOrderNumber) {
            interval = setInterval(async () => {
                try {
                    const statusRes = await apiClient.get(`/orders/${pollingOrderId}/status`);
                    if (statusRes.data.status === 'PAID') {
                        clearInterval(interval);
                        setTimeout(async () => {
                            try {
                                const saleRes = await apiClient.get(`/sales/order/${pollingOrderNumber}`);
                                setLastSale(saleRes.data);
                                setCart([]);
                                setCustomer(null);
                                setWaitingForPayment(false);
                                setDiscountValue('');
                                setTimeout(() => window.print(), 800);
                            } catch (e) {
                                setWaitingForPayment(false);
                            }
                        }, 1500); 
                    }
                } catch (err) { console.error(err); }
            }, 3000); 
        }
        return () => clearInterval(interval);
    }, [waitingForPayment, pollingOrderId, pollingOrderNumber]);

    const handleProductSearch = async (term: string) => {
        setSearchTerm(term);
        if (term.length < 2) { setSearchResults([]); return; }
        setIsSearching(true);
        try {
            const res = await apiClient.get(`/products?q=${term}`);
            setSearchResults(res.data.data || res.data || []);
        } catch (error) { setSearchResults([]); } finally { setIsSearching(false); }
    };

    const addToCart = (product: Product | any) => {
        setCart(prev => {
            const exists = prev.find(p => p.id === product.id);
            if (exists) {
                return prev.map(p => p.id === product.id ? { ...p, qty: p.qty + 1 } : p);
            }
            const price = (customer?.isWholesale && product.wholesalePrice) 
                          ? product.wholesalePrice 
                          : product.price;

            const newItem: PosItem = {
                id: product.id,
                name: product.name,
                sku: product.sku,
                price: product.price,
                wholesalePrice: product.wholesalePrice,
                quantity: product.quantity,
                oemNumbers: product.oemNumbers,
                qty: 1, 
                appliedPrice: price,
                ...product
            };
            return [...prev, newItem];
        });
        setSearchTerm('');
        setSearchResults([]);
        searchInputRef.current?.focus();
    };

    const updateQty = (id: string, delta: number) => {
        setCart(prev => prev.map(p => p.id === id ? { ...p, qty: Math.max(1, p.qty + delta) } : p));
    };

    // Fix: Added missing removeFromCart function
    const removeFromCart = (id: string) => {
        setCart(prev => prev.filter(p => p.id !== id));
    };

    const handleCompleteSale = async () => {
        let branchId = currentUser?.branch?.id;
        if (!branchId) {
            alert("No Branch assigned to user. Please contact Admin.");
            return;
        }

        setIsProcessing(true);
        try {
            const payload = {
                items: cart.map(i => ({ 
                    productId: i.id, 
                    name: i.name, 
                    quantity: i.qty, 
                    price: i.appliedPrice, // Exclusive
                    sku: i.sku,
                })),
                totalAmount: finalTotal, // Inclusive
                discount: discountAmount,
                discountType: discountType,
                paymentMethod,
                paymentDetails: { reference: paymentReference },
                customerId: customer?.id === 'GUEST' ? undefined : customer?.id,
                customerName: customer?.name,
                branchId: branchId
            };

            const response = await apiClient.post('/sales', payload);
            setLastSale(response.data);
            setCart([]);
            setCustomer(null);
            setPaymentMethod('CASH');
            setPaymentReference('');
            setDiscountValue('');
            setTimeout(() => window.print(), 500);
        } catch (error: any) {
            alert('Sale Failed: ' + (error.response?.data?.error || 'Server Error'));
        } finally { setIsProcessing(false); }
    };

    if (waitingForPayment) {
        return (
            <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center">
                <div className="bg-white p-8 rounded shadow-2xl text-center max-w-sm w-full border-t-4 border-green-500">
                    <Smartphone className="mx-auto text-gray-400 mb-4 animate-bounce" size={48} />
                    <h2 className="text-xl font-bold text-masuma-dark mb-2">Check Phone</h2>
                    <p className="text-sm text-gray-600 mb-6">Prompt sent to {mpesaPhone}.</p>
                    <div className="bg-gray-100 p-3 rounded mb-6">
                        <p className="text-xs font-bold text-gray-500 uppercase">Amount Due</p>
                        <p className="text-2xl font-bold text-masuma-dark">KES {finalTotal.toLocaleString()}</p>
                    </div>
                    <button onClick={() => setWaitingForPayment(false)} className="text-red-500 font-bold text-sm">Cancel</button>
                </div>
            </div>
        );
    }

    if (lastSale) {
        return (
            <div className="flex items-center justify-center h-[calc(100vh-100px)]">
                <div className="hidden print-force-container">
                    <InvoiceTemplate data={lastSale} type="RECEIPT" />
                </div>
                <div className="bg-white p-8 rounded shadow border border-gray-200 w-96 text-center">
                    <CheckCircle className="text-green-500 mx-auto mb-4" size={48} />
                    <h2 className="text-xl font-bold text-masuma-dark mb-1">Sale Complete</h2>
                    <p className="text-gray-500 text-sm mb-6">Receipt #{lastSale.receiptNumber}</p>
                    <div className="flex gap-3">
                        <button onClick={() => window.print()} className="flex-1 bg-gray-800 text-white py-2 rounded font-bold text-xs uppercase flex items-center justify-center gap-2"><Printer size={16} /> Print</button>
                        <button onClick={() => setLastSale(null)} className="flex-1 bg-masuma-orange text-white py-2 rounded font-bold text-xs uppercase">Next Sale</button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="flex h-[calc(100vh-100px)] gap-4 font-sans">
            {/* Catalog Side */}
            <div className="flex-1 flex flex-col bg-white rounded shadow-sm border border-gray-200 overflow-hidden">
                <div className="p-3 bg-gray-50 border-b">
                    <div className="relative">
                        <input 
                            ref={searchInputRef}
                            type="text" 
                            className="w-full pl-9 pr-4 py-2 border rounded text-sm focus:border-masuma-orange outline-none"
                            placeholder="Search Inventory..."
                            value={searchTerm}
                            onChange={(e) => handleProductSearch(e.target.value)}
                        />
                        <Search className="absolute left-3 top-2.5 text-gray-400" size={16} />
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4 bg-gray-100/50">
                    {isSearching ? <Loader2 className="animate-spin mx-auto text-masuma-orange" /> : (
                        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                            {searchResults.map(p => (
                                <div key={p.id} onClick={() => (p.quantity || 0) > 0 && addToCart(p)} className="bg-white p-3 border rounded shadow-sm hover:border-masuma-orange cursor-pointer flex flex-col justify-between h-full">
                                    <div>
                                        <div className="text-[10px] font-bold text-gray-400 font-mono">{p.sku}</div>
                                        <div className="font-bold text-xs text-masuma-dark line-clamp-2 leading-tight mb-2">{p.name}</div>
                                    </div>
                                    <div className="flex justify-between items-end">
                                        <div className="text-masuma-orange font-bold text-sm">{(p.price * 1.16).toLocaleString()}</div>
                                        <div className="text-[9px] font-bold px-1 bg-gray-100 rounded text-gray-500">{p.quantity} left</div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* Cart & Billing Side */}
            <div className="w-[400px] flex flex-col bg-white rounded shadow-sm border border-gray-200 overflow-hidden">
                <div className="p-3 bg-masuma-dark text-white font-bold text-xs uppercase tracking-widest flex justify-between">
                    <span>Current Cart</span>
                    <span>{cart.length} Items</span>
                </div>

                {/* Items List */}
                <div className="flex-1 overflow-y-auto p-3 space-y-2">
                    {cart.map(item => (
                        <div key={item.id} className="p-2 border rounded flex justify-between items-start group hover:border-masuma-orange transition">
                            <div className="flex-1 pr-2">
                                <div className="text-xs font-bold text-gray-800 leading-tight">{item.name}</div>
                                <div className="text-[10px] text-gray-400 mt-1">@ {(item.appliedPrice * 1.16).toLocaleString()} (Incl. VAT)</div>
                            </div>
                            <div className="flex flex-col items-end">
                                <div className="flex items-center gap-2 mb-1">
                                    <button onClick={() => updateQty(item.id, -1)} className="p-1 hover:bg-gray-100 rounded border"><Minus size={10}/></button>
                                    <span className="text-xs font-bold">{item.qty}</span>
                                    <button onClick={() => updateQty(item.id, 1)} className="p-1 hover:bg-gray-100 rounded border"><Plus size={10}/></button>
                                </div>
                                <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600 transition"><Trash2 size={12}/></button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Totals Section */}
                <div className="p-4 bg-gray-50 border-t border-gray-200 space-y-3">
                    {/* Discount Input */}
                    <div className="flex items-center gap-2 bg-white p-2 rounded border border-gray-200">
                        <Tag size={14} className="text-gray-400" />
                        <span className="text-[10px] font-bold uppercase text-gray-400">Discount:</span>
                        <input type="number" className="w-full text-xs font-bold outline-none" value={discountValue} onChange={e => setDiscountValue(e.target.value)} placeholder="0.00" />
                        <div className="flex border-l pl-2 gap-1">
                            <button onClick={() => setDiscountType('PERCENTAGE')} className={`text-[9px] px-1.5 py-0.5 rounded font-bold ${discountType === 'PERCENTAGE' ? 'bg-masuma-dark text-white' : 'text-gray-400'}`}>%</button>
                            <button onClick={() => setDiscountType('FIXED')} className={`text-[9px] px-1.5 py-0.5 rounded font-bold ${discountType === 'FIXED' ? 'bg-masuma-dark text-white' : 'text-gray-400'}`}>KES</button>
                        </div>
                    </div>

                    <div className="space-y-1 border-b pb-3">
                        <div className="flex justify-between text-xs text-gray-500">
                            <span>Subtotal (Excl. VAT)</span>
                            <span>{exclusiveSubtotal.toLocaleString()}</span>
                        </div>
                        <div className="flex justify-between text-xs text-gray-500">
                            <span>VAT (16%)</span>
                            <span>{((inclusiveSubtotal - exclusiveSubtotal)).toLocaleString(undefined, {maximumFractionDigits: 0})}</span>
                        </div>
                        {discountAmount > 0 && (
                            <div className="flex justify-between text-xs font-bold text-green-600">
                                <span>Discount</span>
                                <span>-{discountAmount.toLocaleString()}</span>
                            </div>
                        )}
                    </div>

                    <div className="flex justify-between items-end pt-1">
                        <span className="text-xs font-bold uppercase text-gray-500">Total Payable</span>
                        <span className="text-2xl font-bold text-masuma-dark tracking-tighter">KES {finalTotal.toLocaleString()}</span>
                    </div>

                    <div className="grid grid-cols-3 gap-2">
                        <button onClick={() => setPaymentMethod('CASH')} className={`py-2 rounded border text-[10px] font-bold uppercase transition ${paymentMethod === 'CASH' ? 'bg-masuma-dark text-white border-masuma-dark' : 'bg-white text-gray-500 hover:bg-gray-100'}`}>Cash</button>
                        <button onClick={() => setPaymentMethod('MPESA')} className={`py-2 rounded border text-[10px] font-bold uppercase transition ${paymentMethod === 'MPESA' ? 'bg-green-600 text-white border-green-600' : 'bg-white text-gray-500 hover:bg-gray-100'}`}>M-Pesa</button>
                        <button onClick={() => setPaymentMethod('CHEQUE')} className={`py-2 rounded border text-[10px] font-bold uppercase transition ${paymentMethod === 'CHEQUE' ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-500 hover:bg-gray-100'}`}>Cheque</button>
                    </div>

                    <button 
                        onClick={handleCompleteSale}
                        disabled={cart.length === 0 || isProcessing}
                        className="w-full bg-masuma-orange text-white py-4 rounded font-bold uppercase tracking-widest text-xs hover:bg-orange-600 transition shadow-lg flex items-center justify-center gap-2"
                    >
                        {isProcessing ? <Loader2 className="animate-spin" size={16}/> : <><Printer size={16}/> Complete Sale</>}
                    </button>
                </div>
            </div>
        </div>
    );
};

