import { Queue } from 'bullmq';
import nodemailer from 'nodemailer';
import { redis } from '../config/redis';
import { config } from '../config/env';

// Transporter Setup
const transporter = nodemailer.createTransport({
    host: config.SMTP_HOST || 'smtp.gmail.com',
    port: Number(config.SMTP_PORT),
    secure: Number(config.SMTP_PORT) === 465, // true for 465, false for other ports
    auth: {
        user: config.SMTP_USER,
        pass: config.SMTP_PASS,
    },
    tls: {
        rejectUnauthorized: false 
    }
});

// Verify connection configuration
transporter.verify(function (error, success) {
    if (error) {
        if (config.SMTP_HOST && config.SMTP_USER) {
            console.warn('⚠️ SMTP Connection Error:', error.message);
        }
    } else {
        console.log('✅ SMTP Server is ready to take messages');
    }
});

let emailQueue: Queue | null = null;
if (redis) {
    emailQueue = new Queue('email-queue', { connection: redis });
}

export class EmailService {

    static async sendEmail(type: string, data: any) {
        if (emailQueue) {
            console.log(`[EMAIL] Queuing ${type} to ${data.email || 'Admin'}`);
            await emailQueue.add('send-email', { type, data });
            return true;
        } else {
            console.log(`ℹ️ Redis missing. Sending email (${type}) directly...`);
            try {
                await this.processDirectEmail(type, data);
                return true;
            } catch (error) {
                console.error('Direct Email Failed:', error);
                return false;
            }
        }
    }

    static async processDirectEmail(type: string, data: any) {
        let subject = '';
        let html = '';
        let to = data.email;

        if (type === 'ORDER_CONFIRMATION') {
            subject = `Order Confirmation #${data.orderNumber}`;
            html = `<h1>Order Received</h1><p>Hi ${data.customerName},</p><p>Thank you for your order #${data.orderNumber}.</p><p>Total: KES ${data.totalAmount}</p>`;
        } else if (type === 'QUOTE_REQUEST') {
            await this.sendRawEmail(
                config.SMTP_USER || 'sales@masuma.africa',
                `New Inquiry: ${data.productName}`,
                `<p><strong>Customer:</strong> ${data.name} (${data.phone})</p><p><strong>Email:</strong> ${data.email}</p><p><strong>Product:</strong> ${data.productName}</p><p><strong>Message:</strong><br/>${data.message}</p>`
            );

            if (data.email && data.email.includes('@')) {
                to = data.email;
                subject = `We received your request: ${data.productName}`;
                html = `<p>Jambo ${data.name},</p><p>We have received your inquiry regarding <strong>${data.productName}</strong>.</p><p>Our sales team will contact you shortly.</p><br/><p>Regards,<br/>Masuma Autoparts EA Team</p>`;
            } else return;
        } else if (type === 'PASSWORD_RESET') {
            subject = 'Reset Your Masuma ERP Password';
            const resetUrl = `${data.origin}/?view=RESET_PASSWORD&token=${data.token}`;
            html = `
                <div style="font-family: sans-serif; max-width: 600px; border: 1px solid #eee; padding: 20px;">
                    <h2 style="color: #E0621B;">Password Reset Request</h2>
                    <p>Jambo,</p>
                    <p>You requested to reset your password for the Masuma Autoparts ERP system.</p>
                    <p>Please click the button below to set a new password. This link is valid for 1 hour.</p>
                    <a href="${resetUrl}" style="background: #1A1A1A; color: white; padding: 12px 24px; text-decoration: none; display: inline-block; font-weight: bold; border-radius: 4px; margin: 20px 0;">Reset Password</a>
                    <p style="color: #666; font-size: 12px;">If you didn't request this, please ignore this email.</p>
                </div>
            `;
        }

        if (to && subject && html) {
            await this.sendRawEmail(to, subject, html);
        }
    }

    static async sendRawEmail(to: string, subject: string, html: string) {
        if (!config.SMTP_HOST || !config.SMTP_USER) {
            console.warn(`⚠️ [EMAIL] SMTP Config missing. Email to ${to} not sent.`);
            return;
        }
        try {
            await transporter.sendMail({
                from: `"Masuma Auto Parts" <${config.FROM_EMAIL}>`,
                to,
                subject,
                html,
            });
            console.log(`✅ Email sent to ${to}`);
        } catch(e: any) {
             console.error(`❌ Email send failed to ${to}:`, e.message);
             throw e;
        }
    }
}

import { Router } from 'express';
import { z } from 'zod';
import { validate } from '../middleware/validate';
import { AppDataSource } from '../config/database';
import { User } from '../entities/User';
import { Security } from '../utils/security';
import { authenticate } from '../middleware/auth';
import { EmailService } from '../services/emailService';
import crypto from 'crypto';
import { MoreThan } from 'typeorm';

const router = Router();
const userRepo = AppDataSource.getRepository(User);

router.post('/login', validate(z.object({ email: z.string().email(), password: z.string().min(6) })), async (req, res) => {
    const { email, password } = req.body;
    const user = await userRepo.findOne({ where: { email }, relations: ['branch'] });
    if (!user) return res.status(401).json({ error: 'Invalid credentials' });
    const isValid = await Security.comparePassword(password, user.passwordHash);
    if (!isValid) return res.status(401).json({ error: 'Invalid credentials' });
    if (!user.isActive) return res.status(403).json({ error: 'Account is disabled' });
    const token = Security.generateToken({ id: user.id, email: user.email, role: user.role, branchId: user.branch?.id });
    res.json({ token, user: { id: user.id, name: user.fullName, role: user.role, email: user.email, branch: user.branch ? { id: user.branch.id, name: user.branch.name } : null } });
});

router.post('/forgot-password', validate(z.object({ email: z.string().email() })), async (req, res) => {
    try {
        const { email } = req.body;
        const user = await userRepo.findOne({ where: { email } });

        // Security best practice: don't reveal if user exists, but here we proceed only if they do
        if (user) {
            const token = crypto.randomBytes(32).toString('hex');
            user.resetPasswordToken = token;
            user.resetPasswordExpires = new Date(Date.now() + 3600000); // 1 hour
            await userRepo.save(user);

            await EmailService.sendEmail('PASSWORD_RESET', {
                email: user.email,
                token,
                origin: req.headers.origin || 'https://masuma.africa'
            });
        }

        res.json({ message: 'If an account with that email exists, a reset link has been sent.' });
    } catch (error) {
        res.status(500).json({ error: 'Failed to process request' });
    }
});

router.post('/reset-password', validate(z.object({ token: z.string(), password: z.string().min(6) })), async (req, res) => {
    try {
        const { token, password } = req.body;
        const user = await userRepo.findOne({
            where: {
                resetPasswordToken: token,
                resetPasswordExpires: MoreThan(new Date())
            }
        });

        if (!user) {
            return res.status(400).json({ error: 'Password reset token is invalid or has expired.' });
        }

        user.passwordHash = await Security.hashPassword(password);
        user.resetPasswordToken = undefined;
        user.resetPasswordExpires = undefined;
        await userRepo.save(user);

        res.json({ message: 'Password has been updated successfully.' });
    } catch (error) {
        res.status(500).json({ error: 'Failed to reset password' });
    }
});

router.get('/me', authenticate, async (req, res) => {
    if (!req.user) return res.status(401).json({ error: 'Not authenticated' });
    const freshUser = await userRepo.findOne({ where: { id: req.user.id }, relations: ['branch'] });
    res.json(freshUser); 
});

router.put('/profile', authenticate, validate(z.object({ firstName: z.string().optional(), lastName: z.string().optional(), currentPassword: z.string().min(6).optional(), newPassword: z.string().min(6).optional() })), async (req, res) => {
    const { firstName, lastName, currentPassword, newPassword } = req.body;
    const user = await userRepo.findOneBy({ id: req.user!.id });
    if (!user) return res.status(404).json({ error: 'User not found' });
    if (firstName || lastName) user.fullName = `${firstName || ''} ${lastName || ''}`.trim() || user.fullName;
    if (newPassword) {
        if (!currentPassword) return res.status(400).json({ error: 'Current password required' });
        const isMatch = await Security.comparePassword(currentPassword, user.passwordHash);
        if (!isMatch) return res.status(400).json({ error: 'Incorrect current password' });
        user.passwordHash = await Security.hashPassword(newPassword);
    }
    await userRepo.save(user);
    res.json({ message: 'Profile updated' });
});

export default router;

