                    <p style="color: #999; font-size: 10px;">URL: ${resetUrl}</p>
                </div>
            `;
        }

        if (to && subject && html) {
            return await this.sendRawEmail(to, subject, html);
        }
        return false;
    }

    static async sendRawEmail(to: string, subject: string, html: string) {
        if (!config.SMTP_HOST || !config.SMTP_USER) {
            console.warn(`⚠️ [EMAIL] SMTP Host or User missing in .env. Email to ${to} aborted.`);
            return false;
        }
        try {
            console.log(`📧 [SMTP] Attempting delivery to: ${to}...`);
            const info = await transporter.sendMail({
                from: `"Masuma Auto Parts" <${config.FROM_EMAIL || config.SMTP_USER}>`,
                to,
                subject,
                html,
            });
            console.log(`✅ [SMTP] Message sent! MessageId: ${info.messageId}`);
