import { Lock, Loader2, CheckCircle, ArrowLeft, ShieldCheck, Eye, EyeOff, AlertCircle } from 'lucide-react';
import { apiClient } from '../utils/apiClient';
import { Logo } from './Logo';

interface ResetPasswordProps {
    onBack: () => void;
}

const ResetPassword: React.FC<ResetPasswordProps> = ({ onBack }) => {
    const [token, setToken] = useState('');
    const [password, setPassword] = useState('');
    const [confirm, setConfirm] = useState('');
    const [showPass, setShowPass] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState(false);

    useEffect(() => {
        const params = new URLSearchParams(window.location.search);
        const t = params.get('token');
        if (t) {
            setToken(t);
        } else {
            setError('The reset link appears to be invalid or missing a security token.');
        }
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (password !== confirm) return setError('Passwords do not match.');
        if (password.length < 8) return setError('Security requirement: Password must be at least 8 characters.');

        setIsLoading(true);
        setError('');

        try {
            await apiClient.post('/auth/reset-password', { token, password });
            setSuccess(true);
            // Clear URL params to prevent re-submitting
            window.history.replaceState({}, '', window.location.pathname);
        } catch (err: any) {
            setError(err.response?.data?.error || 'Password reset failed. The link may have expired or was already used.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-gray-100 flex items-center justify-center p-4 font-sans">
            <div className="bg-white p-8 rounded-lg shadow-2xl w-full max-w-md border-t-4 border-masuma-orange animate-scale-up">
                <div className="text-center mb-8 flex flex-col items-center">
                    <Logo />
                    <div className="h-1 w-12 bg-gray-100 my-4"></div>
                    <p className="text-sm text-gray-500 uppercase tracking-widest font-bold">Secure Account Recovery</p>
                </div>

                {success ? (
                    <div className="text-center py-6 animate-fade-in">
                        <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-6">
                            <CheckCircle size={48} />
                        </div>
                        <h3 className="text-2xl font-bold text-masuma-dark mb-2">Success!</h3>
                        <p className="text-gray-600 mb-8 leading-relaxed">
                            Your password has been updated. You can now access the Masuma ERP with your new credentials.
                        </p>
                        <button 
                            onClick={onBack}
                            className="w-full bg-masuma-dark text-white py-4 rounded font-bold uppercase tracking-widest hover:bg-masuma-orange transition shadow-lg"
                        >
                            Return to Login
                        </button>
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} className="space-y-5">
                        <div className="bg-blue-50 p-4 rounded border border-blue-100 text-xs text-blue-700 font-bold uppercase tracking-tight flex items-start gap-3">
                            <ShieldCheck size={18} className="shrink-0" />
                            <span>Create a strong password to protect your access to the Masuma ERP system.</span>
                        </div>

                        {error && (
                            <div className="bg-red-50 text-red-600 p-4 rounded text-sm font-bold border border-red-100 flex items-start gap-2 animate-pulse">
                                <AlertCircle size={18} className="shrink-0" />
                                {error}
                            </div>
                        )}

                        <div className="space-y-4">
                            <div className="relative">
                                <label className="block text-[10px] font-black uppercase text-gray-400 mb-1 ml-1">New Password</label>
                                <div className="relative">
                                    <input 
                                        type={showPass ? "text" : "password"} 
                                        required
                                        value={password}
                                        onChange={e => setPassword(e.target.value)}
                                        className="w-full p-3 pl-10 border border-gray-300 rounded focus:border-masuma-orange focus:ring-1 focus:ring-masuma-orange outline-none transition bg-gray-50 focus:bg-white" 
                                        placeholder="Min. 8 characters"
                                    />
                                    <Lock className="absolute left-3 top-3.5 text-gray-300" size={18} />
                                    <button 
                                        type="button"
                                        onClick={() => setShowPass(!showPass)}
                                        className="absolute right-3 top-3.5 text-gray-400 hover:text-masuma-orange transition"
                                    >
                                        {showPass ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                </div>
                                {password.length > 0 && password.length < 8 && (
                                    <p className="text-[10px] text-red-500 font-bold mt-1 ml-1 uppercase">Too short</p>
                                )}
                            </div>

                            <div className="relative">
                                <label className="block text-[10px] font-black uppercase text-gray-400 mb-1 ml-1">Confirm Password</label>
                                <div className="relative">
                                    <input 
                                        type={showPass ? "text" : "password"} 
                                        required
                                        value={confirm}
                                        onChange={e => setConfirm(e.target.value)}
                                        className={`w-full p-3 pl-10 border rounded outline-none transition bg-gray-50 focus:bg-white ${
                                            confirm && password !== confirm ? 'border-red-300 focus:border-red-500' : 'border-gray-300 focus:border-masuma-orange'
                                        }`} 
                                        placeholder="Repeat your password"
                                    />
                                    <Lock className="absolute left-3 top-3.5 text-gray-300" size={18} />
                                </div>
                                {confirm && password !== confirm && (
                                    <p className="text-[10px] text-red-500 font-bold mt-1 ml-1 uppercase">Passwords do not match</p>
                                )}
                            </div>
                        </div>

                        <button 
                            type="submit" 
                            disabled={isLoading || !token || password !== confirm || password.length < 8}
                            className="w-full bg-masuma-dark text-white py-4 rounded font-bold uppercase tracking-widest hover:bg-masuma-orange transition shadow-xl flex items-center justify-center gap-2 disabled:opacity-50 disabled:grayscale"
                        >
                            {isLoading ? (
                                <>
                                    <Loader2 className="animate-spin" size={20} />
                                    Updating...
                                </>
                            ) : (
                                <>
                                    <ShieldCheck size={20} />
                                    Set New Password
                                </>
                            )}
                        </button>

                        <button 
                            type="button" 
                            onClick={onBack} 
                            className="w-full text-center text-xs text-gray-400 font-bold uppercase hover:text-masuma-dark mt-4 flex items-center justify-center gap-2"
                        >
                            <ArrowLeft size={14} /> Back to Login
                        </button>
                    </form>
                )}
            </div>

            <div className="fixed bottom-6 text-center text-[10px] text-gray-400 uppercase tracking-widest pointer-events-none">
                Masuma Autoparts EA Ltd • Internal Security System
            </div>
        </div>
    );
};

export default ResetPassword;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductList from './components/ProductList';
import CartDrawer from './components/CartDrawer';
import AIAssistant from './components/AIAssistant';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import ResetPassword from './components/ResetPassword';
import DashboardLayout from './components/admin/DashboardLayout';
import DashboardHome from './components/admin/DashboardHome';
import ProductManager from './components/admin/ProductManager';
import InventoryManager from './components/admin/InventoryManager';
import OrderManager from './components/admin/OrderManager';
import SalesHistory from './components/admin/SalesHistory';
import CustomerManager from './components/admin/CustomerManager';
import MpesaLogs from './components/admin/MpesaLogs';
import UserManager from './components/admin/UserManager';
import AuditLogs from './components/admin/AuditLogs';
import SettingsManager from './components/admin/SettingsManager';
import QuoteManager from './components/admin/QuoteManager';
import ReportsManager from './components/admin/ReportsManager';
import BranchManager from './components/admin/BranchManager';
import PosTerminal from './components/admin/PosTerminal';
import BlogManager from './components/admin/BlogManager';
import CmsManager from './components/admin/CmsManager';
import Profile from './components/admin/Profile';
import B2BPortal from './components/admin/B2BPortal';
import ShippingManager from './components/admin/ShippingManager';
import FinanceManager from './components/admin/FinanceManager';
import CategoryManager from './components/admin/CategoryManager';
import PartFinder from './components/PartFinder';
import Blog from './components/Blog';
import Contact from './components/Contact';
import About from './components/About';
import WarrantyPolicy from './components/WarrantyPolicy';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const handleRouting = async () => {
      const params = new URLSearchParams(window.location.search);
      const viewParam = params.get('view');
      const productParam = params.get('product');
      const postParam = params.get('post');

      // 1. Reset Password Priority (Email link)
      if (viewParam === 'RESET_PASSWORD') {
          setView('RESET_PASSWORD');
          return;
      }

      // 2. Product Deep Link
      if (productParam) {
          try {
              if (!selectedProduct || selectedProduct.id !== productParam) {
                  const res = await apiClient.get(`/products/${productParam}`);
                  if (res.data) setSelectedProduct(res.data);
              }
          } catch (e) {}
      } else if (selectedProduct) {
          setSelectedProduct(null);
      }

      // 3. Blog Deep Link
      if (postParam) {
          setActivePostId(postParam);
          setView('BLOG');
      } 
      // 4. General View navigation
      else if (viewParam) {
          setView(viewParam as ViewState);
      }
  };

  useEffect(() => {
      handleRouting();
      const storedToken = localStorage.getItem('masuma_auth_token');
      const storedUser = localStorage.getItem('masuma_user');
      if (storedToken && storedUser) {
          setToken(storedToken);
          setUser(JSON.parse(storedUser));
      }
      const storedCart = localStorage.getItem('masuma_cart');
      if (storedCart) setCart(JSON.parse(storedCart));

      window.addEventListener('popstate', handleRouting);
      return () => window.removeEventListener('popstate', handleRouting);
  }, []);

  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      const newUrl = `${window.location.pathname}?product=${product.id}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      setToast({ message: 'Operation Successful!', type: 'success' });
  };

  const renderContent = () => {
    // Lock into Reset Password regardless of login state if in URL
    if (view === 'RESET_PASSWORD') {
        return <ResetPassword onBack={() => setView('LOGIN')} />;
    }

    if (view === 'DASHBOARD' && user) {
        const renderModule = () => {
            switch(adminModule) {
                case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                case 'products': return <ProductManager />;
                case 'inventory': return <InventoryManager />;
                case 'orders': return <OrderManager />;
                case 'sales_history': return <SalesHistory />;
                case 'customers': return <CustomerManager />;
                case 'mpesa': return <MpesaLogs />;
                case 'users': return <UserManager />;
                case 'audit': return <AuditLogs />;
                case 'settings': return <SettingsManager />;
                case 'quotes': return <QuoteManager />;
                case 'reports': return <ReportsManager />;
                case 'branches': return <BranchManager />;
                case 'pos': return <PosTerminal />;
                case 'blog': return <BlogManager />;
                case 'cms': return <CmsManager />;
                case 'profile': return <Profile />;
                case 'b2b': return <B2BPortal />;
                case 'shipping': return <ShippingManager />;
                case 'finance': return <FinanceManager />;
                case 'categories': return <CategoryManager />;
                default: return <DashboardHome onNavigate={setAdminModule} />;
            }
        };

        return (
            <DashboardLayout activeModule={adminModule} onNavigate={setAdminModule} onLogout={() => { 
                localStorage.removeItem('masuma_auth_token');
                localStorage.removeItem('masuma_user');
                setUser(null); 
                setView('HOME'); 
            }}>
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {renderModule()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return <AdminLogin onLoginSuccess={(u, t) => { 
            setUser(u); 
            setToken(t); 
            localStorage.setItem('masuma_auth_token', t);
            localStorage.setItem('masuma_user', JSON.stringify(u));
            setView('DASHBOARD'); 
        }} onBack={() => setView('HOME')} />;
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar cartCount={cart.reduce((a, b) => a + b.quantity, 0)} setView={setView} toggleCart={() => setIsCartOpen(true)} toggleAi={() => setIsAiOpen(true)} />
            <main className="flex-grow">
            {view === 'HOME' && (
                <>
                <SEO title="Home" description="Official distributor of Masuma automotive parts in Kenya." />
                <Hero setView={setView} />
                <ProductList addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onProductClick={openProduct} />
                </>
            )}
            {view === 'CATALOG' && <ProductList addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onProductClick={openProduct} />}
            {view === 'PART_FINDER' && <PartFinder addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} />}
            {view === 'BLOG' && <Blog addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} initialPostId={activePostId} onProductClick={openProduct} />}
            {view === 'ABOUT' && <About setView={setView} />}
            {view === 'CONTACT' && <Contact />}
            {view === 'WARRANTY' && <WarrantyPolicy />}
            </main>
            <Footer setView={setView} />
            <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} cartItems={cart} removeFromCart={(id) => setCart(cart.filter(i => i.id !== id))} onCheckout={clearCart} updateQuantity={(id, q) => setCart(cart.map(i => i.id === id ? {...i, quantity: q} : i))} />
            <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />
            <QuickView product={selectedProduct} isOpen={!!selectedProduct} onClose={() => setSelectedProduct(null)} addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onSwitchProduct={setSelectedProduct} />
        </div>
    );
  };

  return (
    <>
        {renderContent()}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

export default App;

import 'reflect-metadata';
import path from 'path';
import fs from 'fs'; 

console.log(`\n🚀 [APP] Initializing Masuma ERP Server Module...`);

import { config } from './config/env'; 
import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
declare const require: any;

const compression = require('compression'); 
import rateLimit from 'express-rate-limit';
import { AppDataSource } from './config/database';
import { errorHandler } from './middleware/errorHandler'; 
import { httpLogger } from './middleware/httpLogger'; 
import { logger } from './utils/logger';
import { startEmailWorker } from './workers/emailWorker';

const app = express();
app.set('trust proxy', 1);

AppDataSource.initialize()
  .then(() => {
    logger.info(`✅ Database connected: ${config.DB_NAME}`);
    console.log('👷 [WORKER] Starting background services...');
    startEmailWorker();
  })
  .catch((err) => {
    logger.error('❌ Database connection failed:', err);
  });

app.use(helmet({
  crossOriginResourcePolicy: { policy: "cross-origin" },
  contentSecurityPolicy: false,
  crossOriginEmbedderPolicy: false 
}) as any); 
app.use(compression() as any); 

app.use(cors({ 
  origin: true,
  credentials: true 
}) as any);

app.use(express.json() as any);
app.use(httpLogger as any);

app.use('/media', express.static(path.join(process.cwd(), 'media')) as any);

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, 
  max: 20000,
  message: { error: 'Too many requests' }
});
app.use('/api', limiter as any);

// --- STATIC FRONTEND SERVING (PRODUCTION READY) ---
// We look for the 'dist' folder in several common locations
const possibleDistPaths = [
    path.join(process.cwd(), 'dist'),                         // Root of project
    path.join(process.cwd(), '..', 'dist'),                   // Parent (standard server setup)
    '/home/kemasuma/htdocs/masuma.africa/dist',              // Absolute production path
];

let frontendPath = '';
for (const p of possibleDistPaths) {
    if (fs.existsSync(p) && fs.existsSync(path.join(p, 'index.html'))) {
        frontendPath = p;
        console.log(`📂 [SERVER] Frontend detected and serving from: ${p}`);
        app.use(express.static(p) as any);
        break;
    }
}

if (!frontendPath) {
    console.warn('⚠️ [SERVER] WARNING: dist folder not found. Website will not load.');
}

// Routes
