import { Queue } from 'bullmq';
import nodemailer from 'nodemailer';
import { redis } from '../config/redis';
import { config } from '../config/env';

const smtpConfig = {
    host: config.SMTP_HOST || 'smtp.gmail.com',
    port: Number(config.SMTP_PORT) || 587,
    secure: Number(config.SMTP_PORT) === 465,
    auth: {
        user: config.SMTP_USER,
        pass: config.SMTP_PASS,
    },
    tls: {
        rejectUnauthorized: false 
    }
};

const transporter = nodemailer.createTransport(smtpConfig);

const getFromAddress = () => {
    const from = config.FROM_EMAIL || config.SMTP_USER || 'noreply@masuma.africa';
    if (!from.includes('@')) {
        return `"${from}" <${config.SMTP_USER}>`;
    }
    return from;
};

transporter.verify((error, success) => {
    if (error) {
        console.error('❌ [SMTP] Connection Error:', error.message);
    } else {
        console.log('✅ [SMTP] Connection Verified. Server is ready.');
    }
});

let emailQueue: Queue | null = null;
if (redis && process.env.DISABLE_EMAIL_QUEUE !== 'true') {
    emailQueue = new Queue('email-queue', { connection: redis });
}

export class EmailService {

    static async sendEmail(type: string, data: any) {
        if (emailQueue) {
            console.log(`[EMAIL] Queuing ${type} to ${data.email || 'Admin'}...`);
            await emailQueue.add('send-email', { type, data });
            return true;
        } else {
            console.log(`ℹ️ [EMAIL] Queue disabled. Sending ${type} directly...`);
            try {
                return await this.processDirectEmail(type, data);
            } catch (error) {
                console.error('❌ [EMAIL] Direct Send Failed:', error);
                return false;
            }
        }
    }

    static async processDirectEmail(type: string, data: any) {
        let subject = '';
        let html = '';
        let to = data.email;

        if (type === 'ORDER_CONFIRMATION') {
            subject = `Order Confirmation #${data.orderNumber} - Masuma Autoparts EA`;
            html = `
                <div style="font-family: sans-serif; max-width: 600px; padding: 20px; border: 1px solid #eee;">
                    <h2 style="color: #E0621B;">Jambo ${data.customerName}!</h2>
                    <p>We've received your payment and your order is now being processed.</p>
                    <div style="background: #f9f9f9; padding: 15px; margin: 20px 0;">
                        <p><strong>Order Number:</strong> ${data.orderNumber}</p>
                        <p><strong>Total Paid:</strong> KES ${Number(data.totalAmount).toLocaleString()}</p>
                        <p><strong>Status:</strong> PAID / PROCESSING</p>
                    </div>
                    <p>Our team at Ruby Mall is preparing your parts for dispatch. You will receive another email once your shipment is on the way.</p>
                    <p>Regards,<br/><strong>Masuma Autoparts East Africa Limited</strong></p>
                </div>
            `;
        } else if (type === 'SHIPMENT_DISPATCHED') {
            subject = `Your Order #${data.orderNumber} is on the way!`;
            html = `
                <div style="font-family: sans-serif; max-width: 600px; padding: 20px; border: 1px solid #eee;">
                    <h2 style="color: #E0621B;">Good News!</h2>
                    <p>Hi ${data.customerName}, your order <strong>#${data.orderNumber}</strong> has been dispatched from our Nairobi warehouse.</p>
                    <div style="background: #f9f9f9; padding: 15px; margin: 20px 0; border-left: 4px solid #E0621B;">
                        <p><strong>Delivery Method:</strong> Standard Dispatch</p>
                        <p><strong>Destination:</strong> ${data.shippingAddress || 'Nairobi Region'}</p>
                    </div>
                    <p>Our rider/driver will contact you at <strong>${data.customerPhone}</strong> upon arrival.</p>
                    <p>Thank you for choosing Masuma Japanese precision.</p>
                    <p>Regards,<br/><strong>Masuma Logistics Team</strong></p>
                </div>
            `;
        } else if (type === 'QUOTE_REQUEST') {
            await this.sendRawEmail(
                config.SMTP_USER || 'sales@masuma.africa',
                `New Inquiry: ${data.productName}`,
                `<p><strong>Customer:</strong> ${data.name} (${data.phone})</p><p><strong>Email:</strong> ${data.email}</p><p><strong>Product:</strong> ${data.productName}</p><p><strong>Message:</strong><br/>${data.message}</p>`
            );

            if (data.email && data.email.includes('@')) {
                to = data.email;
                subject = `We received your request: ${data.productName}`;
                html = `<p>Jambo ${data.name},</p><p>We have received your inquiry regarding <strong>${data.productName}</strong>.</p><br/><p>Regards,<br/>Masuma Autoparts EA Team</p>`;
            } else return true;
        } else if (type === 'PASSWORD_RESET') {
            subject = 'Reset Your Masuma ERP Password';
            const resetUrl = `${data.origin}/?view=RESET_PASSWORD&token=${data.token}`;
            html = `
                <div style="font-family: sans-serif; max-width: 600px; padding: 20px; border: 1px solid #eee;">
                    <h2 style="color: #E0621B;">Password Reset</h2>
                    <p>You requested a password reset for the Masuma Autoparts ERP.</p>
                    <a href="${resetUrl}" style="background: #1A1A1A; color: white; padding: 10px 20px; text-decoration: none; display: inline-block;">Reset Password</a>
                    <p style="font-size: 10px; color: #999; margin-top: 20px;">Link: ${resetUrl}</p>
                </div>
            `;
        }

        if (to && subject && html) {
            return await this.sendRawEmail(to, subject, html);
        }
        return false;
    }

    static async sendRawEmail(to: string, subject: string, html: string) {
        if (!config.SMTP_HOST || !config.SMTP_USER) {
            console.error('⚠️ [SMTP] Missing credentials in .env');
            return false;
        }
        try {
            const from = getFromAddress();
            console.log(`📧 [SMTP] Delivering to: ${to} from: ${from}`);
            const info = await transporter.sendMail({
                from,
                to,
                subject,
                html,
            });
            console.log(`✅ [SMTP] Success: ${info.messageId}`);
            return true;
        } catch(e: any) {
             console.error(`❌ [SMTP] Delivery Failed to ${to}:`, e.message);
             throw e;
        }
    }
}

import axios from 'axios';
import { Buffer } from 'buffer';
import { AppDataSource } from '../config/database';
import { MpesaTransaction } from '../entities/MpesaTransaction';
import { Order, OrderStatus } from '../entities/Order';
import { SystemSetting } from '../entities/SystemSetting';
import { CacheService } from '../lib/cache';
import { logger } from '../utils/logger';
import { SaleService } from './saleService';
import { EmailService } from './emailService';

export class MpesaService {
  private static transactionRepo = AppDataSource.getRepository(MpesaTransaction);
  private static orderRepo = AppDataSource.getRepository(Order);
  private static settingsRepo = AppDataSource.getRepository(SystemSetting);

  private static async getSetting(key: string, envKey?: string): Promise<string> {
    const setting = await this.settingsRepo.findOneBy({ key });
    if (setting && setting.value) return setting.value;
    return (envKey && process.env[envKey]) ? process.env[envKey]! : '';
  }

  private static formatPhoneNumber(phone: string): string {
    let p = phone.replace(/\D/g, ''); 
    if (p.startsWith('07') || p.startsWith('01')) {
      p = '254' + p.substring(1);
    } else if (p.startsWith('7') || p.startsWith('1')) {
        p = '254' + p;
    } else if (p.startsWith('+254')) {
        p = p.substring(1);
    }
    if (p.length === 9) p = '254' + p;
    return p;
  }

  private static async getAccessToken(): Promise<string> {
    return CacheService.getOrSet('mpesa_access_token', async () => {
        const consumerKey = await this.getSetting('MPESA_CONSUMER_KEY', 'MPESA_CONSUMER_KEY');
        const consumerSecret = await this.getSetting('MPESA_CONSUMER_SECRET', 'MPESA_CONSUMER_SECRET');
        const env = process.env.MPESA_ENV || 'sandbox';
        const baseUrl = env === 'production' ? 'https://api.safaricom.co.ke' : 'https://sandbox.safaricom.co.ke';

        if (!consumerKey || !consumerSecret) throw new Error('M-Pesa credentials not configured');

        const auth = Buffer.from(`${consumerKey}:${consumerSecret}`).toString('base64');
        try {
            const response = await axios.get(`${baseUrl}/oauth/v1/generate?grant_type=client_credentials`, {
                headers: { Authorization: `Basic ${auth}` }
            });
            return response.data.access_token;
        } catch (error: any) {
            throw new Error('Failed to authenticate with Safaricom');
        }
    }, 3300); 
  }

  static async initiateStkPush(orderId: string, phoneNumber: string, amount: number) {
    try {
        const token = await this.getAccessToken();
        const formattedPhone = this.formatPhoneNumber(phoneNumber);
        const timestamp = new Date().toISOString().replace(/[^0-9]/g, '').slice(0, 14);

        const shortcode = await this.getSetting('MPESA_SHORTCODE', 'MPESA_SHORTCODE');
        const passkey = await this.getSetting('MPESA_PASSKEY', 'MPESA_PASSKEY');
        const callbackUrl = await this.getSetting('MPESA_CALLBACK_URL', 'MPESA_CALLBACK_URL');
        const txType = await this.getSetting('MPESA_TRANSACTION_TYPE') || 'CustomerPayBillOnline'; 

        const env = process.env.MPESA_ENV || 'sandbox';
        const baseUrl = env === 'production' ? 'https://api.safaricom.co.ke' : 'https://sandbox.safaricom.co.ke';

        if (!shortcode || !passkey || !callbackUrl) throw new Error('Missing M-Pesa Configuration');

        const password = Buffer.from(`${shortcode}${passkey}${timestamp}`).toString('base64');

        const sanitizedRef = orderId.replace(/[^a-zA-Z0-9]/g, '').slice(-12).toUpperCase();

        const payload = {
            BusinessShortCode: shortcode,
            Password: password,
            Timestamp: timestamp,
            TransactionType: txType, 
            Amount: Math.round(amount), 
            PartyA: formattedPhone,
            PartyB: shortcode, 
            PhoneNumber: formattedPhone,
            CallBackURL: callbackUrl,
            AccountReference: sanitizedRef, 
            TransactionDesc: "Payment" 
        };

        logger.info(`Sending STK Push [Ref: ${payload.AccountReference}] to ${formattedPhone}`);

        const response = await axios.post(`${baseUrl}/mpesa/stkpush/v1/processrequest`, payload, {
            headers: { Authorization: `Bearer ${token}` }
        });

        const order = await this.orderRepo.findOneBy({ id: orderId });
        if (order) {
            const tx = this.transactionRepo.create({
                order: order,
                merchantRequestID: response.data.MerchantRequestID,
                checkoutRequestID: response.data.CheckoutRequestID,
                amount: amount,
                phoneNumber: formattedPhone,
                status: 'PENDING'
            });
            await this.transactionRepo.save(tx);
        }

        return response.data;
    } catch (error: any) {
        const apiMsg = error.response?.data?.errorMessage || error.message;
        logger.error('Daraja API Rejection:', apiMsg);
        throw new Error(`Safaricom rejected request: ${apiMsg}`);
    }
  }

  static async handleCallback(body: any) {
    const { stkCallback } = body.Body;
    if (!stkCallback) return;

    const { CheckoutRequestID, ResultCode, ResultDesc, CallbackMetadata } = stkCallback;
    const transaction = await this.transactionRepo.findOne({
      where: { checkoutRequestID: CheckoutRequestID },
      relations: ['order']
    });

    if (!transaction || transaction.status !== 'PENDING') return;

    if (ResultCode === 0) {
      const items = CallbackMetadata.Item;
      const receiptNumber = items.find((i: any) => i.Name === 'MpesaReceiptNumber')?.Value;
      const paidAmount = items.find((i: any) => i.Name === 'Amount')?.Value;

      transaction.mpesaReceiptNumber = receiptNumber;
      transaction.resultDesc = 'Success';
      transaction.amount = Number(paidAmount);
      transaction.status = 'COMPLETED';

      transaction.order.status = OrderStatus.PAID;
      transaction.order.amountPaid = Number(paidAmount);
      transaction.order.balance = 0;

      await this.transactionRepo.save(transaction);
      await this.orderRepo.save(transaction.order);

      const fullOrder = await this.orderRepo.findOne({
          where: { id: transaction.order.id },
          relations: ['items', 'items.product']
      });

      if (fullOrder) {
          try {
              // 1. Convert to Sale for ERP tracking
              await SaleService.createSaleFromOrder(fullOrder);

              // 2. Send Customer Confirmation Email
              if (fullOrder.customerEmail && fullOrder.customerEmail.includes('@')) {
                  await EmailService.sendEmail('ORDER_CONFIRMATION', {
                      email: fullOrder.customerEmail,
                      customerName: fullOrder.customerName,
                      orderNumber: fullOrder.orderNumber,
                      totalAmount: fullOrder.totalAmount
                  });
              }
          } catch (e) {
              logger.error('Post-payment automation failed', e);
          }
      }
    } else {
      transaction.status = 'FAILED';
      transaction.resultDesc = ResultDesc;
      await this.transactionRepo.save(transaction);
    }
  }
}

import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { Order, OrderStatus } from '../entities/Order';
import { OrderItem } from '../entities/OrderItem';
import { validate } from '../middleware/validate';
import { authenticate, authorize } from '../middleware/auth';
import { z } from 'zod';
import { SaleService } from '../services/saleService';
import { EmailService } from '../services/emailService';
import { logger } from '../utils/logger';

const router = Router();
const orderRepo = AppDataSource.getRepository(Order);

router.get('/:id/status', async (req: any, res: any) => {
  try {
    const { id } = req.params;
    const order = await orderRepo.findOne({
      where: { id: id },
      select: ['id', 'status', 'orderNumber']
    });

    if (!order) {
      logger.warn(`Order Status Polling: Order ${id} not found`);
      return res.status(404).json({ error: 'Order not found' });
    }

    res.json({ status: order.status });
  } catch (error) {
    logger.error(`Status Check Error for Order ${req.params.id}:`, error);
    res.status(500).json({ error: 'Server error during status check' });
  }
});

const createOrderSchema = z.object({
    customerName: z.string(),
    customerEmail: z.union([z.string().email(), z.string(), z.null(), z.undefined()]).optional(),
    customerPhone: z.string(),
    shippingAddress: z.string().optional(),
    items: z.array(z.object({
        productId: z.string(),
        quantity: z.coerce.number(),
        price: z.coerce.number()
    })),
    paymentMethod: z.string().optional()
});

router.post('/', validate(createOrderSchema), async (req, res) => {
    try {
        const { customerName, customerEmail, customerPhone, shippingAddress, items, paymentMethod } = req.body;
        const totalAmount = items.reduce((sum: number, item: any) => sum + (item.price * item.quantity), 0);

        const order = new Order();
        order.orderNumber = `ORD-${Date.now().toString().slice(-6)}`;
        order.customerName = customerName;
        order.customerEmail = (customerEmail && customerEmail.length > 0) ? customerEmail : undefined;
        order.customerPhone = customerPhone;
        order.shippingAddress = shippingAddress || '';
        order.totalAmount = totalAmount;
        order.amountPaid = 0;
        order.balance = totalAmount;
        order.status = OrderStatus.PENDING;
        order.paymentMethod = paymentMethod || 'MANUAL';

        order.items = items.map((i: any) => {
            const item = new OrderItem();
            item.product = { id: i.productId } as any;
            item.quantity = i.quantity;
            item.price = i.price;
            return item;
        });

        await orderRepo.save(order);
        res.status(201).json({ 
            message: 'Order created successfully', 
            orderId: order.id,
            orderNumber: order.orderNumber
        });
    } catch (error) {
        res.status(500).json({ error: 'Failed to create order' });
    }
});

router.get('/', authenticate, async (req, res) => {
    try {
        const status = req.query.status as string;
        const search = req.query.search as string;

        const query = orderRepo.createQueryBuilder('order')
            .leftJoinAndSelect('order.items', 'items')
            .leftJoinAndSelect('items.product', 'product')
            .leftJoinAndSelect('product.oemNumbers', 'oem')
            .orderBy('order.createdAt', 'DESC');

        if (status && status !== 'All Statuses' && status !== 'All') {
            query.andWhere('order.status = :status', { status });
        }

        if (search) {
            query.andWhere('(order.id LIKE :search OR order.customerName LIKE :search)', { search: `%${search}%` });
        }

        const orders = await query.take(50).getMany();
        const formattedOrders = orders.map(o => ({
            id: o.id,
            orderNumber: o.orderNumber || o.id.substring(0, 8).toUpperCase(),
            customerName: o.customerName,
            customerEmail: o.customerEmail,
            customerPhone: o.customerPhone,
            shippingAddress: o.shippingAddress,
            date: new Date(o.createdAt).toLocaleDateString(),
            total: Number(o.totalAmount),
            status: o.status,
            paymentMethod: o.paymentMethod || 'Manual',
            items: o.items.map(i => ({ 
                id: i.id,
                name: i.product?.name || 'Unknown Product', 
                sku: i.product?.sku || 'N/A',
                oem: i.product?.oemNumbers?.[0]?.code || '',
                qty: i.quantity,
                price: Number(i.price),
                image: i.product?.imageUrl
            }))
        }));

        res.json(formattedOrders);
    } catch (error) {
        res.status(500).json({ error: 'Failed to fetch orders' });
    }
});

const updateStatusSchema = z.object({
    status: z.enum(['PENDING', 'PAID', 'SHIPPED', 'DELIVERED', 'FAILED']),
    trackingInfo: z.string().optional()
});

router.patch('/:id/status', authenticate, authorize(['ADMIN', 'MANAGER']), validate(updateStatusSchema), async (req, res) => {
    try {
        const { status } = req.body;
        const order = await orderRepo.findOne({ 
            where: { id: req.params.id },
            relations: ['items', 'items.product'] 
        });

        if (!order) return res.status(404).json({ error: 'Order not found' });

        const previousStatus = order.status;
        order.status = status as OrderStatus;
        await orderRepo.save(order);

        // Automation 1: Create Sale when Paid
        if (status === 'PAID' && previousStatus !== 'PAID') {
            try {
                await SaleService.createSaleFromOrder(order, req.user);
            } catch (saleError) {
                console.error("Sale conversion failed", saleError);
            }
        }

        // Automation 2: Notify customer when Shipped
        if (status === 'SHIPPED' && previousStatus !== 'SHIPPED') {
            if (order.customerEmail && order.customerEmail.includes('@')) {
                try {
                    await EmailService.sendEmail('SHIPMENT_DISPATCHED', {
                        email: order.customerEmail,
                        customerName: order.customerName,
                        orderNumber: order.orderNumber,
                        customerPhone: order.customerPhone,
                        shippingAddress: order.shippingAddress
                    });
                } catch (emailError) {
                    logger.error("Shipping notification failed", emailError);
                }
            }
        }

        res.json(order);
    } catch (error) {
        res.status(500).json({ error: 'Failed to update order status' });
    }
});

export default router;

