export interface GeminiResponse {
  text: string;
  sources?: { uri: string; title: string }[];
}

export const sendMessageToGemini = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<GeminiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // SDK history must start with 'user'
  const cleanHistory = history.length > 0 && history[0].role === 'model' ? history.slice(1) : history;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [...cleanHistory, { role: 'user', parts: [{ text: message }] }],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }], // Enables live searching of masuma.parts and masuma.africa
    },
  });

  if (!response || !response.text) {
      throw new Error("Empty response from AI");
  }

  // Extract grounding URLs as sources
  const sources: { uri: string; title: string }[] = [];
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (groundingChunks) {
    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          uri: chunk.web.uri,
          title: chunk.web.title || 'Official Masuma Resource'
        });
      }
    });
  }

  // De-duplicate sources
  const uniqueSources = Array.from(new Map(sources.map(s => [s.uri, s])).values());

  return {
    text: response.text,
    sources: uniqueSources
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Sparkles, Bot, ExternalLink, Car } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';

// Extended type for grounding sources
interface ExtendedChatMessage extends ChatMessage {
  sources?: { uri: string; title: string }[];
}

interface AIAssistantProps {
  isOpen: boolean;
  onClose: () => void;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, onClose }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<ExtendedChatMessage[]>([
    { 
      role: 'model', 
      text: "Jambo! Karibu to Masuma Autoparts East Africa. 🇰🇪\n\nI am your intelligent assistant, trained with technical data from Masuma Japan. Are you looking for a specific part today, or do you need help identifying a part number for your vehicle?" 
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMessage: ExtendedChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
        const history = messages.map(m => ({
            role: m.role === 'model' ? 'model' : 'user',
            parts: [{ text: m.text }]
        }));

      const result = await sendMessageToGemini(history, userMessage.text);

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: result.text,
        sources: result.sources 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "I'm having trouble accessing the global parts database right now. Please try again in a moment.", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[1000] pointer-events-none flex flex-col md:flex-row items-end justify-end">
      {/* Backdrop */}
      <div 
          className="absolute inset-0 bg-black/50 pointer-events-auto md:bg-transparent" 
          onClick={onClose}
      ></div>

      <div className="pointer-events-auto absolute md:relative top-[120px] bottom-0 left-0 right-0 md:top-auto md:bottom-6 md:right-6 md:left-auto w-full md:w-[420px] md:h-[650px] bg-white md:rounded-xl shadow-2xl flex flex-col overflow-hidden border border-gray-200 font-sans animate-slide-up z-[1001]">

        {/* Header */}
        <div className="bg-masuma-dark p-4 flex justify-between items-center text-white border-b-4 border-masuma-orange shadow-md">
          <div className="flex items-center gap-3">
            <div className="bg-masuma-orange p-2 rounded-lg shadow-lg">
              <Bot size={22} className="text-white" />
            </div>
            <div>
              <h3 className="font-bold text-sm uppercase tracking-widest flex items-center gap-2">
                Masuma Expert AI
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              </h3>
              <p className="text-[10px] text-gray-400 font-medium">Synced with masuma.parts</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="p-2 text-gray-400 hover:text-white transition bg-white/5 rounded-full"
          >
            <X size={20} />
          </button>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-6 bg-gray-50/50">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`max-w-[90%] p-4 text-sm leading-relaxed shadow-sm rounded-2xl ${
                  msg.role === 'user' 
                    ? 'bg-masuma-orange text-white rounded-tr-none' 
                    : 'bg-white text-masuma-dark border border-gray-100 rounded-tl-none'
                } ${msg.isError ? 'border-red-500 text-red-600 bg-red-50' : ''}`}
              >
                <div className="whitespace-pre-wrap">{msg.text}</div>

                {/* Grounding Sources */}
                {msg.sources && msg.sources.length > 0 && (
                  <div className="mt-4 pt-3 border-t border-gray-100">
                    <p className="text-[10px] font-bold text-gray-400 uppercase mb-2">Verified Sources:</p>
                    <div className="flex flex-col gap-1.5">
                      {msg.sources.map((src, sIdx) => (
                        <a 
                          key={sIdx} 
                          href={src.uri} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="text-[10px] text-masuma-orange font-bold hover:underline flex items-center gap-1 bg-orange-50 p-1.5 rounded border border-orange-100 truncate"
                        >
                          <ExternalLink size={10} className="shrink-0" />
                          {src.title}
                        </a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex justify-start">
              <div className="bg-white text-masuma-dark p-4 rounded-2xl rounded-tl-none shadow-sm border border-gray-100 flex items-center gap-3">
                <div className="flex gap-1">
                  <div className="w-1.5 h-1.5 bg-masuma-orange rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                  <div className="w-1.5 h-1.5 bg-masuma-orange rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                  <div className="w-1.5 h-1.5 bg-masuma-orange rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                </div>
                <span className="text-[10px] font-bold uppercase text-gray-400 tracking-wider">Accessing Parts Catalog...</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Quick Actions */}
        {!isLoading && messages.length < 4 && (
          <div className="px-4 py-2 flex gap-2 overflow-x-auto bg-white border-t border-gray-50 scrollbar-hide">
             <button 
              onClick={() => { setInput("How do I find my Chassis Number?"); handleSend(); }}
              className="whitespace-nowrap px-3 py-1.5 bg-gray-100 hover:bg-masuma-orange hover:text-white text-[10px] font-bold uppercase rounded-full transition"
             >
               Find Chassis #
             </button>
             <button 
              onClick={() => { setInput("Tell me about the 12-month warranty"); handleSend(); }}
              className="whitespace-nowrap px-3 py-1.5 bg-gray-100 hover:bg-masuma-orange hover:text-white text-[10px] font-bold uppercase rounded-full transition"
             >
               Warranty Info
             </button>
             <button 
              onClick={() => { setInput("Where is Ruby Mall?"); handleSend(); }}
              className="whitespace-nowrap px-3 py-1.5 bg-gray-100 hover:bg-masuma-orange hover:text-white text-[10px] font-bold uppercase rounded-full transition"
             >
               Showroom Location
             </button>
          </div>
        )}

        {/* Input */}
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="relative flex items-center gap-2">
            <div className="relative flex-1">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Type your message here..."
                className="w-full pl-4 pr-10 py-4 bg-gray-100 border border-transparent rounded-xl focus:ring-2 focus:ring-masuma-orange/20 focus:bg-white transition outline-none text-sm text-masuma-dark"
                disabled={isLoading}
                autoFocus
              />
              <Car className="absolute right-3 top-4 text-gray-300" size={18} />
            </div>
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className="p-4 bg-masuma-dark text-white hover:bg-masuma-orange disabled:opacity-50 disabled:hover:bg-masuma-dark transition rounded-xl shadow-lg"
            >
              <Send size={18} />
            </button>
          </div>
          <p className="text-[8px] text-gray-400 text-center mt-3 font-medium uppercase tracking-[0.1em]">
            Masuma Intelligent Assistant • Japanese Precision
          </p>
        </div>

      </div>
    </div>
  );
};

