import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Edit2, Trash2, X, Save, Loader2, UploadCloud, Download, Upload, Package, ChevronLeft, ChevronRight, Percent, AlertTriangle, FileSpreadsheet, CheckCircle } from 'lucide-react';
import { Product, Branch } from '../../types';
import { apiClient } from '../../utils/apiClient';

const ProductManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isDiscountModalOpen, setIsDiscountModalOpen] = useState(false);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [pagination, setPagination] = useState({ page: 1, limit: 20, total: 0, pages: 1 });

  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [oemString, setOemString] = useState(''); 
  const [compatString, setCompatString] = useState(''); 

  const [discountPercentage, setDiscountPercentage] = useState<string>('0');
  const [isAdjusting, setIsAdjusting] = useState(false);

  // Bulk Import State
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importTargetBranch, setImportTargetBranch] = useState('');
  const [importStatus, setImportStatus] = useState<{success?: string, error?: string} | null>(null);

  const csvInputRef = useRef<HTMLInputElement>(null);

  const fetchProducts = async (page = 1) => {
    setIsLoading(true);
    try {
        const res = await apiClient.get(`/products?q=${searchTerm}&page=${page}&limit=${pagination.limit}`);
        if (res.data && res.data.data) {
            setProducts(res.data.data);
            setPagination(res.data.meta);
        } else {
            setProducts(res.data);
        }
    } catch (error) {
        console.error('Failed to fetch products', error);
    } finally {
        setIsLoading(false);
    }
  };

  const fetchData = async () => {
      try {
          const [catRes, branchRes] = await Promise.all([
              apiClient.get('/categories'),
              apiClient.get('/branches')
          ]);
          setCategories(catRes.data);
          setBranches(branchRes.data);
          if (branchRes.data.length > 0) setImportTargetBranch(branchRes.data[0].id);
      } catch (error) {
          console.error('Failed to fetch support data', error);
      }
  };

  useEffect(() => {
    const debounce = setTimeout(() => fetchProducts(1), 500);
    return () => clearTimeout(debounce);
  }, [searchTerm]);

  useEffect(() => {
      fetchData();
  }, []);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          fetchProducts(newPage);
      }
  };

  const handleDownloadTemplate = () => {
      const headers = "SKU,Name,Category,Price (Retail),Quantity,Cost Price,Wholesale Price,Description,OEM Numbers,Compatible Vehicles\n";
      const sample = "MFC-112,Oil Filter,Filters,850,100,450,750,Masuma genuine oil filter,\"90915-10001, 90915-YZZE1\",\"Toyota Vitz, Toyota Fielder\"";
      const blob = new Blob([headers + sample], { type: 'text/csv' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.setAttribute('hidden', '');
      a.setAttribute('href', url);
      a.setAttribute('download', 'masuma_kenya_import.csv');
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
  };

  /**
   * Robust CSV Parser that handles:
   * 1. Empty fields (,,)
   * 2. Commas inside quotes ("Field, With, Comma")
   * 3. Escaped quotes ("" inside quotes)
   */
  const parseCSV = (text: string) => {
      const lines = text.split(/\r?\n/);
      if (lines.length === 0) return [];

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const results = [];

      for (let i = 1; i < lines.length; i++) {
          const row = lines[i].trim();
          if (!row) continue;

          const values = [];
          let currentField = '';
          let inQuotes = false;

          for (let charIndex = 0; charIndex < row.length; charIndex++) {
              const char = row[charIndex];
              const nextChar = row[charIndex + 1];

              if (char === '"') {
                  if (inQuotes && nextChar === '"') {
                      // Escaped quote
                      currentField += '"';
                      charIndex++; // skip next quote
                  } else {
                      // Toggle quote state
                      inQuotes = !inQuotes;
                  }
              } else if (char === ',' && !inQuotes) {
                  // Field boundary
                  values.push(currentField.trim());
                  currentField = '';
              } else {
                  currentField += char;
              }
          }
          values.push(currentField.trim()); // Push final field

          const obj: any = {};
          headers.forEach((header, index) => {
              let val = values[index] !== undefined ? values[index].replace(/^"|"$/g, '').trim() : '';

              if (header === 'sku') obj['sku'] = val;
              else if (header === 'name') obj['name'] = val;
              else if (header === 'category') obj['category'] = val;
              else if (header === 'price (retail)') obj['price'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'quantity') obj['quantity'] = parseInt(val.replace(/[^0-9]/g, '')) || 0;
              else if (header === 'cost price') obj['costPrice'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'wholesale price') obj['wholesalePrice'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'description') obj['description'] = val;
              else if (header === 'oem numbers') obj['oemNumbers'] = val;
              else if (header === 'compatible vehicles') obj['compatibility'] = val;
          });
          results.push(obj);
      }
      return results;
  };

  const handleBulkSubmit = async () => {
      if (!bulkFile || !importTargetBranch) return;

      setIsImporting(true);
      setImportStatus(null);

      try {
          const reader = new FileReader();
          reader.onload = async (e) => {
              const text = e.target?.result as string;
              const products = parseCSV(text);

              if (products.length === 0) {
                  setImportStatus({ error: "CSV file is empty or formatted incorrectly." });
                  setIsImporting(false);
                  return;
              }

              try {
                  const res = await apiClient.post('/products/bulk', {
                      branchId: importTargetBranch,
                      products
                  });
                  setImportStatus({ success: `Done! Imported ${res.data.created} new items and updated ${res.data.updated} existing ones.` });
                  fetchProducts(1);
                  setBulkFile(null);
              } catch (err: any) {
                  const msg = err.response?.data?.error || "Import failed. Check data for excessively long text in Name column.";
                  setImportStatus({ error: msg });
              } finally {
                  setIsImporting(false);
              }
          };
          reader.readAsText(bulkFile);
      } catch (error) {
          setImportStatus({ error: "System could not read the file." });
          setIsImporting(false);
      }
  };

  const handleAddNew = () => {
    setFormData({
        name: '', sku: '', price: '', costPrice: '', wholesalePrice: '', quantity: '',
        description: '', category: categories[0]?.name || 'General', image: '', images: [], oemNumbers: [], compatibility: []
    });
    setOemString('');
    setCompatString('');
    setIsEditorOpen(true);
  };

  const handleEdit = (product: Product) => {
    setFormData({
        ...product,
        images: product.images || (product.image ? [product.image] : [])
    });
    setOemString(product.oemNumbers ? product.oemNumbers.join(', ') : '');
    setCompatString(product.compatibility ? product.compatibility.join(', ') : '');
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this product?')) return;

    try {
        await apiClient.delete(`/products/${id}`);
        fetchProducts(pagination.page);
        alert('Product deleted successfully.');
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to delete product.');
    }
  };

  const handleAdjustPrices = async () => {
      const pct = parseFloat(discountPercentage);
      if (isNaN(pct) || pct === 0) return alert("Please enter a valid percentage.");

      const action = pct < 0 ? 'Reduction' : 'Increase';
      if (!confirm(`CRITICAL ACTION: Are you sure you want to apply a ${Math.abs(pct)}% ${action} to ALL products in the database? This cannot be undone.`)) return;

      setIsAdjusting(true);
      try {
          await apiClient.post('/products/adjust-prices', { percentage: pct });
          alert(`Successfully applied ${pct}% adjustment.`);
          setIsDiscountModalOpen(false);
          fetchProducts(1);
      } catch (error) {
          alert("Failed to adjust prices.");
      } finally {
          setIsAdjusting(false);
      }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sku || (!formData.price && formData.price !== 0)) {
        alert('Please fill in required fields.');
        return;
    }

    setIsSaving(true);
    try {
        const payload = {
            ...formData,
            oemNumbers: oemString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            compatibility: compatString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            price: parseFloat(formData.price),
            costPrice: parseFloat(formData.costPrice || 0),
            wholesalePrice: formData.wholesalePrice ? parseFloat(formData.wholesalePrice) : undefined,
            quantity: parseInt(formData.quantity || 0)
        };

        if (formData.id) {
            await apiClient.put(`/products/${formData.id}`, payload);
        } else {
            await apiClient.post('/products', payload);
        }

        setIsEditorOpen(false);
        fetchProducts(pagination.page); 
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to save product.');
    } finally {
        setIsSaving(false);
    }
  };

  return (
    <div className="h-full flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Product Manager</h2>
