                                        </>
                                    )}
                                </div>
                                <input 
                                    type="file" 
                                    ref={csvInputRef} 
                                    className="hidden" 
                                    accept=".csv" 
                                    onChange={e => setBulkFile(e.target.files?.[0] || null)} 
                                />
                            </div>

                            {importStatus?.error && (
                                <div className="p-3 bg-red-50 border border-red-200 text-red-600 rounded text-xs font-bold flex items-center gap-2">
                                    <AlertTriangle size={14} /> {importStatus.error}
