                                {isImporting ? 'Processing Data...' : 'Start Import'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Global Adjust Modal */}
        {isDiscountModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-md rounded-lg shadow-2xl overflow-hidden animate-scale-up">
                    <div className="bg-masuma-dark text-white p-5 flex justify-between items-center">
                        <h3 className="font-bold uppercase tracking-wider flex items-center gap-2">
                            <Percent size={20} className="text-masuma-orange"/> Global Price Adjustment
                        </h3>
                        <button onClick={() => setIsDiscountModalOpen(false)} className="text-gray-400 hover:text-white transition"><X size={24} /></button>
                    </div>
                    <div className="p-6">
                        <div className="bg-orange-50 border border-orange-200 p-4 rounded-sm flex gap-3 mb-6">
                            <AlertTriangle className="text-masuma-orange shrink-0" size={24} />
                            <p className="text-xs text-orange-800 leading-relaxed font-bold">
                                WARNING: This action updates ALL products in the catalog. All retail and wholesale prices will be modified.
                            </p>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Percentage Change (%)</label>
                                <input 
                                    type="number" 
                                    className="w-full p-4 border-2 border-gray-200 rounded-lg text-2xl font-bold text-masuma-dark focus:border-masuma-orange outline-none"
