  }, [searchTerm]);

  useEffect(() => {
      fetchData();
  }, []);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          fetchProducts(newPage);
      }
  };

  const handleDownloadTemplate = () => {
      const headers = "SKU,Name,Category,Price (Retail),Quantity,Cost Price,Wholesale Price,Description,OEM Numbers,Compatible Vehicles\n";
      const sample = "MFC-112,Oil Filter,Filters,850,100,450,750,Masuma genuine oil filter,\"90915-10001, 90915-YZZE1\",\"Toyota Vitz, Toyota Fielder\"";
      const blob = new Blob([headers + sample], { type: 'text/csv' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.setAttribute('hidden', '');
      a.setAttribute('href', url);
      a.setAttribute('download', 'masuma_kenya_import.csv');
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
  };

  /**
   * Robust CSV Parser that handles:
   * 1. Empty fields (,,)
   * 2. Commas inside quotes ("Field, With, Comma")
   * 3. Escaped quotes ("" inside quotes)
   */
  const parseCSV = (text: string) => {
      const lines = text.split(/\r?\n/);
      if (lines.length === 0) return [];

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const results = [];

      for (let i = 1; i < lines.length; i++) {
          const row = lines[i].trim();
          if (!row) continue;

          const values = [];
          let currentField = '';
          let inQuotes = false;

          for (let charIndex = 0; charIndex < row.length; charIndex++) {
              const char = row[charIndex];
              const nextChar = row[charIndex + 1];

              if (char === '"') {
                  if (inQuotes && nextChar === '"') {
                      currentField += '"';
                      charIndex++; 
                  } else {
                      inQuotes = !inQuotes;
                  }
              } else if (char === ',' && !inQuotes) {
                  values.push(currentField.trim());
                  currentField = '';
              } else {
                  currentField += char;
              }
          }
          values.push(currentField.trim()); 

          const obj: any = {};
          headers.forEach((header, index) => {
              let val = values[index] !== undefined ? values[index].replace(/^"|"$/g, '').trim() : '';

              if (header === 'sku') obj['sku'] = val;
              else if (header === 'name') obj['name'] = val;
              else if (header === 'category') obj['category'] = val;
              else if (header === 'price (retail)') obj['price'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'quantity') {
                const num = parseInt(val.replace(/[^0-9]/g, ''));
                obj['quantity'] = isNaN(num) ? null : num;
              }
              else if (header === 'cost price') {
                const num = parseFloat(val.replace(/[^0-9.]/g, ''));
                obj['costPrice'] = isNaN(num) ? null : num;
              }
              else if (header === 'wholesale price') {
                const num = parseFloat(val.replace(/[^0-9.]/g, ''));
                obj['wholesalePrice'] = isNaN(num) ? null : num;
              }
              else if (header === 'description') obj['description'] = val;
              else if (header === 'oem numbers') obj['oemNumbers'] = val;
              else if (header === 'compatible vehicles') obj['compatibility'] = val;
          });
          results.push(obj);
      }
      return results;
  };

  const handleBulkSubmit = async () => {
      if (!bulkFile || !importTargetBranch) return;

      setIsImporting(true);
      setImportStatus(null);

      try {
          const reader = new FileReader();
          reader.onload = async (e) => {
              const text = e.target?.result as string;
              const products = parseCSV(text);

              if (products.length === 0) {
                  setImportStatus({ error: "CSV file is empty or formatted incorrectly." });
                  setIsImporting(false);
                  return;
              }

              try {
                  const res = await apiClient.post('/products/bulk', {
                      branchId: importTargetBranch,
                      products
                  });
                  setImportStatus({ success: `Done! Imported ${res.data.created} new items and updated ${res.data.updated} existing ones.` });
                  fetchProducts(1);
                  setBulkFile(null);
              } catch (err: any) {
                  const msg = err.response?.data?.error || "Import failed. Check data for excessively long text or invalid formats.";
                  setImportStatus({ error: msg });
              } finally {
                  setIsImporting(false);
              }
          };
          reader.readAsText(bulkFile);
      } catch (error) {
          setImportStatus({ error: "System could not read the file." });
          setIsImporting(false);
      }
  };

  const handleAddNew = () => {
    setFormData({
        name: '', sku: '', price: '', costPrice: '', wholesalePrice: '', quantity: '',
        description: '', category: categories[0]?.name || 'General', image: '', images: [], oemNumbers: [], compatibility: []
    });
    setOemString('');
    setCompatString('');
    setIsEditorOpen(true);
  };

  const handleEdit = (product: Product) => {
    setFormData({
        ...product,
        images: product.images || (product.image ? [product.image] : [])
    });
    setOemString(product.oemNumbers ? product.oemNumbers.join(', ') : '');
    setCompatString(product.compatibility ? product.compatibility.join(', ') : '');
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this product?')) return;

    try {
        await apiClient.delete(`/products/${id}`);
        fetchProducts(pagination.page);
        alert('Product deleted successfully.');
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to delete product.');
    }
  };

  const handleAdjustPrices = async () => {
      const pct = parseFloat(discountPercentage);
      if (isNaN(pct) || pct === 0) return alert("Please enter a valid percentage.");

      const action = pct < 0 ? 'Reduction' : 'Increase';
      if (!confirm(`CRITICAL ACTION: Are you sure you want to apply a ${Math.abs(pct)}% ${action} to ALL products in the database? This cannot be undone.`)) return;

      setIsAdjusting(true);
      try {
          await apiClient.post('/products/adjust-prices', { percentage: pct });
          alert(`Successfully applied ${pct}% adjustment.`);
          setIsDiscountModalOpen(false);
          fetchProducts(1);
      } catch (error) {
          alert("Failed to adjust prices.");
      } finally {
          setIsAdjusting(false);
      }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sku || (!formData.price && formData.price !== 0)) {
        alert('Please fill in required fields.');
        return;
    }

    setIsSaving(true);
    try {
        const payload = {
            ...formData,
            oemNumbers: oemString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            compatibility: compatString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            price: parseFloat(formData.price),
            costPrice: parseFloat(formData.costPrice || 0),
            wholesalePrice: formData.wholesalePrice ? parseFloat(formData.wholesalePrice) : undefined,
            quantity: parseInt(formData.quantity || 0)
        };

        if (formData.id) {
            await apiClient.put(`/products/${formData.id}`, payload);
        } else {
            await apiClient.post('/products', payload);
        }

        setIsEditorOpen(false);
        fetchProducts(pagination.page); 
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to save product.');
    } finally {
        setIsSaving(false);
    }
  };

  return (
    <div className="h-full flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Product Manager</h2>
                <p className="text-sm text-gray-500">Manage catalog, pricing, and specifications.</p>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={() => setIsBulkModalOpen(true)}
                    className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded font-bold uppercase text-xs hover:bg-gray-50 flex items-center gap-2"
                >
                    <Upload size={16} /> Bulk Import
                </button>
                <button 
                    onClick={() => setIsDiscountModalOpen(true)}
                    className="bg-white border border-gray-300 text-masuma-orange px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-50 flex items-center gap-2"
                >
                    <Percent size={16} /> Global Adjust
                </button>
                <button 
                    onClick={handleAddNew}
                    className="bg-masuma-orange text-white px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-600 flex items-center gap-2 shadow-md"
                >
                    <Plus size={16} /> Add Product
                </button>
            </div>
        </div>

        {/* Bulk Import Modal */}
        {isBulkModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-lg rounded-lg shadow-2xl overflow-hidden animate-scale-up">
                    <div className="bg-masuma-dark text-white p-5 flex justify-between items-center">
                        <h3 className="font-bold uppercase tracking-wider flex items-center gap-2">
                            <FileSpreadsheet size={20} className="text-masuma-orange"/> Bulk Part Import
                        </h3>
                        <button onClick={() => { setIsBulkModalOpen(false); setImportStatus(null); }} className="text-gray-400 hover:text-white transition"><X size={24} /></button>
                    </div>
                    <div className="p-6">
                        <div className="mb-6">
                            <button 
                                onClick={handleDownloadTemplate}
                                className="w-full flex items-center justify-center gap-2 py-3 border-2 border-dashed border-gray-200 text-gray-500 rounded-lg hover:border-masuma-orange hover:text-masuma-orange transition font-bold text-xs uppercase"
                            >
                                <Download size={16} /> Download CSV Template
                            </button>
                            <p className="text-[9px] text-gray-400 mt-2 text-center uppercase font-bold">Headers match your request: SKU, Name, Price (Retail), etc.</p>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Import Target Branch</label>
                                <select 
                                    className="w-full p-3 border border-gray-300 rounded-lg outline-none focus:border-masuma-orange bg-white text-sm"
                                    value={importTargetBranch}
                                    onChange={e => setImportTargetBranch(e.target.value)}
                                >
                                    {branches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
                                </select>
                            </div>

                            <div className="relative">
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Select CSV File</label>
                                <div 
                                    onClick={() => csvInputRef.current?.click()}
                                    className={`p-10 border-2 border-dashed rounded-lg flex flex-col items-center justify-center cursor-pointer transition ${bulkFile ? 'border-green-500 bg-green-50' : 'border-gray-200 hover:border-masuma-orange bg-gray-50'}`}
                                >
                                    {bulkFile ? (
                                        <>
                                            <CheckCircle className="text-green-600 mb-2" size={32} />
                                            <span className="text-sm font-bold text-green-700">{bulkFile.name}</span>
                                        </>
                                    ) : (
                                        <>
                                            <UploadCloud className="text-gray-400 mb-2" size={32} />
                                            <span className="text-xs font-bold text-gray-500 uppercase">Click to upload or drag & drop</span>
                                        </>
                                    )}
                                </div>
                                <input 
                                    type="file" 
                                    ref={csvInputRef} 
                                    className="hidden" 
                                    accept=".csv" 
                                    onChange={e => setBulkFile(e.target.files?.[0] || null)} 
                                />
                            </div>

                            {importStatus?.error && (
                                <div className="p-3 bg-red-50 border border-red-200 text-red-600 rounded text-xs font-bold flex items-center gap-2">
                                    <AlertTriangle size={14} /> {importStatus.error}
                                </div>
                            )}

                            {importStatus?.success && (
                                <div className="p-3 bg-green-50 border border-green-200 text-green-700 rounded text-xs font-bold flex items-center gap-2">
                                    <CheckCircle size={14} /> {importStatus.success}
                                </div>
                            )}

                            <button 
                                onClick={handleBulkSubmit}
                                disabled={isImporting || !bulkFile}
                                className="w-full bg-masuma-dark text-white py-4 rounded-lg font-bold uppercase tracking-widest hover:bg-masuma-orange transition flex items-center justify-center gap-2 disabled:opacity-50"
                            >
                                {isImporting ? <Loader2 className="animate-spin" size={20}/> : <Upload size={20}/>}
                                {isImporting ? 'Processing Data...' : 'Start Import'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Global Adjust Modal */}
        {isDiscountModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                <div className="bg-white w-full max-md rounded-lg shadow-2xl overflow-hidden animate-scale-up">
                    <div className="bg-masuma-dark text-white p-5 flex justify-between items-center">
                        <h3 className="font-bold uppercase tracking-wider flex items-center gap-2">
                            <Percent size={20} className="text-masuma-orange"/> Global Price Adjustment
                        </h3>
                        <button onClick={() => setIsDiscountModalOpen(false)} className="text-gray-400 hover:text-white transition"><X size={24} /></button>
                    </div>
                    <div className="p-6">
                        <div className="bg-orange-50 border border-orange-200 p-4 rounded-sm flex gap-3 mb-6">
                            <AlertTriangle className="text-masuma-orange shrink-0" size={24} />
                            <p className="text-xs text-orange-800 leading-relaxed font-bold">
                                WARNING: This action updates ALL products in the catalog. All retail and wholesale prices will be modified.
                            </p>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Percentage Change (%)</label>
                                <input 
                                    type="number" 
                                    className="w-full p-4 border-2 border-gray-200 rounded-lg text-2xl font-bold text-masuma-dark focus:border-masuma-orange outline-none"
                                    placeholder="e.g. -10 for reduction"
                                    value={discountPercentage}
                                    onChange={e => setDiscountPercentage(e.target.value)}
                                />
                                <p className="text-[10px] text-gray-400 mt-2 uppercase font-bold">
                                    Use negative values (e.g. -15) for discounts. <br/>
                                    Use positive values (e.g. 10) for price increases.
                                </p>
                            </div>

                            <button 
                                onClick={handleAdjustPrices}
                                disabled={isAdjusting}
                                className="w-full bg-masuma-dark text-white py-4 rounded-lg font-bold uppercase tracking-widest hover:bg-masuma-orange transition flex items-center justify-center gap-2 disabled:opacity-50"
                            >
                                {isAdjusting ? <Loader2 className="animate-spin" size={20}/> : <Percent size={20}/>}
                                {isAdjusting ? 'Processing Adjustment...' : 'Apply Bulk Update'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        {/* Editor Modal */}
        {isEditorOpen && (
            <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                <div className="bg-white w-full max-w-4xl rounded-lg shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-scale-up">
                    <div className="bg-masuma-dark text-white p-4 flex justify-between items-center">
                        <h3 className="font-bold uppercase tracking-wider">{formData.id ? 'Edit Product' : 'New Product'}</h3>
                        <button onClick={() => setIsEditorOpen(false)} className="text-gray-400 hover:text-white"><X size={24} /></button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-6 bg-gray-50">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="bg-white p-4 rounded shadow-sm border border-gray-200 space-y-4">
                                <h4 className="font-bold text-gray-500 text-xs uppercase border-b pb-2 mb-2">Core Details</h4>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">Part Name *</label>
                                        <input type="text" className="w-full p-2 border rounded focus:border-masuma-orange outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="e.g. Oil Filter" />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">SKU / Part No *</label>
                                        <input type="text" className="w-full p-2 border rounded focus:border-masuma-orange outline-none uppercase font-mono" value={formData.sku} onChange={e => setFormData({...formData, sku: e.target.value})} placeholder="MFC-112" />
                                    </div>
                                </div>
                                <div>
                                    <label className="text-xs font-bold text-gray-500 uppercase">Category *</label>
                                    <select className="w-full p-2 border rounded focus:border-masuma-orange outline-none bg-white" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}>
                                        {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="text-xs font-bold text-gray-500 uppercase">Description</label>
                                    <textarea className="w-full p-2 border rounded focus:border-masuma-orange outline-none h-20 resize-none" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})}></textarea>
                                </div>
                            </div>

                            <div className="bg-white p-4 rounded shadow-sm border border-gray-200 space-y-4">
                                <h4 className="font-bold text-gray-500 text-xs uppercase border-b pb-2 mb-2">Pricing & Inventory</h4>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">Retail Price (KES) *</label>
                                        <input type="number" className="w-full p-2 border rounded focus:border-masuma-orange outline-none" value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} placeholder="0" />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">Stock Quantity</label>
                                        <input type="number" className="w-full p-2 border rounded focus:border-masuma-orange outline-none" value={formData.quantity} onChange={e => setFormData({...formData, quantity: e.target.value})} placeholder="0" />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">Wholesale Price</label>
                                        <input type="number" className="w-full p-2 border rounded focus:border-masuma-orange outline-none" value={formData.wholesalePrice} onChange={e => setFormData({...formData, wholesalePrice: e.target.value})} placeholder="Optional" />
                                    </div>
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase">Cost Price</label>
                                        <input type="number" className="w-full p-2 border rounded focus:border-masuma-orange outline-none" value={formData.costPrice} onChange={e => setFormData({...formData, costPrice: e.target.value})} placeholder="Optional" />
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="p-4 border-t border-gray-200 bg-white flex justify-end gap-3">
                        <button onClick={() => setIsEditorOpen(false)} className="px-6 py-2 border rounded text-gray-500 font-bold uppercase text-xs hover:bg-gray-50">Cancel</button>
                        <button 
                            onClick={handleSave} 
                            disabled={isSaving}
                            className="bg-masuma-dark text-white px-8 py-2 rounded font-bold uppercase text-xs hover:bg-masuma-orange transition flex items-center gap-2 disabled:opacity-50"
                        >
                            {isSaving ? <Loader2 className="animate-spin" size={16}/> : <Save size={16}/>}
                            {formData.id ? 'Update Product' : 'Create Product'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Product List */}
        <div className="bg-white rounded-lg shadow-sm border border-gray-200 flex-1 flex flex-col overflow-hidden">
            <div className="p-4 border-b border-gray-200 bg-gray-50 flex gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-3 text-gray-400" size={18} />
                    <input 
                        type="text" 
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded outline-none focus:border-masuma-orange bg-white" 
                        placeholder="Search SKU or Name..." 
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            <div className="flex-1 overflow-auto">
                <table className="w-full text-left text-sm">
                    <thead className="bg-white text-gray-500 uppercase font-bold text-xs border-b border-gray-200 sticky top-0 z-10">
                        <tr>
                            <th className="px-6 py-3">Product</th>
                            <th className="px-6 py-3">SKU</th>
                            <th className="px-6 py-3">Category</th>
                            <th className="px-6 py-3">Price</th>
                            <th className="px-6 py-3">Stock</th>
                            <th className="px-6 py-3 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                        {products.map(product => (
                            <tr key={product.id} className="hover:bg-gray-50 group">
                                <td className="px-6 py-3">
                                    <div className="flex items-center gap-3">
                                        <span className="font-bold text-gray-800 line-clamp-1">{product.name}</span>
                                    </div>
                                </td>
                                <td className="px-6 py-3 font-mono text-xs text-masuma-dark">{product.sku}</td>
                                <td className="px-6 py-3 text-xs text-gray-500">{product.category}</td>
                                <td className="px-6 py-3 font-bold">{product.price.toLocaleString()}</td>
                                <td className="px-6 py-3">
                                    {(product.quantity || 0) > 5 ? (
                                        <span className="text-green-600 font-bold text-[10px] uppercase bg-green-50 px-2 py-1 rounded">{product.quantity || 0} In Stock</span>
                                    ) : (
                                        <span className="text-red-600 font-bold text-[10px] uppercase bg-red-50 px-2 py-1 rounded">Low Stock</span>
                                    )}
                                </td>
                                <td className="px-6 py-3 text-right">
                                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition">
                                        <button onClick={() => handleEdit(product)} className="p-2 bg-gray-100 rounded hover:bg-masuma-orange hover:text-white transition"><Edit2 size={14} /></button>
                                        <button onClick={() => handleDelete(product.id)} className="p-2 bg-gray-100 rounded hover:bg-red-500 hover:text-white transition"><Trash2 size={14} /></button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Pagination */}
            <div className="p-4 border-t border-gray-200 bg-gray-50 flex justify-between items-center">
                <span className="text-xs text-gray-500">Page {pagination.page} of {pagination.pages}</span>
                <div className="flex gap-2">
                    <button 
                        onClick={() => handlePageChange(pagination.page - 1)}
                        disabled={pagination.page === 1}
                        className="p-2 border rounded hover:bg-white disabled:opacity-50"
                    >
                        <ChevronLeft size={16} />
                    </button>
                    <button 
                        onClick={() => handlePageChange(pagination.page + 1)}
                        disabled={pagination.page === pagination.pages}
                        className="p-2 border rounded hover:bg-white disabled:opacity-50"
                    >
                        <ChevronRight size={16} />
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export default ProductManager;

import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Edit2, Trash2, X, Save, Loader2, UploadCloud, Download, Upload, Package, ChevronLeft, ChevronRight, Percent, AlertTriangle, FileSpreadsheet, CheckCircle } from 'lucide-react';
import { Product, Branch } from '../../types';
import { apiClient } from '../../utils/apiClient';

const ProductManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isDiscountModalOpen, setIsDiscountModalOpen] = useState(false);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [pagination, setPagination] = useState({ page: 1, limit: 20, total: 0, pages: 1 });

  const [isSaving, setIsSaving] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [oemString, setOemString] = useState(''); 
  const [compatString, setCompatString] = useState(''); 

  const [discountPercentage, setDiscountPercentage] = useState<string>('0');
  const [isAdjusting, setIsAdjusting] = useState(false);

  // Bulk Import State
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importTargetBranch, setImportTargetBranch] = useState('');
  const [importStatus, setImportStatus] = useState<{success?: string, error?: string} | null>(null);

  const csvInputRef = useRef<HTMLInputElement>(null);

  const fetchProducts = async (page = 1) => {
    setIsLoading(true);
    try {
        const res = await apiClient.get(`/products?q=${searchTerm}&page=${page}&limit=${pagination.limit}`);
        if (res.data && res.data.data) {
            setProducts(res.data.data);
            setPagination(res.data.meta);
        } else {
            setProducts(res.data);
        }
    } catch (error) {
        console.error('Failed to fetch products', error);
    } finally {
        setIsLoading(false);
    }
  };

  const fetchData = async () => {
      try {
          const [catRes, branchRes] = await Promise.all([
              apiClient.get('/categories'),
              apiClient.get('/branches')
          ]);
          setCategories(catRes.data);
          setBranches(branchRes.data);
          if (branchRes.data.length > 0) setImportTargetBranch(branchRes.data[0].id);
      } catch (error) {
          console.error('Failed to fetch support data', error);
      }
  };

  useEffect(() => {
    const debounce = setTimeout(() => fetchProducts(1), 500);
    return () => clearTimeout(debounce);
  }, [searchTerm]);

  useEffect(() => {
      fetchData();
  }, []);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          fetchProducts(newPage);
      }
  };

  const handleDownloadTemplate = () => {
      const headers = "SKU,Name,Category,Price (Retail),Quantity,Cost Price,Wholesale Price,Description,OEM Numbers,Compatible Vehicles\n";
      const sample = "MFC-112,Oil Filter,Filters,850,100,450,750,Masuma genuine oil filter,\"90915-10001, 90915-YZZE1\",\"Toyota Vitz, Toyota Fielder\"";
      const blob = new Blob([headers + sample], { type: 'text/csv' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.setAttribute('hidden', '');
      a.setAttribute('href', url);
      a.setAttribute('download', 'masuma_kenya_import.csv');
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
  };

  /**
   * Robust CSV Parser that handles:
   * 1. Empty fields (,,)
   * 2. Commas inside quotes ("Field, With, Comma")
   * 3. Escaped quotes ("" inside quotes)
   */
  const parseCSV = (text: string) => {
      const lines = text.split(/\r?\n/);
      if (lines.length === 0) return [];

      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const results: any[] = [];

      for (let i = 1; i < lines.length; i++) {
          const row = lines[i].trim();
          if (!row) continue;

          const values: string[] = [];
          let currentField = '';
          let inQuotes = false;

          for (let charIndex = 0; charIndex < row.length; charIndex++) {
              const char = row[charIndex];
              const nextChar = row[charIndex + 1];

              if (char === '"') {
                  if (inQuotes && nextChar === '"') {
                      currentField += '"';
                      charIndex++; 
                  } else {
                      inQuotes = !inQuotes;
                  }
              } else if (char === ',' && !inQuotes) {
                  values.push(currentField.trim());
                  currentField = '';
              } else {
                  currentField += char;
              }
          }
          values.push(currentField.trim()); 

          const obj: any = {};
          headers.forEach((header, index) => {
              let val = values[index] !== undefined ? values[index].replace(/^"|"$/g, '').trim() : '';

              if (header === 'sku') obj['sku'] = val;
              else if (header === 'name') obj['name'] = val;
              else if (header === 'category') obj['category'] = val;
              else if (header === 'price (retail)') obj['price'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'quantity') {
                const num = parseInt(val.replace(/[^0-9]/g, ''));
                obj['quantity'] = isNaN(num) ? null : num;
              }
              else if (header === 'cost price') {
                const num = parseFloat(val.replace(/[^0-9.]/g, ''));
                obj['costPrice'] = isNaN(num) ? null : num;
              }
              else if (header === 'wholesale price') {
                const num = parseFloat(val.replace(/[^0-9.]/g, ''));
                obj['wholesalePrice'] = isNaN(num) ? null : num;
              }
              else if (header === 'description') obj['description'] = val;
              else if (header === 'oem numbers') obj['oemNumbers'] = val;
              else if (header === 'compatible vehicles') obj['compatibility'] = val;
          });
          results.push(obj);
      }
      return results;
  };

  const handleBulkSubmit = async () => {
      if (!bulkFile || !importTargetBranch) return;

      setIsImporting(true);
      setImportStatus(null);

      try {
          const reader = new FileReader();
          reader.onload = async (e) => {
              const text = e.target?.result as string;
              const products = parseCSV(text);

              if (products.length === 0) {
                  setImportStatus({ error: "CSV file is empty or formatted incorrectly." });
                  setIsImporting(false);
                  return;
              }

              try {
                  const res = await apiClient.post('/products/bulk', {
                      branchId: importTargetBranch,
                      products
                  });
                  setImportStatus({ success: `Done! Imported ${res.data.created} new items and updated ${res.data.updated} existing ones.` });
                  fetchProducts(1);
                  setBulkFile(null);
              } catch (err: any) {
                  const msg = err.response?.data?.error || "Import failed. Check data for excessively long text or invalid formats.";
                  setImportStatus({ error: msg });
              } finally {
                  setIsImporting(false);
              }
          };
          reader.readAsText(bulkFile);
      } catch (error) {
          setImportStatus({ error: "System could not read the file." });
          setIsImporting(false);
      }
  };

  const handleAddNew = () => {
    setFormData({
        name: '', sku: '', price: '', costPrice: '', wholesalePrice: '', quantity: '',
        description: '', category: categories[0]?.name || 'General', image: '', images: [], oemNumbers: [], compatibility: []
    });
    setOemString('');
    setCompatString('');
    setIsEditorOpen(true);
  };

  const handleEdit = (product: Product) => {
    setFormData({
        ...product,
        images: product.images || (product.image ? [product.image] : [])
    });
    setOemString(product.oemNumbers ? product.oemNumbers.join(', ') : '');
    setCompatString(product.compatibility ? product.compatibility.join(', ') : '');
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this product?')) return;

    try {
        await apiClient.delete(`/products/${id}`);
        fetchProducts(pagination.page);
        alert('Product deleted successfully.');
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to delete product.');
    }
  };

  const handleAdjustPrices = async () => {
      const pct = parseFloat(discountPercentage);
      if (isNaN(pct) || pct === 0) return alert("Please enter a valid percentage.");

      const action = pct < 0 ? 'Reduction' : 'Increase';
      if (!confirm(`CRITICAL ACTION: Are you sure you want to apply a ${Math.abs(pct)}% ${action} to ALL products in the database? This cannot be undone.`)) return;

      setIsAdjusting(true);
      try {
          await apiClient.post('/products/adjust-prices', { percentage: pct });
          alert(`Successfully applied ${pct}% adjustment.`);
          setIsDiscountModalOpen(false);
          fetchProducts(1);
      } catch (error) {
          alert("Failed to adjust prices.");
      } finally {
          setIsAdjusting(false);
      }
  };

  const handleSave = async () => {
    if (!formData.name || !formData.sku || (!formData.price && formData.price !== 0)) {
        alert('Please fill in required fields.');
        return;
    }

    setIsSaving(true);
    try {
        const payload = {
            ...formData,
            oemNumbers: oemString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            compatibility: compatString.split(',').map(s => s.trim()).filter(s => s.length > 0),
            price: parseFloat(formData.price),
            costPrice: parseFloat(formData.costPrice || 0),
            wholesalePrice: formData.wholesalePrice ? parseFloat(formData.wholesalePrice) : undefined,
            quantity: parseInt(formData.quantity || 0)
        };

        if (formData.id) {
            await apiClient.put(`/products/${formData.id}`, payload);
        } else {
            await apiClient.post('/products', payload);
        }

        setIsEditorOpen(false);
        fetchProducts(pagination.page); 
    } catch (error: any) {
        alert(error.response?.data?.error || 'Failed to save product.');
    } finally {
        setIsSaving(false);
    }
  };

  return (
    <div className="h-full flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Product Manager</h2>
                <p className="text-sm text-gray-500">Manage catalog, pricing, and specifications.</p>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={() => setIsBulkModalOpen(true)}
                    className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded font-bold uppercase text-xs hover:bg-gray-50 flex items-center gap-2"
                >
                    <Upload size={16} /> Bulk Import
                </button>
                <button 
                    onClick={() => setIsDiscountModalOpen(true)}
                    className="bg-white border border-gray-300 text-masuma-orange px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-50 flex items-center gap-2"
                >
                    <Percent size={16} /> Global Adjust
                </button>
                <button 
                    onClick={handleAddNew}
                    className="bg-masuma-orange text-white px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-600 flex items-center gap-2 shadow-md"
                >
                    <Plus size={16} /> Add Product
                </button>
            </div>
        </div>

        {/* Bulk Import Modal */}
        {isBulkModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-lg rounded-lg shadow-2xl overflow-hidden animate-scale-up">
                    <div className="bg-masuma-dark text-white p-5 flex justify-between items-center">
