                            </button>
                            <p className="text-[9px] text-gray-400 mt-2 text-center uppercase font-bold">Headers match your request: SKU, Name, Price (Retail), etc.</p>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Import Target Branch</label>
                                <select 
                                    className="w-full p-3 border border-gray-300 rounded-lg outline-none focus:border-masuma-orange bg-white text-sm"
                                    value={importTargetBranch}
                                    onChange={e => setImportTargetBranch(e.target.value)}
                                >
                                    {branches.map(b => <option key={b.id} value={b.id}>{b.name} ({b.code})</option>)}
                                </select>
                            </div>

                            <div className="relative">
                                <label className="block text-xs font-bold text-gray-500 uppercase mb-2">Select CSV File</label>
                                <div 
                                    onClick={() => csvInputRef.current?.click()}
