export enum QuoteStatus {
  DRAFT = 'DRAFT',
  SENT = 'SENT',
  ACCEPTED = 'ACCEPTED',
  EXPIRED = 'EXPIRED',
  CONVERTED = 'CONVERTED' // New status
}

export enum QuoteType {
  STANDARD = 'STANDARD',
  SOURCING = 'SOURCING'
}

@Entity('quotes')
export class Quote {
  @PrimaryGeneratedColumn('uuid')
  id!: string;

  @Column({ unique: true })
  quoteNumber!: string; 

  @ManyToOne(() => Customer, (customer) => customer.quotes)
  customer!: Customer;

  @ManyToOne(() => User, { nullable: true })
