  @Column('decimal', { precision: 16, scale: 2 })
  tax!: number;

  @Column('decimal', { precision: 16, scale: 2 })
  total!: number;

  @Column({
    type: 'enum',
    enum: QuoteStatus,
    default: QuoteStatus.DRAFT
  })
  status!: QuoteStatus;

  @Column({
    type: 'enum',
    enum: QuoteType,
    default: QuoteType.STANDARD
  })
  requestType!: QuoteType;

  @Column({ type: 'date', nullable: true })
  validUntil?: Date;

  @CreateDateColumn()
  createdAt!: Date;

  @UpdateDateColumn()
  updatedAt!: Date;
}

