  };

  const handleSave = async () => {
    if (!formData.name || !formData.sku || (!formData.price && formData.price !== 0)) return alert('Fill required fields.');
    setIsSaving(true);
    try {
        const payload = { ...formData, oemNumbers: oemString.split(',').map(s => s.trim()).filter(s => s.length > 0), compatibility: compatString.split(',').map(s => s.trim()).filter(s => s.length > 0), price: parseFloat(formData.price), costPrice: parseFloat(formData.costPrice || 0), wholesalePrice: formData.wholesalePrice ? parseFloat(formData.wholesalePrice) : undefined, quantity: parseInt(formData.quantity || 0) };
        if (formData.id) await apiClient.put(`/products/${formData.id}`, payload);
        else await apiClient.post('/products', payload);
        setIsEditorOpen(false); fetchProducts(pagination.page); 
    } catch (error: any) { alert(error.response?.data?.error || 'Save failed.'); } finally { setIsSaving(false); }
  };

  return (
    <div className="h-full flex flex-col">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase">Product Manager</h2>
                <p className="text-sm text-gray-500">Manage catalog for Masuma Autoparts East Africa Limited.</p>
            </div>
            <div className="flex gap-2">
                <button onClick={() => { setImportStep('upload'); setBulkFile(null); setDryRunReport(null); setIsBulkModalOpen(true); }} className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded font-bold uppercase text-xs hover:bg-gray-50 flex items-center gap-2">
                    <Upload size={16} /> Bulk Import
                </button>
                <button onClick={() => setIsDiscountModalOpen(true)} className="bg-white border border-gray-300 text-masuma-orange px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-50 flex items-center gap-2">
                    <Percent size={16} /> Global Adjust
                </button>
                <button onClick={handleAddNew} className="bg-masuma-orange text-white px-4 py-2 rounded font-bold uppercase text-xs hover:bg-orange-600 flex items-center gap-2 shadow-md">
                    <Plus size={16} /> Add Product
                </button>
            </div>
        </div>

        {/* BULK IMPORT MODAL WIZARD */}
        {isBulkModalOpen && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                <div className="bg-white w-full max-w-4xl rounded-lg shadow-2xl overflow-hidden animate-scale-up flex flex-col max-h-[90vh]">
                    <div className="bg-masuma-dark text-white p-5 flex justify-between items-center">
                        <h3 className="font-bold uppercase tracking-wider flex items-center gap-2">
                            <FileSpreadsheet size={20} className="text-masuma-orange"/> Bulk Parts Importer
                        </h3>
                        <button onClick={() => setIsBulkModalOpen(false)} className="text-gray-400 hover:text-white"><X size={24} /></button>
                    </div>

                    {/* Stepper */}
                    <div className="bg-gray-100 px-6 py-3 flex gap-8 items-center border-b border-gray-200">
                        <div className={`flex items-center gap-2 text-xs font-bold uppercase ${importStep === 'upload' ? 'text-masuma-orange' : 'text-gray-400'}`}>
                            <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] ${importStep === 'upload' ? 'bg-masuma-orange text-white' : 'bg-gray-300 text-gray-500'}`}>1</span> Upload
