      const percentage = parseFloat(discountPercentage);
      if (isNaN(percentage)) return alert('Invalid percentage');
      setIsAdjusting(true);
      try {
          await apiClient.post('/products/adjust-prices', { percentage });
          setIsDiscountModalOpen(false);
          fetchProducts(1);
