                                        <input type="text" className="w-full p-3 border border-gray-300 rounded focus:border-masuma-orange outline-none font-mono uppercase" value={formData.sku} onChange={e => setFormData({...formData, sku: e.target.value})} />
                                    </div>
                                    <div>
                                        <label className="text-[10px] font-black uppercase text-gray-400 block mb-1">Category</label>
                                        <select className="w-full p-3 border border-gray-300 rounded bg-white outline-none" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}>
