                            <FileSpreadsheet size={20} className="text-masuma-orange"/> Bulk Parts Importer
                        </h3>
                        <button onClick={() => setIsBulkModalOpen(false)} className="text-gray-400 hover:text-white"><X size={24} /></button>
                    </div>

                    <div className="bg-gray-100 px-6 py-3 flex gap-8 items-center border-b border-gray-200">
                        <div className={`flex items-center gap-2 text-xs font-bold uppercase ${importStep === 'upload' ? 'text-masuma-orange' : 'text-gray-400'}`}>
                            <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] ${importStep === 'upload' ? 'bg-masuma-orange text-white' : 'bg-gray-300 text-gray-500'}`}>1</span> Upload
                        </div>
                        <ArrowRight size={14} className="text-gray-300"/>
                        <div className={`flex items-center gap-2 text-xs font-bold uppercase ${importStep === 'validate' ? 'text-masuma-orange' : 'text-gray-400'}`}>
                            <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] ${importStep === 'validate' ? 'bg-masuma-orange text-white' : 'bg-gray-300 text-gray-500'}`}>2</span> Validate
                        </div>
                        <ArrowRight size={14} className="text-gray-300"/>
                        <div className={`flex items-center gap-2 text-xs font-bold uppercase ${importStep === 'success' ? 'text-masuma-orange' : 'text-gray-400'}`}>
                            <span className={`w-5 h-5 rounded-full flex items-center justify-center text-[10px] ${importStep === 'success' ? 'bg-masuma-orange text-white' : 'bg-gray-300 text-gray-500'}`}>3</span> Finish
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-8 bg-gray-50/50">
                        {importStep === 'upload' && (
                            <div className="space-y-6">
                                <div className="bg-blue-50 border border-blue-100 p-4 rounded-sm flex gap-3">
                                    <Info className="text-blue-500 shrink-0" size={20}/>
                                    <p className="text-xs text-blue-800 leading-relaxed">
