                <span className="text-xs text-gray-500">Page {pagination.page} of {pagination.pages}</span>
                <div className="flex gap-2">
                    <button onClick={() => handlePageChange(pagination.page - 1)} disabled={pagination.page === 1} className="p-2 border rounded hover:bg-white disabled:opacity-50"><ChevronLeft size={16}/></button>
                    <button onClick={() => handlePageChange(pagination.page + 1)} disabled={pagination.page === pagination.pages} className="p-2 border rounded hover:bg-white disabled:opacity-50"><ChevronRight size={16}/></button>
                </div>
            </div>
        </div>
    </div>
  );
};

