const bulkImportSchema = z.object({
    branchId: z.string(),
    dryRun: z.boolean().optional().default(false),
    products: z.array(z.object({
        sku: z.string(),
        name: z.string(),
        category: z.string(),
        price: z.number().finite(),
        costPrice: z.number().finite().nullable().optional(), 
        wholesalePrice: z.number().finite().nullable().optional(), 
        description: z.string().optional(),
        oemNumbers: z.string().optional(), 
        compatibility: z.string().optional(),
        quantity: z.number().finite().nullable().optional(),
        lowStockThreshold: z.number().finite().nullable().optional(),
        imageUrl: z.string().optional()
    }))
});

router.post('/bulk', authenticate, authorize(['ADMIN', 'MANAGER']), validate(bulkImportSchema), async (req, res) => {
    const { branchId, products, dryRun } = req.body;
    const batchId = `BATCH-${new Date().toISOString().slice(0,10)}-${Math.random().toString(36).substring(7).toUpperCase()}`;
    const queryRunner = AppDataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
        const branch = await queryRunner.manager.findOneBy(Branch, { id: branchId });
        if (!branch) throw new Error('Invalid Branch ID');

        let createdCount = 0;
        let updatedCount = 0;
        const reports: { row: number, sku: string, status: 'CREATED' | 'UPDATED' | 'ERROR', message: string }[] = [];

        for (let i = 0; i < products.length; i++) {
            const item = products[i];
            try {
                const safeSku = item.sku.trim().toUpperCase();
                const safeName = item.name.trim().substring(0, 490);

                let category = await queryRunner.manager.findOneBy(Category, { name: item.category });
                if (!category) {
                    category = queryRunner.manager.create(Category, { name: item.category });
                    await queryRunner.manager.save(category);
                }

                let product = await queryRunner.manager.findOneBy(Product, { sku: safeSku });
                const price = Number(item.price) || 0;

                if (product) {
                    product.name = safeName;
                    product.price = price;
                    product.costPrice = Number(item.costPrice) || product.costPrice;
                    product.category = category;
                    await queryRunner.manager.save(product);
                    updatedCount++;
                    reports.push({ row: i + 1, sku: safeSku, status: 'UPDATED', message: 'Refreshed existing part.' });
                } else {
                    product = new Product();
                    product.sku = safeSku;
                    product.name = safeName;
                    product.price = price;
                    product.costPrice = Number(item.costPrice) || 0;
                    product.description = item.description || '';
                    product.category = category;
                    product.importBatchId = batchId; // Tag new products
                    await queryRunner.manager.save(product);
                    createdCount++;
                    reports.push({ row: i + 1, sku: safeSku, status: 'CREATED', message: 'New part added.' });
                }

                if (item.oemNumbers) {
                    await queryRunner.manager.delete(OemNumber, { product: { id: product.id } } as any);
                    const oems = item.oemNumbers.split(',').map(s => s.trim()).filter(s => s).map(code => {
                        const o = new OemNumber();
                        o.code = code.toUpperCase();
                        o.product = product!;
                        return o;
                    });
                    if (oems.length > 0) await queryRunner.manager.save(oems);
                }

                if (item.quantity !== undefined) {
                    let stock = await queryRunner.manager.findOne(ProductStock, {
                        where: { product: { id: product.id } as any, branch: { id: branch.id } as any }
                    });
                    if (!stock) {
                        stock = new ProductStock();
                        stock.product = product;
                        stock.branch = branch;
                    }
                    stock.quantity = Number(item.quantity) || 0;
                    await queryRunner.manager.save(stock);
                }
            } catch (rowError: any) {
                reports.push({ row: i + 1, sku: item.sku, status: 'ERROR', message: rowError.message });
            }
        }

        if (dryRun) {
            await queryRunner.rollbackTransaction();
            res.json({ message: 'Dry run completed.', created: createdCount, updated: updatedCount, reports, isDryRun: true });
        } else {
            await queryRunner.commitTransaction();
            res.json({ message: 'Import finalized.', created: createdCount, updated: updatedCount, reports, batchId, isDryRun: false });
        }
    } catch (error: any) {
        await queryRunner.rollbackTransaction();
        res.status(500).json({ error: error.message || 'Import failed' });
    } finally {
        await queryRunner.release();
    }
});

export default router;

import React, { useState, useEffect, useRef } from 'react';
import { Search, Plus, Edit2, Trash2, X, Save, Loader2, UploadCloud, Download, Upload, Package, ChevronLeft, ChevronRight, Percent, AlertTriangle, FileSpreadsheet, CheckCircle, Info, ArrowRight, RotateCcw, ShieldAlert, ChevronDown } from 'lucide-react';
import { Product, Branch } from '../../types';
import { apiClient } from '../../utils/apiClient';

const ProductManager: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [categories, setCategories] = useState<{id: string, name: string}[]>([]);
  const [branches, setBranches] = useState<Branch[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isDiscountModalOpen, setIsDiscountModalOpen] = useState(false);
  const [isBulkModalOpen, setIsBulkModalOpen] = useState(false);
  const [isNuclearOpen, setIsNuclearOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const [pagination, setPagination] = useState({ page: 1, limit: 20, total: 0, pages: 1 });
  const [isSaving, setIsSaving] = useState(false);
  const [formData, setFormData] = useState<any>({});
  const [oemString, setOemString] = useState(''); 
  const [compatString, setCompatString] = useState(''); 
  const [discountPercentage, setDiscountPercentage] = useState<string>('0');
  const [isAdjusting, setIsAdjusting] = useState(false);

  // Bulk Import Wizard State
  const [importStep, setImportStep] = useState<'upload' | 'validate' | 'success'>('upload');
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importTargetBranch, setImportTargetBranch] = useState('');
  const [dryRunReport, setDryRunReport] = useState<any>(null);
  const [importStatus, setImportStatus] = useState<{success?: string, error?: string, batchId?: string} | null>(null);
  const csvInputRef = useRef<HTMLInputElement>(null);

  const fetchProducts = async (page = 1) => {
    setIsLoading(true);
    try {
        const res = await apiClient.get(`/products?q=${searchTerm}&page=${page}&limit=${pagination.limit}`);
        if (res.data && res.data.data) {
            setProducts(res.data.data);
            setPagination(res.data.meta);
        } else {
            setProducts(res.data);
        }
    } catch (error) {
        console.error('Failed to fetch products', error);
    } finally {
        setIsLoading(false);
    }
  };

  const fetchData = async () => {
      try {
          const [catRes, branchRes] = await Promise.all([
              apiClient.get('/categories'),
              apiClient.get('/branches')
          ]);
          setCategories(catRes.data);
          setBranches(branchRes.data);
          if (branchRes.data.length > 0) setImportTargetBranch(branchRes.data[0].id);
      } catch (error) {
          console.error('Failed to fetch support data', error);
      }
  };

  useEffect(() => {
    const debounce = setTimeout(() => fetchProducts(1), 500);
    return () => clearTimeout(debounce);
  }, [searchTerm]);

  useEffect(() => {
      fetchData();
  }, []);

  const handlePageChange = (newPage: number) => {
      if (newPage >= 1 && newPage <= pagination.pages) {
          fetchProducts(newPage);
      }
  };

  const handleBulkSubmit = async (isDryRun: boolean = true) => {
      if (!bulkFile || !importTargetBranch) return;
      setIsImporting(true);
      setImportStatus(null);
      const reader = new FileReader();
      reader.onload = async (e) => {
          const text = e.target?.result as string;
          const products = parseCSV(text);
          if (products.length === 0) {
              setImportStatus({ error: "CSV file is empty." });
              setIsImporting(false);
              return;
          }
          try {
              const res = await apiClient.post('/products/bulk', { branchId: importTargetBranch, products, dryRun: isDryRun });
              if (isDryRun) {
                  setDryRunReport(res.data);
                  setImportStep('validate');
              } else {
                  setImportStatus({ 
                    success: `Import Finalized! ${res.data.created} created, ${res.data.updated} updated.`,
                    batchId: res.data.batchId
                  });
                  setImportStep('success');
                  fetchProducts(1);
              }
          } catch (err: any) {
              setImportStatus({ error: err.response?.data?.error || "Import failed." });
          } finally {
              setIsImporting(false);
          }
      };
      reader.readAsText(bulkFile);
  };

  const parseCSV = (text: string) => {
      const lines = text.split(/\r?\n/);
      if (lines.length === 0) return [];
      const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
      const results: any[] = [];
      for (let i = 1; i < lines.length; i++) {
          const row = lines[i].trim();
          if (!row) continue;
          const values: string[] = [];
          let currentField = '';
          let inQuotes = false;
          for (let charIndex = 0; charIndex < row.length; charIndex++) {
              const char = row[charIndex];
              const nextChar = row[charIndex + 1];
              if (char === '"') {
                  if (inQuotes && nextChar === '"') { currentField += '"'; charIndex++; } else { inQuotes = !inQuotes; }
              } else if (char === ',' && !inQuotes) { values.push(currentField.trim()); currentField = ''; } else { currentField += char; }
          }
          values.push(currentField.trim()); 
          const obj: any = {};
          headers.forEach((header, index) => {
              let val = values[index] !== undefined ? values[index].replace(/^"|"$/g, '').trim() : '';
              if (header === 'sku') obj['sku'] = val;
              else if (header === 'name') obj['name'] = val;
              else if (header === 'category') obj['category'] = val;
              else if (header === 'price (retail)') obj['price'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'quantity') obj['quantity'] = parseInt(val.replace(/[^0-9]/g, '')) || 0;
              else if (header === 'cost price') obj['costPrice'] = parseFloat(val.replace(/[^0-9.]/g, '')) || 0;
              else if (header === 'description') obj['description'] = val;
              else if (header === 'oem numbers') obj['oemNumbers'] = val;
          });
          results.push(obj);
      }
      return results;
  };

  const handleRollback = async (batchId: string) => {
      if (!confirm(`CAUTION: This will delete all products created in batch ${batchId}. This cannot be undone.`)) return;
      setIsImporting(true);
      try {
          await apiClient.delete(`/products/bulk/rollback/${batchId}`);
          alert('Rollback successful. Imported rows removed.');
          setIsBulkModalOpen(false);
          fetchProducts(1);
      } catch (e) {
          alert('Rollback failed.');
      } finally {
          setIsImporting(false);
      }
  };

  const handleClearAll = async () => {
      if (!confirm('ULTIMATE CAUTION: This will delete ALL products, stock records, and OEMs in the entire database. Type "CONFIRM" in the next prompt if you are sure.')) return;
      if (prompt('Type "CONFIRM" to proceed with a full catalog wipe:') !== 'CONFIRM') return;

      setIsLoading(true);
      try {
          await apiClient.post('/products/bulk/clear-all');
          alert('Database cleared. You can now perform a fresh import.');
          fetchProducts(1);
      } catch (e) {
          alert('Nuclear clear failed.');
      } finally {
          setIsLoading(false);
      }
  };

  const handleAddNew = () => {
    setFormData({ name: '', sku: '', price: '', costPrice: '', wholesalePrice: '', quantity: '', description: '', category: categories[0]?.name || 'General', image: '', images: [], oemNumbers: [], compatibility: [] });
    setOemString(''); setCompatString(''); setIsEditorOpen(true);
  };

  const handleEdit = (product: Product) => {
    setFormData({ ...product, images: product.images || (product.image ? [product.image] : []) });
    setOemString(product.oemNumbers ? product.oemNumbers.join(', ') : '');
    setCompatString(product.compatibility ? product.compatibility.join(', ') : '');
    setIsEditorOpen(true);
  };

  const handleDelete = async (id: string) => {
      if (!window.confirm('Are you sure you want to delete this product?')) return;
      try {
          await apiClient.delete(`/products/${id}`);
          fetchProducts(pagination.page);
      } catch (error: any) {
          alert(error.response?.data?.error || 'Delete failed.');
      }
  };

  const toggleSelect = (id: string) => {
      setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  return (
    <div className="h-full flex flex-col font-sans">
        <div className="flex justify-between items-center mb-6">
            <div>
                <h2 className="text-2xl font-bold text-masuma-dark font-display uppercase tracking-tight">Product Manager</h2>
                <p className="text-sm text-gray-500">Inventory control for Masuma Autoparts East Africa.</p>
            </div>
            <div className="flex gap-2">
                <div className="relative group">
                    <button onClick={() => setIsNuclearOpen(!isNuclearOpen)} className="bg-white border border-red-200 text-red-600 px-4 py-2 rounded font-bold uppercase text-[10px] hover:bg-red-50 flex items-center gap-2">
                        <ShieldAlert size={14} /> Advanced <ChevronDown size={12}/>
                    </button>
                    {isNuclearOpen && (
                        <div className="absolute right-0 mt-2 w-48 bg-white shadow-2xl rounded border border-gray-100 z-50 overflow-hidden animate-scale-up">
                            <button onClick={handleClearAll} className="w-full text-left px-4 py-3 text-[10px] font-bold text-red-600 hover:bg-red-600 hover:text-white transition uppercase border-b border-gray-50 flex items-center gap-2">
                                <Trash2 size={12}/> Clear All Products
                            </button>
                            <button onClick={() => setIsNuclearOpen(false)} className="w-full text-left px-4 py-2 text-[10px] font-bold text-gray-400 hover:bg-gray-50 uppercase">Close Menu</button>
                        </div>
                    )}
                </div>
                <button onClick={() => { setImportStep('upload'); setBulkFile(null); setDryRunReport(null); setIsBulkModalOpen(true); }} className="bg-white border border-gray-300 text-gray-700 px-4 py-2 rounded font-bold uppercase text-[10px] hover:bg-gray-50 flex items-center gap-2">
                    <Upload size={14} /> Bulk Import
                </button>
                <button onClick={handleAddNew} className="bg-masuma-orange text-white px-4 py-2 rounded font-bold uppercase text-[10px] hover:bg-orange-600 flex items-center gap-2 shadow-md">
                    <Plus size={14} /> Add Product
