router.post('/', authenticate, authorize(['ADMIN', 'MANAGER']), validate(createProductSchema), async (req, res) => {
    try {
        const payload = { ...req.body, branchId: req.user?.branch?.id };
        const product = await ProductService.createProduct(payload);
