            </div>
            <div className="flex-1 overflow-auto">
                <table className="w-full text-left text-sm">
                    <thead className="bg-white text-gray-500 uppercase font-bold text-[10px] border-b border-gray-200 sticky top-0 z-10 shadow-sm">
