export interface GeminiResponse {
  text: string;
  sources?: { uri: string; title: string }[];
}

export const sendMessageToGemini = async (history: {role: string, parts: {text: string}[]}[], message: string): Promise<GeminiResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // SDK history must start with 'user'
  const cleanHistory = history.length > 0 && history[0].role === 'model' ? history.slice(1) : history;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: [...cleanHistory, { role: 'user', parts: [{ text: message }] }],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      tools: [{ googleSearch: {} }], 
    },
  });

  if (!response || !response.text) {
      throw new Error("Empty response from AI");
  }

  const sources: { uri: string; title: string }[] = [];
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (groundingChunks) {
    groundingChunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({
          uri: chunk.web.uri,
          title: chunk.web.title || 'Official Masuma Resource'
        });
      }
    });
  }

  const uniqueSources = Array.from(new Map(sources.map(s => [s.uri, s])).values());

  return {
    text: response.text,
    sources: uniqueSources
  };
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Sparkles, Bot, ExternalLink, Car, ShieldCheck, MapPin } from 'lucide-react';
import { sendMessageToGemini } from '../services/geminiService';
import { ChatMessage } from '../types';

interface ExtendedChatMessage extends ChatMessage {
  sources?: { uri: string; title: string }[];
}

interface AIAssistantProps {
  isOpen: boolean;
  onClose: () => void;
}

const AIAssistant: React.FC<AIAssistantProps> = ({ isOpen, onClose }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [messages, setMessages] = useState<ExtendedChatMessage[]>([
    { 
      role: 'model', 
      text: "Jambo! Karibu to Masuma Autoparts East Africa Limited. 🇰🇪\n\nI am your technical specialist. I can help you find part numbers for your vehicle, explain our 12-month warranty, or help you locate our Nairobi showroom.\n\nWhich vehicle are you driving today?" 
    }
  ]);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMessage: ExtendedChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
        const history = messages.map(m => ({
            role: m.role === 'model' ? 'model' : 'user',
            parts: [{ text: m.text }]
        }));

      const result = await sendMessageToGemini(history, userMessage.text);

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: result.text,
        sources: result.sources 
      }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Samahani, I'm having trouble accessing our parts database right now. Please try again or visit us at Ruby Mall FF25.", isError: true }]);
