            <div>
              <h3 className="font-bold text-sm uppercase tracking-widest flex items-center gap-2">
                Masuma Expert AI
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              </h3>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tight">Nairobi HQ Showroom Connected</p>
            </div>
          </div>
          <button 
            onClick={onClose} 
            className="p-2 text-gray-400 hover:text-white transition bg-white/5 rounded-full"
          >
            <X size={20} />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-5 space-y-6 bg-gray-50/50">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`max-w-[85%] p-4 text-sm leading-relaxed shadow-sm rounded-2xl ${
                  msg.role === 'user' 
                    ? 'bg-masuma-orange text-white rounded-tr-none' 
