                className="w-full pl-4 pr-10 py-4 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-masuma-orange/20 focus:bg-white focus:border-masuma-orange transition outline-none text-sm text-masuma-dark"
                disabled={isLoading}
                autoFocus
              />
              <Car className="absolute right-3 top-4 text-gray-300" size={20} />
