import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { Subscriber } from '../entities/Subscriber';
import { validate } from '../middleware/validate';
import { z } from 'zod';
import { AuditService } from '../services/auditService';

const router = Router();
const subscriberRepo = AppDataSource.getRepository(Subscriber);

const subscribeSchema = z.object({
    email: z.string().email("Please provide a valid email address.")
});

router.post('/subscribe', validate(subscribeSchema), async (req, res) => {
    try {
        const { email } = req.body;

        const existing = await subscriberRepo.findOneBy({ email });
        if (existing) {
            return res.status(200).json({ message: 'You are already on our list!' });
        }

        const subscriber = subscriberRepo.create({ email });
        await subscriberRepo.save(subscriber);

        // Optional: Log subscription in audit for admin visibility
        await AuditService.log('NEWSLETTER_SIGNUP', email, `New subscriber joined: ${email}`);

        res.status(201).json({ message: 'Welcome to Masuma Autoparts! Subscription confirmed.' });
    } catch (error) {
        res.status(500).json({ error: 'Subscription failed. Please try again later.' });
    }
});

export default router;

