import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { Subscriber } from '../entities/Subscriber';
import { validate } from '../middleware/validate';
import { authenticate, authorize } from '../middleware/auth';
import { z } from 'zod';
import { AuditService } from '../services/auditService';

const router = Router();
const subscriberRepo = AppDataSource.getRepository(Subscriber);

const subscribeSchema = z.object({
    email: z.string().email("Please provide a valid email address.")
});

// GET /api/newsletter - Admin Only
router.get('/', authenticate, authorize(['ADMIN', 'MANAGER']), async (req, res) => {
    try {
        const subscribers = await subscriberRepo.find({
            order: { createdAt: 'DESC' }
        });
        res.json(subscribers);
    } catch (error) {
        res.status(500).json({ error: 'Failed to fetch subscribers' });
    }
});

// POST /api/newsletter/subscribe - Public
router.post('/subscribe', validate(subscribeSchema), async (req, res) => {
    try {
        const { email } = req.body;

        const existing = await subscriberRepo.findOneBy({ email });
        if (existing) {
            // Treat as success to the end-user but with a friendly message
            return res.status(200).json({ message: 'Jambo! You are already on our VIP list.' });
        }

        const subscriber = subscriberRepo.create({ email });
        await subscriberRepo.save(subscriber);

        // Optional: Log subscription in audit for admin visibility
        await AuditService.log('NEWSLETTER_SIGNUP', email, `New subscriber joined: ${email}`);

        res.status(201).json({ message: 'Welcome to Masuma! You will now receive exclusive updates.' });
    } catch (error) {
        res.status(500).json({ error: 'Subscription failed. Please try again later.' });
    }
});

// DELETE /api/newsletter/:id - Admin Only
router.delete('/:id', authenticate, authorize(['ADMIN']), async (req, res) => {
    try {
        await subscriberRepo.delete(req.params.id);
        res.json({ message: 'Subscriber removed.' });
    } catch (error) {
        res.status(500).json({ error: 'Failed to remove subscriber' });
    }
});

export default router;

