                                                    <ImageIcon size={32} className="mb-2" />
                                                    <span className="text-[10px] font-bold uppercase">No Images Uploaded</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <div>
                                        <label className="text-[10px] font-black uppercase text-gray-400 block mb-1">YouTube Video URL</label>
