                            <span className="inline-block px-3 py-1 bg-gray-50 border border-gray-200 text-xs font-bold text-gray-500 rounded-full shadow-sm">
                                {product.category}
                            </span>
                        </div>
                    </div>

                    {gallery.length > 1 && (
                        <div className="flex gap-2 overflow-x-auto pb-2 justify-center">
                            {gallery.map((img, idx) => (
                                <button 
                                    key={idx}
