                    <div className="relative flex-1 flex items-center justify-center min-h-[400px] md:min-h-[500px] bg-white group/viewer">
                        {activeMedia?.type === 'video' ? (
                            <div className="w-full h-full aspect-video">
                                <iframe 
                                    src={getYoutubeEmbedUrl(activeMedia.url)}
                                    className="w-full h-full"
                                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                    allowFullScreen
                                ></iframe>
                            </div>
                        ) : (
                            <img 
                                src={activeMedia?.url || 'https://via.placeholder.com/600x600?text=No+Image'} 
                                alt={product.name} 
                                className="max-h-[450px] md:max-h-[550px] w-full object-contain transition-all duration-700 p-12" 
                            />
                        )}

                        {media.length > 1 && (
                            <>
                                <button onClick={handlePrev} className="absolute left-8 top-1/2 -translate-y-1/2 p-4 bg-white/80 hover:bg-white text-masuma-dark rounded-2xl shadow-2xl transition-all opacity-0 group-hover/viewer:opacity-100 backdrop-blur-md">
                                    <ChevronLeft size={24} />
                                </button>
                                <button onClick={handleNext} className="absolute right-8 top-1/2 -translate-y-1/2 p-4 bg-white/80 hover:bg-white text-masuma-dark rounded-2xl shadow-2xl transition-all opacity-0 group-hover/viewer:opacity-100 backdrop-blur-md">
                                    <ChevronRight size={24} />
                                </button>
                            </>
