                    </div>

                    {media.length > 1 && (
                        <div className="bg-gray-100/50 p-6">
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide snap-x justify-center lg:justify-start">
                                {media.map((item, idx) => (
                                    <button 
                                        key={idx}
                                        onClick={() => setActiveIndex(idx)}
                                        className={`relative w-20 h-20 shrink-0 rounded-2xl overflow-hidden transition-all snap-start border-4 ${activeIndex === idx ? 'border-masuma-orange scale-110' : 'border-white hover:border-gray-200'}`}
                                    >
                                        {item.type === 'video' ? (
                                            <div className="w-full h-full bg-masuma-dark flex items-center justify-center">
                                                <Play size={20} className="text-white fill-current" />
                                            </div>
                                        ) : (
                                            <img src={item.url} className="w-full h-full object-cover" alt="" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* Details Section */}
                <div className="w-full lg:w-2/5 p-8 md:p-12 flex flex-col">
                    <div className="mb-10">
                        <div className="flex flex-wrap gap-2 mb-4">
                            <span className="px-4 py-1.5 bg-masuma-dark text-white text-[9px] font-black uppercase tracking-[0.2em] rounded-full">
                                {product.category}
                            </span>
                            {product.stock ? (
                                <span className="flex items-center gap-1.5 text-green-600 text-[9px] font-black uppercase tracking-[0.2em] bg-green-50 px-3 py-1.5 rounded-full">
                                    <Check size={12} strokeWidth={3} /> In Stock
                                </span>
                            ) : (
                                <span className="flex items-center gap-1.5 text-red-600 text-[9px] font-black uppercase tracking-[0.2em] bg-red-50 px-3 py-1.5 rounded-full">
                                    <AlertTriangle size={12} strokeWidth={3} /> Out of Stock
                                </span>
                            )}
                        </div>
                        <h2 className="text-3xl md:text-5xl font-bold text-masuma-dark font-display leading-[0.95] mb-4">{product.name}</h2>
                        <p className="text-[10px] text-gray-400 font-mono tracking-widest uppercase">Genuine Part No: {product.sku}</p>
