                                    {(product.oemNumbers || []).map((oem, i) => (
                                        <span key={i} className="px-3 py-1.5 bg-white border border-gray-200 text-gray-600 text-[10px] font-mono rounded-lg shadow-sm">{oem}</span>
                                    ))}
