            {/* Related Parts Section */}
            {relatedProducts.length > 0 && (
                <div className="p-12 bg-gray-50 border-t border-gray-100">
                    <div className="flex items-center justify-between mb-10">
                        <h3 className="text-2xl font-bold text-masuma-dark uppercase tracking-tight font-display">
                            Related Parts
                        </h3>
                        <div className="flex gap-2">
                             <div className="w-10 h-1 bg-masuma-orange rounded-full"></div>
                             <div className="w-4 h-1 bg-gray-200 rounded-full"></div>
                        </div>
                    </div>

                    <div className="flex gap-8 overflow-x-auto pb-6 scrollbar-hide snap-x">
                        {isLoadingRelated ? (
                            <div className="w-full text-center text-xs text-gray-400 py-12">Checking warehouse...</div>
                        ) : (
                            relatedProducts.map(rp => (
                                <div 
                                    key={rp.id} 
                                    onClick={() => handleSwitch(rp)}
                                    className="min-w-[260px] w-[260px] bg-white border border-gray-100 rounded-[32px] hover:shadow-2xl transition-all duration-500 cursor-pointer snap-start group flex flex-col p-4 shadow-sm"
                                >
                                    <div className="h-44 rounded-2xl bg-gray-50 relative p-6 flex items-center justify-center overflow-hidden mb-4">
                                        <img src={rp.image} alt={rp.name} className="max-h-full max-w-full object-contain group-hover:scale-110 transition duration-700" />
                                    </div>
                                    <div className="px-2 pb-2 flex-1 flex flex-col">
                                        <div className="text-[9px] text-gray-400 uppercase font-black mb-1 tracking-widest">{rp.sku}</div>
                                        <h4 className="text-sm font-bold text-masuma-dark leading-tight line-clamp-2 mb-4 group-hover:text-masuma-orange transition font-display">
                                            {rp.name}
                                        </h4>
                                        <div className="mt-auto flex justify-between items-center">
                                            <Price amount={rp.price} className="text-base font-black text-masuma-dark" />
                                            <div className="p-2 rounded-xl bg-gray-50 group-hover:bg-masuma-orange group-hover:text-white transition-colors">
                                                <ArrowRight size={16} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}
          </div>
        </div>
      </div>

      <QuoteModal 
        isOpen={isQuoteModalOpen} 
        onClose={() => setIsQuoteModalOpen(false)} 
        product={product} 
      />
    </>
  );
};

