import React, { useState, useEffect } from 'react';
import { ShieldCheck, ArrowLeft, Smartphone, CreditCard, Loader2, CheckCircle, AlertCircle, MapPin, User, Mail, Phone, Lock, ChevronRight, Package, Truck } from 'lucide-react';
import { CartItem, Product, ViewState } from '../types';
