import React, { useState, useEffect } from 'react';
import { X, Check, AlertTriangle, Truck, MessageCircle, Plus, Minus, ArrowRight, Share2, Facebook, Twitter, ChevronLeft, ChevronRight, Play, Info, ShieldCheck, Settings } from 'lucide-react';
import { Product } from '../types';
import QuoteModal from './QuoteModal';
import Price from './Price';
import { apiClient } from '../utils/apiClient';
import SEO from './SEO';

interface QuickViewProps {
  product: Product | null;
  isOpen: boolean;
  onClose: () => void;
  addToCart: (product: Product, quantity?: number) => void;
  onSwitchProduct?: (product: Product) => void;
}

interface MediaItem {
    url: string;
    type: 'image' | 'video';
}

const QuickView: React.FC<QuickViewProps> = ({ product, isOpen, onClose, addToCart, onSwitchProduct }) => {
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [isLoadingRelated, setIsLoadingRelated] = useState(false);

  // Carousel State
  const [media, setMedia] = useState<MediaItem[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    if (isOpen && product) {
        setQuantity(1);
        const items: MediaItem[] = [];
        if (product.image) {
            items.push({ url: product.image, type: 'image' });
        }
        if (product.images && Array.isArray(product.images)) {
            product.images.forEach(img => {
                if (img !== product.image) {
                    items.push({ url: img, type: 'image' });
                }
            });
        }
        if (product.videoUrl) {
            items.push({ url: product.videoUrl, type: 'video' });
        }
        if (items.length === 0) {
            items.push({ url: 'https://via.placeholder.com/800x800?text=No+Product+Image', type: 'image' });
        }

        setMedia(items);
        setActiveIndex(0);
        fetchRelatedProducts(product);
    }
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      setIsLoadingRelated(true);
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=12`);
          const allProducts = res.data.data || res.data || [];
          const filtered = allProducts.filter((p: Product) => p.id !== currentProduct.id);
          setRelatedProducts(filtered);
      } catch (error) {
          console.error("Failed to fetch related products", error);
          setRelatedProducts([]);
      } finally {
          setIsLoadingRelated(false);
      }
  };

  if (!isOpen || !product) return null;

  const handleNext = () => setActiveIndex((prev) => (prev + 1) % media.length);
  const handlePrev = () => setActiveIndex((prev) => (prev - 1 + media.length) % media.length);

  const handleQuantityChange = (delta: number) => {
    setQuantity(prev => Math.max(1, prev + delta));
  };

  const handleAddToCart = () => {
    addToCart(product, quantity);
    onClose();
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('quickview-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  const getYoutubeEmbedUrl = (url: string) => {
      if (!url) return '';
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      if (!id) return '';
      return `https://www.youtube.com/embed/${id}?autoplay=1`;
  };

  const handleSocialShare = (platform: 'whatsapp' | 'facebook' | 'twitter') => {
      const shareUrl = `${window.location.origin}/?product=${product.id}`;
      const shareText = `Masuma Japan Genuine: ${product.name}`;
      let url = '';
      switch (platform) {
          case 'whatsapp':
              url = `https://wa.me/?text=${encodeURIComponent(`${shareText} ${shareUrl}`)}`;
              break;
          case 'facebook':
              url = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(shareUrl)}`;
              break;
          case 'twitter':
              url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(shareText)}&url=${encodeURIComponent(shareUrl)}`;
              break;
      }
      window.open(url, '_blank', 'width=600,height=400');
  };

  const activeMedia = media[activeIndex];

  return (
    <>
      <SEO 
        title={`${product.sku} - ${product.name}`} 
        description={product.description.substring(0, 160)} 
        image={product.image}
        type="product"
      />

      <div className="fixed inset-0 z-[2000] flex items-center justify-center p-2 sm:p-4 md:p-8 lg:p-12 overflow-hidden">
        {/* Immersive Deep Backdrop */}
        <div 
          className="absolute inset-0 bg-masuma-dark/95 backdrop-blur-3xl transition-opacity duration-500"
          onClick={onClose}
        ></div>

        <div className="relative bg-white w-full max-w-[1600px] shadow-[0_0_100px_rgba(0,0,0,0.5)] overflow-hidden flex flex-col h-full max-h-[100%] lg:max-h-[90vh] animate-scale-up border border-white/10 rounded-sm lg:rounded-xl">

          {/* Top Control Bar */}
          <div className="absolute top-0 right-0 left-0 h-16 flex items-center justify-between px-6 z-[60] bg-white/80 backdrop-blur-md border-b border-gray-100">
             <div className="flex items-center gap-4">
                 <span className="text-[10px] font-black uppercase tracking-[0.3em] text-gray-400 bg-gray-100 px-3 py-1.5 rounded-full">Part Details View</span>
                 <span className="text-xs font-mono font-bold text-masuma-orange">{product.sku}</span>
             </div>
             <div className="flex items-center gap-2">
                 <button onClick={() => handleSocialShare('whatsapp')} className="p-2 text-gray-400 hover:text-green-600 transition"><Share2 size={18}/></button>
                 <button 
                    onClick={onClose}
                    className="p-2 text-gray-400 hover:text-masuma-orange transition-colors"
                  >
                    <X size={28} />
                  </button>
             </div>
          </div>

          <div id="quickview-content" className="flex-1 overflow-y-auto bg-white pt-16">
            <div className="flex flex-col lg:flex-row h-full">

                {/* Left: The Stage (Visual Content) */}
                <div className="w-full lg:w-[60%] bg-gray-50 flex flex-col relative min-h-[400px] lg:min-h-0 border-r border-gray-100">
                    <div className="absolute inset-0 flex items-center justify-center opacity-[0.03] pointer-events-none overflow-hidden">
                        <span className="text-[25vh] font-black uppercase tracking-tighter whitespace-nowrap rotate-[-15deg] select-none">{product.sku}</span>
                    </div>

                    <div className="relative flex-1 flex items-center justify-center p-12 group/viewer h-full">
                        {activeMedia?.type === 'video' ? (
                            <div className="w-full h-full aspect-video rounded-lg overflow-hidden shadow-2xl">
                                <iframe 
                                    src={getYoutubeEmbedUrl(activeMedia.url)}
                                    className="w-full h-full"
                                    allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                                    allowFullScreen
                                ></iframe>
                            </div>
                        ) : (
                            <img 
                                src={activeMedia?.url || 'https://via.placeholder.com/800x800?text=No+Image'} 
                                alt={product.name} 
                                className="max-h-[60vh] w-full object-contain transition-all duration-700 drop-shadow-2xl" 
                            />
                        )}

                        {media.length > 1 && (
                            <>
                                <button onClick={handlePrev} className="absolute left-8 top-1/2 -translate-y-1/2 p-4 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl transition-all opacity-0 group-hover/viewer:opacity-100 border border-gray-100">
                                    <ChevronLeft size={24} />
                                </button>
                                <button onClick={handleNext} className="absolute right-8 top-1/2 -translate-y-1/2 p-4 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl transition-all opacity-0 group-hover/viewer:opacity-100 border border-gray-100">
                                    <ChevronRight size={24} />
                                </button>
                            </>
                        )}
                    </div>

                    {media.length > 1 && (
                        <div className="p-6 bg-white border-t border-gray-100">
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide snap-x justify-center lg:justify-start">
                                {media.map((item, idx) => (
                                    <button 
                                        key={idx}
                                        onClick={() => setActiveIndex(idx)}
                                        className={`relative w-20 h-20 shrink-0 overflow-hidden transition-all snap-start border-2 ${activeIndex === idx ? 'border-masuma-orange scale-110 shadow-lg' : 'border-gray-200 opacity-60 hover:opacity-100'}`}
                                    >
                                        {item.type === 'video' ? (
                                            <div className="w-full h-full bg-masuma-dark flex items-center justify-center">
                                                <Play size={24} className="text-white fill-current" />
                                            </div>
                                        ) : (
                                            <img src={item.url} className="w-full h-full object-cover" alt="" />
                                        )}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* Right: Technical Panel */}
                <div className="w-full lg:w-[40%] flex flex-col bg-white overflow-y-auto">
                    <div className="p-8 lg:p-12 space-y-12">
                        {/* Title & Price Header */}
                        <div className="space-y-6">
                            <div className="flex flex-wrap gap-2">
                                <span className="px-3 py-1 bg-masuma-dark text-white text-[9px] font-black uppercase tracking-[0.2em]">
                                    {product.category}
                                </span>
                                {product.stock ? (
                                    <span className="flex items-center gap-1 text-green-600 text-[9px] font-black uppercase tracking-[0.2em] bg-green-50 px-2 py-1">
                                        <Check size={12} strokeWidth={3} /> Available Nairobi
                                    </span>
                                ) : (
                                    <span className="flex items-center gap-1 text-red-600 text-[9px] font-black uppercase tracking-[0.2em] bg-red-50 px-2 py-1">
                                        <AlertTriangle size={12} strokeWidth={3} /> Sourcing Required
                                    </span>
                                )}
                            </div>

                            <h2 className="text-4xl lg:text-6xl font-bold text-masuma-dark font-display leading-[0.9] uppercase tracking-tighter">{product.name}</h2>

                            <div className="flex items-baseline gap-4 pt-4 border-t border-gray-100">
                                <span className="text-5xl font-black text-masuma-orange">
                                    <Price amount={product.price} />
                                </span>
                                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Incl. 16% VAT</span>
                            </div>
                        </div>

                        {/* Description Section */}
                        <div className="space-y-4">
                            <h3 className="text-[11px] font-black text-masuma-dark uppercase tracking-[0.4em] flex items-center gap-2">
                                <Info size={14} className="text-masuma-orange"/> Description
                            </h3>
                            <p className="text-gray-500 text-sm leading-relaxed font-medium">
                                {product.description}
                            </p>
                        </div>

                        {/* Technical Data Grid */}
                        <div className="grid grid-cols-1 gap-8">
                            <div className="space-y-4">
                                <h3 className="text-[11px] font-black text-masuma-dark uppercase tracking-[0.4em] flex items-center gap-2">
                                    <Settings size={14} className="text-masuma-orange"/> Specifications
                                </h3>
                                <div className="space-y-2">
                                    <div className="flex justify-between py-2 border-b border-gray-50 text-sm">
                                        <span className="text-gray-400">Masuma Part No.</span>
                                        <span className="font-mono font-bold text-masuma-dark">{product.sku}</span>
                                    </div>
                                    <div className="flex justify-between py-2 border-b border-gray-50 text-sm">
                                        <span className="text-gray-400">Standard</span>
                                        <span className="font-bold text-masuma-dark">Japanese OE Spec</span>
                                    </div>
                                    <div className="py-2 border-b border-gray-50">
                                        <span className="text-gray-400 text-sm block mb-2">OEM Reference Codes</span>
                                        <div className="flex flex-wrap gap-2">
                                            {(product.oemNumbers || []).map((oem, i) => (
                                                <span key={i} className="px-2 py-1 bg-gray-100 text-gray-600 text-[10px] font-mono font-bold border border-gray-200">{oem}</span>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="space-y-4">
                                <h3 className="text-[11px] font-black text-masuma-dark uppercase tracking-[0.4em] flex items-center gap-2">
                                    <ShieldCheck size={14} className="text-masuma-orange"/> Compatibility
                                </h3>
                                <div className="bg-gray-50 p-4 border border-gray-100">
                                    <p className="text-sm text-gray-700 leading-relaxed font-bold">
                                        {(product.compatibility || []).join(' • ')}
                                    </p>
                                    <p className="text-[9px] text-gray-400 mt-2 uppercase font-black tracking-widest">
                                        * Verify via Chassis/VIN before checkout
                                    </p>
                                </div>
                            </div>
                        </div>

                        {/* Purchase Controls - Fixed for Desktop Panel */}
                        <div className="pt-8 border-t border-gray-100">
                            <div className="flex flex-col sm:flex-row gap-4">
                                {product.stock && (
                                    <div className="flex items-center bg-gray-100 p-1 rounded-sm">
                                        <button onClick={() => handleQuantityChange(-1)} className="w-12 h-12 flex items-center justify-center text-gray-400 hover:text-masuma-dark transition"><Minus size={16} /></button>
                                        <span className="w-10 text-center font-black text-masuma-dark text-lg">{quantity}</span>
                                        <button onClick={() => handleQuantityChange(1)} className="w-12 h-12 flex items-center justify-center text-gray-400 hover:text-masuma-dark transition"><Plus size={16} /></button>
                                    </div>
                                )}

                                <button
                                    onClick={handleAddToCart}
                                    disabled={!product.stock}
                                    className={`flex-1 h-14 font-black uppercase tracking-[0.25em] text-xs transition-all shadow-xl ${
                                        product.stock ? 'bg-masuma-orange text-white hover:bg-masuma-dark' : 'bg-gray-200 text-gray-400 cursor-not-allowed'
                                    }`}
                                >
                                    {product.stock ? 'Add To Local Order' : 'Out of Stock'}
                                </button>

                                <button
                                    onClick={() => setIsQuoteModalOpen(true)}
                                    className="h-14 w-14 bg-masuma-dark text-white hover:bg-masuma-orange transition-all flex items-center justify-center shadow-lg"
                                    title="Technical Inquiry"
                                >
                                    <MessageCircle size={24} />
                                </button>
                            </div>

                            <div className="mt-8 grid grid-cols-2 gap-4">
                                <div className="flex items-center gap-3 text-gray-400">
                                    <Truck size={18} className="text-masuma-orange shrink-0" />
                                    <span className="text-[9px] uppercase font-black tracking-widest leading-tight">Same-Day Dispatch <br/> Nairobi Area</span>
                                </div>
                                <div className="flex items-center gap-3 text-gray-400">
                                    <ShieldCheck size={18} className="text-masuma-orange shrink-0" />
                                    <span className="text-[9px] uppercase font-black tracking-widest leading-tight">12 Month <br/> Full Warranty</span>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Related Parts Footer - Inside Sidebar */}
                    {relatedProducts.length > 0 && (
                        <div className="mt-auto bg-gray-50 border-t border-gray-100 p-8">
                            <h3 className="text-xs font-black text-masuma-dark uppercase tracking-[0.2em] mb-6">You may also need</h3>
                            <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                                {isLoadingRelated ? (
                                    <div className="text-[10px] text-gray-400 animate-pulse">Scanning warehouse...</div>
                                ) : (
                                    relatedProducts.map(rp => (
                                        <div 
                                            key={rp.id} 
                                            onClick={() => handleSwitch(rp)}
                                            className="min-w-[140px] w-[140px] bg-white border border-gray-100 p-3 hover:border-masuma-orange transition-all cursor-pointer snap-start shadow-sm"
                                        >
                                            <div className="h-20 flex items-center justify-center mb-2">
                                                <img src={rp.image} alt={rp.name} className="max-h-full max-w-full object-contain" />
                                            </div>
                                            <div className="text-[9px] font-bold text-masuma-dark line-clamp-2 h-6 mb-2 leading-tight">{rp.name}</div>
                                            <div className="text-[10px] font-black text-masuma-orange">KES {rp.price.toLocaleString()}</div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}
                </div>
            </div>
          </div>
        </div>
      </div>

      <QuoteModal 
        isOpen={isQuoteModalOpen} 
        onClose={() => setIsQuoteModalOpen(false)} 
        product={product} 
      />
    </>
  );
};

