                    </div>

                    {/* Purchase Actions - Sticky Bottom on Mobile, Flowing on Desktop */}
                    <div className="pt-6 space-y-4">
                        <div className="flex gap-2">
                            {product.stock && (
                                <div className="flex items-center bg-gray-100 rounded-sm">
                                    <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="w-10 h-12 flex items-center justify-center text-gray-400 hover:text-masuma-dark"><Minus size={14} /></button>
