                            </button>
                            <button onClick={() => setIsQuoteModalOpen(true)} className="w-12 h-12 bg-masuma-dark text-white hover:bg-masuma-orange transition-all flex items-center justify-center rounded-sm"><MessageCircle size={20} /></button>
