                            </div>
                        </div>
                    </div>

                    {/* Related Parts Segment */}
                    {relatedProducts.length > 0 && (
                        <div className="pt-10 space-y-4">
                            <h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em]">Complementary Parts</h4>
