                                {relatedProducts.map(rp => (
                                    <div key={rp.id} onClick={() => handleSwitch(rp)} className="min-w-[120px] w-[120px] bg-white border border-gray-100 p-2 hover:border-masuma-orange transition-all cursor-pointer snap-start shadow-sm group/card">
