                                    <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Global SKU</span>
                                    <span className="font-mono font-bold text-masuma-dark bg-gray-50 px-2 py-0.5 rounded group-hover/spec:bg-masuma-orange group-hover/spec:text-white transition-colors">{product.sku}</span>
                                </div>
                                <div className="flex justify-between items-center text-xs">
                                    <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Quality Std</span>
