                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Description & Vehicle Fitment */}
                    <div className="space-y-8">
                        <div>
                            <h4 className="text-[11px] font-black text-masuma-dark uppercase tracking-[0.3em] mb-3 opacity-60">Description</h4>
                            <p className="text-sm text-gray-600 leading-relaxed font-medium">{product.description}</p>
                        </div>
                        <div className="bg-masuma-dark text-white p-5 rounded-lg shadow-inner border-l-4 border-masuma-orange relative overflow-hidden">
                            <div className="absolute top-[-10px] right-[-10px] opacity-10 rotate-12"><Check size={64}/></div>
                            <h4 className="text-[11px] font-black uppercase tracking-[0.3em] mb-3 flex items-center gap-2">Verified Fitment</h4>
