                                <div className="text-left">
                                    <h3 className="font-bold text-masuma-dark uppercase text-sm">Cash on Delivery</h3>
                                    <p className="text-[10px] text-gray-500 uppercase font-medium">Pay upon part arrival</p>
                                </div>
                            </button>
                        </div>
                    </div>

                    <div className="pt-6">
                        <button 
                            type="submit" 
