import React, { useState, useEffect, useRef } from 'react';
import { X, Check, AlertTriangle, Truck, MessageCircle, Plus, Minus, Share2, ChevronLeft, ChevronRight, Play, Info, ShieldCheck, Settings, Hash, Maximize2, ZoomIn } from 'lucide-react';
import { Product } from '../types';
import QuoteModal from './QuoteModal';
import Price from './Price';
import { apiClient } from '../utils/apiClient';
import SEO from './SEO';

interface QuickViewProps {
  product: Product | null;
  isOpen: boolean;
  onClose: () => void;
  addToCart: (product: Product, quantity?: number) => void;
  onSwitchProduct?: (product: Product) => void;
}

interface MediaItem {
    url: string;
    type: 'image' | 'video';
}

const QuickView: React.FC<QuickViewProps> = ({ product, isOpen, onClose, addToCart, onSwitchProduct }) => {
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [media, setMedia] = useState<MediaItem[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [zoomPos, setZoomPos] = useState({ x: 50, y: 50 }); // Center by default
  const [isZooming, setIsZooming] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  const stageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && product) {
        setQuantity(1);
        setIsFullScreen(false);
        const items: MediaItem[] = [];
        if (product.image) items.push({ url: product.image, type: 'image' });
        if (product.images && Array.isArray(product.images)) {
            product.images.forEach(img => {
                if (img !== product.image) items.push({ url: img, type: 'image' });
            });
        }
        if (product.videoUrl) items.push({ url: product.videoUrl, type: 'video' });
        if (items.length === 0) items.push({ url: 'https://via.placeholder.com/800x800?text=No+Product+Image', type: 'image' });

        setMedia(items);
        setActiveIndex(0);
        fetchRelatedProducts(product);
    }
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=6`);
          const allProducts = res.data.data || res.data || [];
          setRelatedProducts(allProducts.filter((p: Product) => p.id !== currentProduct.id));
      } catch (error) {
          console.error("Failed to fetch related products", error);
      }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
      if (!stageRef.current) return;
      const { left, top, width, height } = stageRef.current.getBoundingClientRect();
      const x = ((e.clientX - left) / width) * 100;
      const y = ((e.clientY - top) / height) * 100;
      setZoomPos({ x, y });
  };

  if (!isOpen || !product) return null;

  const getYoutubeEmbedUrl = (url: string) => {
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      return id ? `https://www.youtube.com/embed/${id}?autoplay=1` : '';
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('sidebar-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  const activeMedia = media[activeIndex];

  return (
    <>
      <SEO title={product.name} description={product.description} image={product.image} type="product" />

      <div className={`fixed inset-0 z-[2000] flex items-center justify-center overflow-hidden transition-all duration-500 ${isFullScreen ? 'p-0' : 'p-0 sm:p-4 md:p-6 lg:p-10'}`}>
        {/* Deep Backdrop */}
        <div className="absolute inset-0 bg-masuma-dark/98 backdrop-blur-3xl transition-opacity" onClick={onClose}></div>

        <div className={`relative bg-white w-full h-full shadow-2xl flex flex-col overflow-hidden animate-scale-up border border-white/5 transition-all duration-500 ${isFullScreen ? 'max-w-none max-h-none rounded-none' : 'max-w-[1450px] max-h-[92vh] sm:rounded-xl'}`}>

          {/* Header Bar */}
          <div className="flex-shrink-0 h-14 flex items-center justify-between px-6 bg-white border-b border-gray-100 z-50">
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2 px-3 py-1 bg-masuma-dark text-white rounded-full shadow-sm">
                    <Hash size={10} className="text-masuma-orange" />
                    <span className="text-[10px] font-black uppercase tracking-widest">{product.sku}</span>
                </div>
                <div className="h-4 w-px bg-gray-200 hidden md:block"></div>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] hidden md:inline">Japanese Precision Specification</span>
            </div>
            <div className="flex items-center gap-4">
                <button 
                  onClick={() => setIsFullScreen(!isFullScreen)}
                  className={`p-2 transition-colors ${isFullScreen ? 'text-masuma-orange' : 'text-gray-400 hover:text-masuma-dark'}`}
                  title="Toggle Cinema Mode"
                >
                  <Maximize2 size={18} />
                </button>
                <button onClick={() => window.open(`https://wa.me/?text=Check this Masuma part: ${window.location.origin}/?product=${product.id}`, '_blank')} className="text-gray-400 hover:text-green-600 transition"><Share2 size={18}/></button>
                <button onClick={onClose} className="p-1 text-gray-400 hover:text-masuma-orange transition-colors"><X size={32} strokeWidth={1.5} /></button>
            </div>
          </div>

          <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">

            {/* Left Column: The Cinema Stage (Optimized for detailed inspection) */}
            <div className="w-full lg:w-[55%] bg-white relative flex flex-col min-h-0 border-r border-gray-100 group/stage overflow-hidden">
                {/* Visual Grid Backdrop */}
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>

                {/* Image Stage */}
                <div 
                    ref={stageRef}
                    className="relative flex-1 flex items-center justify-center p-6 md:p-12 overflow-hidden cursor-crosshair bg-white"
                    onMouseEnter={() => setIsZooming(true)}
                    onMouseLeave={() => setIsZooming(false)}
                    onMouseMove={handleMouseMove}
                >
                    {activeMedia?.type === 'video' ? (
                        <div className="w-full h-full aspect-video rounded-lg shadow-2xl overflow-hidden bg-black max-w-4xl">
                            <iframe src={getYoutubeEmbedUrl(activeMedia.url)} className="w-full h-full" allowFullScreen></iframe>
                        </div>
                    ) : (
                        <div className="relative w-full h-full flex items-center justify-center overflow-hidden">
                            <img 
                                src={activeMedia?.url} 
                                alt={product.name} 
                                style={{ 
                                    transformOrigin: `${zoomPos.x}% ${zoomPos.y}%`,
                                    transform: isZooming ? 'scale(2.5)' : 'scale(1)'
                                }}
                                className={`max-w-full max-h-[65vh] object-contain transition-transform duration-200 ease-out will-change-transform ${!isZooming ? 'drop-shadow-[0_15px_35px_rgba(0,0,0,0.1)]' : ''}`}
                            />

                            {/* Controls Hints */}
                            {!isZooming && activeMedia?.type === 'image' && (
                                <div className="absolute bottom-4 flex items-center gap-2 bg-masuma-dark/5 backdrop-blur-md px-3 py-1.5 rounded-full border border-black/5">
                                    <ZoomIn size={12} className="text-masuma-orange" />
                                    <span className="text-[9px] font-black uppercase text-masuma-dark/60 tracking-widest">Precision Hover Zoom</span>
                                </div>
                            )}
                        </div>
                    )}

                    {media.length > 1 && (
                        <>
                            <button onClick={() => setActiveIndex((prev) => (prev - 1 + media.length) % media.length)} className="absolute left-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 hover:scale-110 active:scale-95 z-50"><ChevronLeft size={24} /></button>
                            <button onClick={() => setActiveIndex((prev) => (prev + 1) % media.length)} className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 hover:scale-110 active:scale-95 z-50"><ChevronRight size={24} /></button>
                        </>
                    )}
                </div>

                {/* Thumbnail Strip */}
                {media.length > 1 && (
                    <div className="h-24 bg-white border-t border-gray-100 flex items-center px-6 gap-3 overflow-x-auto scrollbar-hide">
                        {media.map((item, idx) => (
                            <button 
                                key={idx} 
                                onClick={() => setActiveIndex(idx)}
                                className={`relative w-16 h-16 shrink-0 border-2 transition-all p-1.5 bg-gray-50 rounded-lg group/thumb ${activeIndex === idx ? 'border-masuma-orange scale-105 shadow-md bg-white' : 'border-transparent opacity-60 hover:opacity-100 hover:bg-white'}`}
                            >
                                {item.type === 'video' ? <div className="w-full h-full bg-masuma-dark flex items-center justify-center text-white rounded-md"><Play size={16} /></div> : <img src={item.url} className="w-full h-full object-contain rounded-sm transition-transform group-hover/thumb:scale-110" alt="" />}
                            </button>
                        ))}
                    </div>
                )}
            </div>

            {/* Right Column: Information Panel (Balanced Layout) */}
            <div id="sidebar-content" className="w-full lg:w-[45%] flex flex-col bg-white overflow-y-auto border-l border-gray-100 scrollbar-hide">
                <div className="p-8 lg:p-10 space-y-8">
                    {/* Brand Header */}
                    <div className="space-y-3">
                        <div className="flex flex-wrap gap-2">
                            <span className="px-2 py-0.5 bg-masuma-dark text-white text-[9px] font-black uppercase tracking-[0.2em] rounded-sm">{product.category}</span>
                            {product.stock ? (
                                <span className="text-green-600 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-green-50 px-2 py-0.5 rounded-sm"><Check size={10} strokeWidth={3} /> In Stock Nairobi</span>
                            ) : (
                                <span className="text-red-500 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-red-50 px-2 py-0.5 rounded-sm"><AlertTriangle size={10} strokeWidth={3} /> Special Order Only</span>
                            )}
                        </div>
                        <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold text-masuma-dark font-display uppercase leading-[0.9] tracking-tight">{product.name}</h2>
                        <div className="flex items-baseline gap-4 pt-4 border-t border-gray-50">
                            <span className="text-4xl lg:text-5xl font-black text-masuma-orange tracking-tighter"><Price amount={product.price} /></span>
                            <div className="flex flex-col">
                                <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none">Net Local Price</span>
                                <span className="text-[9px] text-gray-400 font-bold uppercase tracking-widest mt-1">Incl. 16% VAT</span>
                            </div>
                        </div>
                    </div>

                    {/* Technical Dashboard */}
                    <div className="grid grid-cols-1 gap-6 py-6 border-y border-gray-100">
                        <div className="space-y-4">
                            <h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em] flex items-center gap-2 border-l-3 border-masuma-orange pl-3">Japanese Engineering Specs</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-3 gap-x-6 text-xs">
                                <div className="flex justify-between items-center group/spec">
                                    <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Global SKU</span>
                                    <span className="font-mono font-bold text-masuma-dark bg-gray-50 px-2 py-0.5 rounded transition-colors group-hover/spec:bg-masuma-orange group-hover/spec:text-white">{product.sku}</span>
                                </div>
                                <div className="flex justify-between items-center">
                                    <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Grade</span>
                                    <span className="font-bold text-masuma-dark">Japanese OE Std</span>
                                </div>
                            </div>
                            <div className="pt-2">
