                </div>
                <div className="h-4 w-px bg-gray-200 hidden md:block"></div>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] hidden md:inline">Japanese Precision Specification</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setIsFullScreen(!isFullScreen)} className={`p-2 transition-colors ${isFullScreen ? 'text-masuma-orange' : 'text-gray-400 hover:text-masuma-dark'}`} title="Toggle Cinema Mode"><Maximize2 size={18} /></button>
                <button onClick={() => window.open(`https://wa.me/?text=Check this Masuma part: ${window.location.origin}/?product=${product.id}`, '_blank')} className="text-gray-400 hover:text-green-600 transition"><Share2 size={18}/></button>
                <button onClick={onClose} className="p-1 text-gray-400 hover:text-masuma-orange transition-colors"><X size={32} strokeWidth={1.5} /></button>
            </div>
          </div>

          <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
            <div className="w-full lg:w-[55%] bg-white relative flex flex-col min-h-0 border-r border-gray-100 group/stage overflow-hidden">
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
                <div ref={stageRef} className="relative flex-1 flex items-center justify-center p-6 md:p-12 overflow-hidden cursor-crosshair bg-white" onMouseEnter={() => setIsZooming(true)} onMouseLeave={() => setIsZooming(false)} onMouseMove={handleMouseMove}>
                    {activeMedia?.type === 'video' ? (
                        <div className="w-full h-full aspect-video rounded-lg shadow-2xl overflow-hidden bg-black max-w-4xl">
                            <iframe src={getYoutubeEmbedUrl(activeMedia.url)} className="w-full h-full" allowFullScreen></iframe>
                        </div>
                    ) : (
                        <div className="relative w-full h-full flex items-center justify-center overflow-hidden">
                            <img src={activeMedia?.url} alt={product.name} style={{ transformOrigin: `${zoomPos.x}% ${zoomPos.y}%`, transform: isZooming ? 'scale(2.5)' : 'scale(1)' }} className={`max-w-full max-h-[65vh] object-contain transition-transform duration-200 ease-out will-change-transform ${!isZooming ? 'drop-shadow-[0_15px_35px_rgba(0,0,0,0.1)]' : ''}`} />
                            {!isZooming && activeMedia?.type === 'image' && (
                                <div className="absolute bottom-4 flex items-center gap-2 bg-masuma-dark/5 backdrop-blur-md px-3 py-1.5 rounded-full border border-black/5"><ZoomIn size={12} className="text-masuma-orange" /><span className="text-[9px] font-black uppercase text-masuma-dark/60 tracking-widest">Precision Hover Zoom</span></div>
                            )}
                        </div>
                    )}
                    {media.length > 1 && (
                        <>
                            <button onClick={() => setActiveIndex((prev) => (prev - 1 + media.length) % media.length)} className="absolute left-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 z-50"><ChevronLeft size={24} /></button>
                            <button onClick={() => setActiveIndex((prev) => (prev + 1) % media.length)} className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 z-50"><ChevronRight size={24} /></button>
                        </>
                    )}
                </div>
                {media.length > 1 && (
                    <div className="h-24 bg-white border-t border-gray-100 flex items-center px-6 gap-3 overflow-x-auto scrollbar-hide">
                        {media.map((item, idx) => (
                            <button key={idx} onClick={() => setActiveIndex(idx)} className={`relative w-16 h-16 shrink-0 border-2 transition-all p-1.5 bg-gray-50 rounded-lg group/thumb ${activeIndex === idx ? 'border-masuma-orange scale-105 shadow-md bg-white' : 'border-transparent opacity-60 hover:opacity-100 hover:bg-white'}`}>{item.type === 'video' ? <div className="w-full h-full bg-masuma-dark flex items-center justify-center text-white rounded-md"><Play size={16} /></div> : <img src={item.url} className="w-full h-full object-contain rounded-sm transition-transform group-hover/thumb:scale-110" alt="" />}</button>
                        ))}
                    </div>
                )}
            </div>

            <div id="sidebar-content" className="w-full lg:w-[45%] flex flex-col bg-white overflow-y-auto border-l border-gray-100 scrollbar-hide">
                <div className="p-8 lg:p-10 space-y-8">
                    <div className="space-y-3">
                        <div className="flex flex-wrap gap-2">
                            <span className="px-2 py-0.5 bg-masuma-dark text-white text-[9px] font-black uppercase tracking-[0.2em] rounded-sm">{product.category}</span>
                            {product.stock ? (
                                <span className="text-green-600 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-green-50 px-2 py-0.5 rounded-sm"><Check size={10} strokeWidth={3} /> In Stock Nairobi</span>
                            ) : (
                                <span className="text-red-500 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-red-50 px-2 py-0.5 rounded-sm"><AlertTriangle size={10} strokeWidth={3} /> Special Order Only</span>
                            )}
                        </div>
                        <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold text-masuma-dark font-display uppercase leading-[0.9] tracking-tight">{product.name}</h2>

                        {/* Restored Price Breakdown */}
                        <div className="pt-6 border-t border-gray-50">
                            <div className="flex flex-col mb-4">
                                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest mb-1">Local Price Summary</span>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-5xl lg:text-6xl font-black text-masuma-orange tracking-tighter"><Price amount={product.price} /></span>
                                    <span className="text-[11px] font-bold text-gray-400 uppercase">incl. VAT</span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4 bg-gray-50 p-4 rounded-xl border border-gray-100">
                                <div className="flex flex-col">
                                    <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none">Net Unit Price</span>
                                    <span className="text-sm font-black text-masuma-dark mt-1"><Price amount={netPrice} /></span>
                                </div>
                                <div className="flex flex-col border-l border-gray-200 pl-4">
                                    <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none">VAT (16%)</span>
                                    <span className="text-sm font-black text-gray-600 mt-1"><Price amount={vatAmount} /></span>
