                    <div className="grid grid-cols-1 gap-6 py-6 border-y border-gray-100">
                        <div className="space-y-4">
                            <h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em] flex items-center gap-2 border-l-3 border-masuma-orange pl-3">Japanese Engineering Specs</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-3 gap-x-6 text-xs">
                                <div className="flex justify-between items-center group/spec"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Global SKU</span><span className="font-mono font-bold text-masuma-dark bg-gray-50 px-2 py-0.5 rounded transition-colors group-hover/spec:bg-masuma-orange group-hover/spec:text-white">{product.sku}</span></div>
                                <div className="flex justify-between items-center"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Grade</span><span className="font-bold text-masuma-dark">Japanese OE Std</span></div>
                            </div>
                            <div className="pt-2">
                                <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest block mb-2">OEM Reference Compatibility</span>
                                <div className="flex flex-wrap gap-1.5">
                                    {(product.oemNumbers || []).map((oem, i) => (
                                        <span key={i} className="px-2 py-1 bg-gray-100 text-gray-600 text-[10px] font-mono font-bold border border-gray-200 rounded-sm hover:border-masuma-orange hover:text-masuma-orange transition-colors cursor-default">{oem}</span>
