  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [media, setMedia] = useState<MediaItem[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [zoomPos, setZoomPos] = useState({ x: 50, y: 50 });
  const [isZooming, setIsZooming] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  const stageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && product) {
        setQuantity(1);
        setIsFullScreen(false);
        const items: MediaItem[] = [];
        if (product.image) items.push({ url: product.image, type: 'image' });
        if (product.images && Array.isArray(product.images)) {
            product.images.forEach(img => {
                if (img !== product.image) items.push({ url: img, type: 'image' });
            });
        }
        if (product.videoUrl) items.push({ url: product.videoUrl, type: 'video' });
        if (items.length === 0) items.push({ url: 'https://via.placeholder.com/800x800?text=No+Product+Image', type: 'image' });

        setMedia(items);
        setActiveIndex(0);
        fetchRelatedProducts(product);
    }
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=6`);
          const allProducts = res.data.data || res.data || [];
          setRelatedProducts(allProducts.filter((p: Product) => p.id !== currentProduct.id));
      } catch (error) {
          console.error("Failed to fetch related products", error);
      }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
      if (!stageRef.current) return;
      const { left, top, width, height } = stageRef.current.getBoundingClientRect();
      const x = ((e.clientX - left) / width) * 100;
      const y = ((e.clientY - top) / height) * 100;
      setZoomPos({ x, y });
  };

  if (!isOpen || !product) return null;

  const getYoutubeEmbedUrl = (url: string) => {
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      return id ? `https://www.youtube.com/embed/${id}?autoplay=1` : '';
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('sidebar-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  const activeMedia = media[activeIndex];
  const basePrice = product.price / 1.16;
  const vatAmount = product.price - basePrice;

  return (
    <>
      <SEO title={product.name} description={product.description} image={product.image} type="product" />

      <div className={`fixed inset-0 z-[2000] flex items-center justify-center overflow-hidden transition-all duration-500 ${isFullScreen ? 'p-0' : 'p-0 sm:p-4 md:p-6 lg:p-10'}`}>
        <div className="absolute inset-0 bg-masuma-dark/98 backdrop-blur-3xl transition-opacity" onClick={onClose}></div>

        <div className={`relative bg-white w-full h-full shadow-2xl flex flex-col overflow-hidden animate-scale-up border border-white/5 transition-all duration-500 ${isFullScreen ? 'max-w-none max-h-none rounded-none' : 'max-w-[1450px] max-h-[92vh] sm:rounded-xl'}`}>

          <div className="flex-shrink-0 h-14 flex items-center justify-between px-6 bg-white border-b border-gray-100 z-50">
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-2 px-3 py-1 bg-masuma-dark text-white rounded-full shadow-sm">
                    <Hash size={10} className="text-masuma-orange" />
                    <span className="text-[10px] font-black uppercase tracking-widest">{product.sku}</span>
                </div>
                <div className="h-4 w-px bg-gray-200 hidden md:block"></div>
                <span className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] hidden md:inline">Japanese Precision Specification</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setIsFullScreen(!isFullScreen)} className={`p-2 transition-colors ${isFullScreen ? 'text-masuma-orange' : 'text-gray-400 hover:text-masuma-dark'}`} title="Toggle Cinema Mode"><Maximize2 size={18} /></button>
                <button onClick={() => window.open(`https://wa.me/?text=Check this Masuma part: ${window.location.origin}/?product=${product.id}`, '_blank')} className="text-gray-400 hover:text-green-600 transition"><Share2 size={18}/></button>
                <button onClick={onClose} className="p-1 text-gray-400 hover:text-masuma-orange transition-colors"><X size={32} strokeWidth={1.5} /></button>
            </div>
          </div>

          <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
            <div className="w-full lg:w-[55%] bg-white relative flex flex-col min-h-0 border-r border-gray-100 group/stage overflow-hidden">
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'linear-gradient(#000 1px, transparent 1px), linear-gradient(90deg, #000 1px, transparent 1px)', backgroundSize: '40px 40px' }}></div>
                <div ref={stageRef} className="relative flex-1 flex items-center justify-center p-6 md:p-12 overflow-hidden cursor-crosshair bg-white" onMouseEnter={() => setIsZooming(true)} onMouseLeave={() => setIsZooming(false)} onMouseMove={handleMouseMove}>
                    {activeMedia?.type === 'video' ? (
                        <div className="w-full h-full aspect-video rounded-lg shadow-2xl overflow-hidden bg-black max-w-4xl">
                            <iframe src={getYoutubeEmbedUrl(activeMedia.url)} className="w-full h-full" allowFullScreen></iframe>
                        </div>
                    ) : (
                        <div className="relative w-full h-full flex items-center justify-center overflow-hidden">
                            <img src={activeMedia?.url} alt={product.name} style={{ transformOrigin: `${zoomPos.x}% ${zoomPos.y}%`, transform: isZooming ? 'scale(2.5)' : 'scale(1)' }} className={`max-w-full max-h-[65vh] object-contain transition-transform duration-200 ease-out will-change-transform ${!isZooming ? 'drop-shadow-[0_15px_35px_rgba(0,0,0,0.1)]' : ''}`} />
                            {!isZooming && activeMedia?.type === 'image' && (
                                <div className="absolute bottom-4 flex items-center gap-2 bg-masuma-dark/5 backdrop-blur-md px-3 py-1.5 rounded-full border border-black/5"><ZoomIn size={12} className="text-masuma-orange" /><span className="text-[9px] font-black uppercase text-masuma-dark/60 tracking-widest">Precision Hover Zoom</span></div>
                            )}
                        </div>
                    )}
                    {media.length > 1 && (
                        <>
                            <button onClick={() => setActiveIndex((prev) => (prev - 1 + media.length) % media.length)} className="absolute left-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 z-50"><ChevronLeft size={24} /></button>
                            <button onClick={() => setActiveIndex((prev) => (prev + 1) % media.length)} className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-white/90 hover:bg-white text-masuma-dark rounded-full shadow-xl opacity-0 group-hover/stage:opacity-100 transition-all border border-gray-100 z-50"><ChevronRight size={24} /></button>
                        </>
                    )}
                </div>
                {media.length > 1 && (
                    <div className="h-24 bg-white border-t border-gray-100 flex items-center px-6 gap-3 overflow-x-auto scrollbar-hide">
                        {media.map((item, idx) => (
                            <button key={idx} onClick={() => setActiveIndex(idx)} className={`relative w-16 h-16 shrink-0 border-2 transition-all p-1.5 bg-gray-50 rounded-lg group/thumb ${activeIndex === idx ? 'border-masuma-orange scale-105 shadow-md bg-white' : 'border-transparent opacity-60 hover:opacity-100 hover:bg-white'}`}>{item.type === 'video' ? <div className="w-full h-full bg-masuma-dark flex items-center justify-center text-white rounded-md"><Play size={16} /></div> : <img src={item.url} className="w-full h-full object-contain rounded-sm transition-transform group-hover/thumb:scale-110" alt="" />}</button>
                        ))}
                    </div>
                )}
            </div>

            <div id="sidebar-content" className="w-full lg:w-[45%] flex flex-col bg-white overflow-y-auto border-l border-gray-100 scrollbar-hide">
                <div className="p-8 lg:p-10 space-y-8">
                    <div className="space-y-3">
                        <div className="flex flex-wrap gap-2">
                            <span className="px-2 py-0.5 bg-masuma-dark text-white text-[9px] font-black uppercase tracking-[0.2em] rounded-sm">{product.category}</span>
                            {product.stock ? (
                                <span className="text-green-600 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-green-50 px-2 py-0.5 rounded-sm"><Check size={10} strokeWidth={3} /> In Stock Nairobi</span>
                            ) : (
                                <span className="text-red-500 text-[9px] font-black uppercase tracking-widest flex items-center gap-1 bg-red-50 px-2 py-0.5 rounded-sm"><AlertTriangle size={10} strokeWidth={3} /> Special Order Only</span>
                            )}
                        </div>
                        <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold text-masuma-dark font-display uppercase leading-[0.9] tracking-tight">{product.name}</h2>

                        {/* Accounting Style Price Breakdown */}
                        <div className="pt-6 border-t border-gray-50 space-y-4">
                            <div className="flex flex-col">
                                <span className="text-[10px] text-gray-400 font-black uppercase tracking-widest mb-1 flex items-center gap-1.5"><Calculator size={10}/> Total Price (Payable)</span>
                                <div className="flex items-baseline gap-2">
                                    <span className="text-5xl lg:text-6xl font-black text-masuma-orange tracking-tighter"><Price amount={product.price} /></span>
                                    <span className="text-[10px] font-bold text-gray-400 uppercase">incl. 16% VAT</span>
                                </div>
                            </div>

                            <div className="bg-gray-50 rounded-2xl border border-gray-100 overflow-hidden">
                                <div className="grid grid-cols-2 divide-x divide-gray-200">
                                    <div className="p-4">
                                        <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none block mb-1">Base Price</span>
                                        <span className="text-sm font-black text-masuma-dark"><Price amount={basePrice} /></span>
                                    </div>
                                    <div className="p-4">
                                        <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none block mb-1">VAT (16%)</span>
                                        <span className="text-sm font-black text-gray-600"><Price amount={vatAmount} /></span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 gap-6 py-6 border-y border-gray-100">
                        <div className="space-y-4">
                            <h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em] flex items-center gap-2 border-l-3 border-masuma-orange pl-3">Japanese Engineering Specs</h4>
                            <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-3 gap-x-6 text-xs">
                                <div className="flex justify-between items-center group/spec"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Global SKU</span><span className="font-mono font-bold text-masuma-dark bg-gray-50 px-2 py-0.5 rounded transition-colors group-hover/spec:bg-masuma-orange group-hover/spec:text-white">{product.sku}</span></div>
                                <div className="flex justify-between items-center"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Grade</span><span className="font-bold text-masuma-dark">Japanese OE Std</span></div>
                            </div>
                            <div className="pt-2">
                                <span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest block mb-2">OEM Reference Compatibility</span>
                                <div className="flex flex-wrap gap-1.5">
                                    {(product.oemNumbers || []).map((oem, i) => (
                                        <span key={i} className="px-2 py-1 bg-gray-100 text-gray-600 text-[10px] font-mono font-bold border border-gray-200 rounded-sm hover:border-masuma-orange hover:text-masuma-orange transition-colors cursor-default">{oem}</span>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-6">
                        <div>
                            <h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em] mb-3 opacity-60">Part Description</h4>
                            <p className="text-sm text-gray-600 leading-relaxed font-medium">{product.description}</p>
                        </div>
                        <div className="bg-masuma-dark text-white p-5 rounded-lg shadow-inner border-l-4 border-masuma-orange relative overflow-hidden">
                            <div className="absolute top-[-10px] right-[-10px] opacity-10 rotate-12"><Check size={48}/></div>
                            <h4 className="text-[10px] font-black uppercase tracking-[0.3em] mb-2 flex items-center gap-2">Verified Vehicle Fitment</h4>
                            <p className="text-xs text-gray-200 font-bold leading-relaxed">{(product.compatibility || []).join(' • ')}</p>
                            <p className="text-[9px] text-masuma-orange mt-3 uppercase font-black tracking-widest italic flex items-center gap-1"><AlertTriangle size={10}/> Chassis verification recommended for all orders</p>
                        </div>
                    </div>

                    <div className="pt-2 space-y-6">
                        <div className="flex gap-2">
                            {product.stock && (
                                <div className="flex items-center bg-gray-100 rounded-lg p-1 border border-gray-200">
                                    <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="w-8 h-12 flex items-center justify-center text-gray-400 hover:text-masuma-dark transition"><Minus size={14} /></button>
                                    <span className="w-8 text-center font-black text-masuma-dark text-md">{quantity}</span>
                                    <button onClick={() => setQuantity(q => q + 1)} className="w-8 h-12 flex items-center justify-center text-gray-400 hover:text-masuma-dark transition"><Plus size={14} /></button>
                                </div>
                            )}
                            <button onClick={() => { addToCart(product, quantity); onClose(); }} disabled={!product.stock} className={`flex-1 h-14 font-black uppercase tracking-[0.3em] text-[11px] lg:text-xs transition-all shadow-xl rounded-lg active:scale-95 ${product.stock ? 'bg-masuma-orange text-white hover:bg-masuma-dark' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>{product.stock ? 'Secure To Cart' : 'Currently Unavailable'}</button>
                            <button onClick={() => setIsQuoteModalOpen(true)} className="w-14 h-14 bg-masuma-dark text-white hover:bg-masuma-orange transition-all flex items-center justify-center rounded-lg shadow-xl active:scale-95" title="Technical Inquiry"><MessageCircle size={22} /></button>
                        </div>
                        <div className="grid grid-cols-2 gap-4 px-1">
                            <div className="flex items-center gap-3 opacity-80 group/feat"><div className="w-8 h-8 bg-gray-50 rounded-full flex items-center justify-center group-hover/feat:bg-masuma-orange transition-colors"><Truck size={16} className="text-masuma-orange group-hover/feat:text-white" /></div><span className="text-[9px] font-black uppercase tracking-tighter leading-tight text-gray-500">Same-Day <br/>Nairobi Area</span></div>
                            <div className="flex items-center gap-3 opacity-80 group/feat"><div className="w-8 h-8 bg-gray-50 rounded-full flex items-center justify-center group-hover/feat:bg-masuma-orange transition-colors"><ShieldCheck size={16} className="text-masuma-orange group-hover/feat:text-white" /></div><span className="text-[9px] font-black uppercase tracking-tighter leading-tight text-gray-500">12 Month <br/>Limited Warranty</span></div>
                        </div>
                    </div>

                    {relatedProducts.length > 0 && (
                        <div className="pt-6 space-y-4">
                            <div className="flex justify-between items-end"><h4 className="text-[10px] font-black text-masuma-dark uppercase tracking-[0.3em]">Complementary Parts</h4><span className="text-[8px] text-gray-400 font-bold uppercase">Local Availability</span></div>
                            <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                                {relatedProducts.map(rp => (
                                    <div key={rp.id} onClick={() => handleSwitch(rp)} className="min-w-[130px] w-[130px] bg-white border border-gray-100 p-2.5 hover:border-masuma-orange hover:shadow-lg transition-all cursor-pointer snap-start rounded-lg group/card">
                                        <div className="aspect-square flex items-center justify-center mb-2 bg-gray-50 overflow-hidden rounded-md"><img src={rp.image} className="max-h-full max-w-full object-contain p-2 group-hover/card:scale-110 transition-transform duration-500" alt="" /></div>
                                        <div className="text-[9px] font-bold text-masuma-dark line-clamp-2 h-6 leading-tight mb-1 uppercase tracking-tighter">{rp.name}</div>
                                        <div className="text-[10px] font-black text-masuma-orange">KES {rp.price.toLocaleString()}</div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
          </div>
        </div>
      </div>

      <QuoteModal isOpen={isQuoteModalOpen} onClose={() => setIsQuoteModalOpen(false)} product={product} />
    </>
  );
};

export default QuickView;

import React from 'react';
import { X, Trash2, Smartphone, Plus, Minus, ShieldCheck, ChevronRight } from 'lucide-react';
import { CartItem } from '../types';
import Price from './Price';

interface CartDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  cartItems: CartItem[];
  removeFromCart: (id: string) => void;
  onCheckout: () => void;
  updateQuantity: (id: string, quantity: number) => void;
}

const CartDrawer: React.FC<CartDrawerProps> = ({ isOpen, onClose, cartItems, removeFromCart, onCheckout, updateQuantity }) => {
  const total = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const basePriceTotal = total / 1.16;
  const vatTotal = total - basePriceTotal;

  return (
    <>
      {/* Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-masuma-dark/60 backdrop-blur-sm z-[1000] transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Drawer */}
      <div className={`fixed top-0 right-0 h-full w-full sm:w-[400px] bg-white z-[1001] transform transition-transform duration-500 ease-out shadow-2xl ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex flex-col h-full">

          {/* Header */}
          <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white">
            <div>
                <h2 className="text-xl font-bold font-display uppercase tracking-tight text-masuma-dark">Your Order</h2>
                <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">{cartItems.length} items selected</p>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-masuma-dark">
              <X size={24} />
            </button>
          </div>

          {/* Items List */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-gray-50/50">
            {cartItems.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-center">
                <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4 text-gray-300">
                    <Smartphone size={40} />
                </div>
                <h3 className="font-bold text-masuma-dark uppercase text-sm">Cart is Empty</h3>
                <p className="text-xs text-gray-400 mt-2 max-w-[200px]">Add genuine Masuma parts to start your local order.</p>
                <button onClick={onClose} className="mt-8 bg-masuma-dark text-white px-8 py-3 rounded font-bold text-[10px] uppercase tracking-widest hover:bg-masuma-orange transition shadow-lg">Browse Catalog</button>
              </div>
            ) : (
              cartItems.map((item) => (
                <div key={item.id} className="flex gap-4 bg-white p-4 rounded-2xl shadow-sm border border-gray-100 transition hover:shadow-md group">
                  <div className="h-20 w-20 bg-gray-50 rounded-xl overflow-hidden flex-shrink-0 flex items-center justify-center border border-gray-50">
                    <img src={item.image} alt={item.name} className="max-h-full max-w-full object-contain p-2 transition-transform group-hover:scale-110 duration-500" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex justify-between items-start gap-2">
                        <h4 className="font-bold text-xs text-masuma-dark line-clamp-2 leading-tight group-hover:text-masuma-orange transition-colors">{item.name}</h4>
                        <button 
                          onClick={() => removeFromCart(item.id)}
                          className="text-gray-300 hover:text-red-500 transition shrink-0"
                          title="Remove"
                        >
                          <Trash2 size={14} />
                        </button>
                    </div>
                    <p className="text-[9px] text-gray-400 font-mono tracking-wider mt-1 uppercase">SKU: {item.sku}</p>

                    <div className="flex justify-between items-center mt-3">
                      <span className="text-masuma-dark font-black text-sm">
                        <Price amount={item.price} />
                      </span>

                      <div className="flex items-center bg-gray-50 rounded-xl p-1 border border-gray-100">
                        <button 
                            onClick={() => updateQuantity(item.id, item.quantity - 1)} 
                            className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg text-gray-400 transition"
                            disabled={item.quantity <= 1}
                        >
                            <Minus size={12}/>
                        </button>
                        <span className="text-xs font-bold w-6 text-center text-masuma-dark">{item.quantity}</span>
                        <button 
                            onClick={() => updateQuantity(item.id, item.quantity + 1)} 
                            className="w-7 h-7 flex items-center justify-center hover:bg-white hover:shadow-sm rounded-lg text-gray-400 transition"
                        >
                            <Plus size={12}/>
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* Footer Actions */}
          {cartItems.length > 0 && (
              <div className="p-6 border-t border-gray-100 bg-white space-y-5">
                <div className="space-y-2">
                  <div className="flex justify-between items-center text-xs text-gray-500 font-medium">
                      <span>Subtotal (Base)</span>
                      <span><Price amount={basePriceTotal} /></span>
                  </div>
                  <div className="flex justify-between items-center text-xs text-gray-500 font-medium">
                      <span>VAT (16%)</span>
                      <span><Price amount={vatTotal} /></span>
                  </div>
                  <div className="h-px bg-gray-100 w-full my-1"></div>
                  <div className="flex justify-between items-end">
                      <div>
                          <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Payable</p>
                          <p className="text-2xl font-black text-masuma-orange tracking-tighter"><Price amount={total} /></p>
                      </div>
                      <div className="text-right">
                           <p className="text-[10px] text-green-600 font-black uppercase tracking-widest">All Taxes Incl.</p>
                      </div>
                  </div>
                </div>

                <button 
                  onClick={onCheckout}
                  className="w-full bg-masuma-dark text-white py-5 rounded-2xl font-black uppercase tracking-[0.25em] text-[10px] flex items-center justify-center gap-2 hover:bg-masuma-orange hover:-translate-y-1 transition-all shadow-xl shadow-masuma-dark/10"
                >
                  Checkout Now <ChevronRight size={16} />
                </button>

                <div className="flex items-center justify-center gap-3 opacity-40 grayscale group-hover:grayscale-0 transition-all">
                    <ShieldCheck size={16} />
                    <span className="text-[8px] font-black uppercase tracking-widest">Secure Regional Checkout</span>
                </div>
              </div>
          )}

        </div>
      </div>
    </>
  );
};

export default CartDrawer;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, ArrowLeft, Smartphone, CreditCard, Loader2, CheckCircle, AlertCircle, MapPin, User, Mail, Phone, Lock, ChevronRight, Package, Truck } from 'lucide-react';
import { CartItem, Product, ViewState } from '../types';
import { apiClient } from '../utils/apiClient';
import Price from './Price';
import SEO from './SEO';

interface CheckoutProps {
