@tailwind base;
@tailwind components;
@tailwind utilities;

/* Custom Base Styles */
body { 
  font-family: 'Inter', sans-serif; 
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

h1, h2, h3, h4, h5, h6 { 
  font-family: 'Oswald', sans-serif; 
}

/* Custom Utilities */
@layer utilities {
  .scrollbar-hide::-webkit-scrollbar {
      display: none;
  }
  .scrollbar-hide {
      -ms-overflow-style: none;
      scrollbar-width: none;
  }

  .media-protected {
    @apply select-none pointer-events-none;
    -webkit-user-drag: none;
    -khtml-user-drag: none;
    -moz-user-drag: none;
    -o-user-drag: none;
  }

  .animate-slide-up {
    animation: slideUp 0.4s ease-out;
  }

  .animate-scale-up {
    animation: scaleUp 0.3s ease-out;
  }

  .animate-fade-in {
    animation: fadeIn 0.5s ease-out;
  }

  .animate-slide-right {
    animation: slideRight 0.6s ease-out;
  }

  .animate-pulse-once {
    animation: pulseOnce 0.5s ease-in-out;
  }
}

/* Manual Prose Styling */
.prose h1 { @apply text-3xl font-bold mb-4 text-masuma-dark font-display uppercase; }
.prose h2 { @apply text-2xl font-bold mb-3 mt-6 text-masuma-dark font-display uppercase; }
.prose h3 { @apply text-xl font-bold mb-2 mt-4 text-masuma-dark font-display uppercase; }
.prose p { @apply mb-4 leading-relaxed text-gray-600; }
.prose ul { @apply list-disc pl-5 mb-4 text-gray-600; }
.prose ol { @apply list-decimal pl-5 mb-4 text-gray-600; }
.prose li { @apply mb-1; }
.prose a { @apply text-masuma-orange hover:underline font-bold; }
.prose blockquote { @apply border-l-4 border-masuma-orange pl-4 italic my-4 text-gray-500; }
.prose strong { @apply font-bold text-gray-800; }

/* Keyframes */
@keyframes slideUp {
  0% { transform: translateY(20px); opacity: 0; }
  100% { transform: translateY(0); opacity: 1; }
}

@keyframes scaleUp {
  0% { transform: scale(0.95); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes fadeIn {
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes slideRight {
  0% { transform: translateX(100%); }
  100% { transform: translateX(0); }
}

@keyframes pulseOnce {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2); }
}

/* --- ROBUST PRINT STYLES --- */
@media print {
  body {
    background: white !important;
    height: auto !important;
    width: 100% !important;
    overflow: visible !important;
    margin: 0 !important;
    padding: 0 !important;
  }

  body * {
    visibility: hidden;
  }

  .print-force-container {
    visibility: visible !important;
    position: fixed !important; 
    top: 0 !important;
    left: 0 !important;
    width: 100% !important;
    height: 100% !important;
    margin: 0 !important;
    padding: 0 !important;
    background: white !important;
    z-index: 99999 !important;
    display: block !important;
    overflow: visible !important;
  }

  .print-force-container * {
    visibility: visible !important;
  }

  nav, header, footer, button, input, select, .no-print {
    display: none !important;
  }

  body {
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  @page {
    margin: 0;
    size: auto;
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { X, Check, AlertTriangle, Truck, MessageCircle, Plus, Minus, Share2, ChevronLeft, ChevronRight, Play, Info, ShieldCheck, Settings, Hash, Maximize2, ZoomIn, ReceiptText, Calculator, Shield } from 'lucide-react';
import { Product } from '../types';
import QuoteModal from './QuoteModal';
import Price from './Price';
import { apiClient } from '../utils/apiClient';
import SEO from './SEO';

interface QuickViewProps {
  product: Product | null;
  isOpen: boolean;
  onClose: () => void;
  addToCart: (product: Product, quantity?: number) => void;
  onSwitchProduct?: (product: Product) => void;
}

interface MediaItem {
    url: string;
    type: 'image' | 'video';
}

const QuickView: React.FC<QuickViewProps> = ({ product, isOpen, onClose, addToCart, onSwitchProduct }) => {
  const [isQuoteModalOpen, setIsQuoteModalOpen] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [relatedProducts, setRelatedProducts] = useState<Product[]>([]);
  const [media, setMedia] = useState<MediaItem[]>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const [zoomPos, setZoomPos] = useState({ x: 50, y: 50 });
  const [isZooming, setIsZooming] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  const stageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && product) {
        setQuantity(1);
        setIsFullScreen(false);
        const items: MediaItem[] = [];
        if (product.image) items.push({ url: product.image, type: 'image' });
        if (product.images && Array.isArray(product.images)) {
            product.images.forEach(img => {
                if (img !== product.image) items.push({ url: img, type: 'image' });
            });
        }
        if (product.videoUrl) items.push({ url: product.videoUrl, type: 'video' });
        if (items.length === 0) items.push({ url: 'https://via.placeholder.com/800x800?text=No+Product+Image', type: 'image' });

        setMedia(items);
        setActiveIndex(0);
        fetchRelatedProducts(product);
    }
  }, [isOpen, product]);

  const fetchRelatedProducts = async (currentProduct: Product) => {
      try {
          const res = await apiClient.get(`/products?category=${currentProduct.category}&limit=6`);
          const allProducts = res.data.data || res.data || [];
          setRelatedProducts(allProducts.filter((p: Product) => p.id !== currentProduct.id));
      } catch (error) {
          console.error("Failed to fetch related products", error);
      }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
      if (!stageRef.current) return;
      const { left, top, width, height } = stageRef.current.getBoundingClientRect();
      const x = ((e.clientX - left) / width) * 100;
      const y = ((e.clientY - top) / height) * 100;
      setZoomPos({ x, y });
  };

  if (!isOpen || !product) return null;

  const getYoutubeEmbedUrl = (url: string) => {
      const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
      const match = url.match(regExp);
      const id = (match && match[2].length === 11) ? match[2] : null;
      return id ? `https://www.youtube.com/embed/${id}?autoplay=1` : '';
  };

  const handleSwitch = (p: Product) => {
      if (onSwitchProduct) {
          const contentDiv = document.getElementById('sidebar-content');
          if (contentDiv) contentDiv.scrollTop = 0;
          onSwitchProduct(p);
      }
  };

  const activeMedia = media[activeIndex];
  const basePrice = product.price / 1.16;
  const vatAmount = product.price - basePrice;

  return (
    <>
      <SEO title={product.name} description={product.description} image={product.image} type="product" />

