                        <span 
                            className="bg-white text-masuma-dark hover:text-masuma-orange px-8 py-4 font-black uppercase text-[10px] tracking-[0.25em] flex items-center gap-2 transform translate-y-8 group-hover:translate-y-0 transition duration-500 shadow-2xl rounded-xl"
                        >
                            <Eye size={16} /> Quick View
                        </span>
                    </div>
                </div>

                <div className="p-6 flex-1 flex flex-col">
