                    className={`h-1 transition-all rounded-full ${i === currentSlide ? 'w-12 bg-masuma-orange' : 'w-4 bg-white/30 hover:bg-white/60'}`}
                  ></button>
              ))}
          </div>
      )}

    </div>
    </>
  );
};

