                    <div className="absolute top-0 left-0 p-4 w-full flex justify-between items-start">
                        <span className="bg-white/80 backdrop-blur-md text-masuma-dark text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-[0.1em] border border-gray-100 shadow-sm">
