                                <div className="grid grid-cols-2 divide-x divide-gray-200">
                                    <div className="p-4">
                                        <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none block mb-1">Base Price</span>
                                        <span className="text-sm font-black text-masuma-dark"><Price amount={basePrice} /></span>
                                    </div>
                                    <div className="p-4">
                                        <span className="text-[9px] text-gray-400 font-black uppercase tracking-widest leading-none block mb-1">VAT (16%)</span>
