                                <div className="flex justify-between items-center group/spec"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Global SKU</span><span className="font-mono font-bold text-masuma-dark bg-gray-50 px-2 py-0.5 rounded transition-colors group-hover/spec:bg-masuma-orange group-hover/spec:text-white">{product.sku}</span></div>
                                <div className="flex justify-between items-center"><span className="text-gray-400 uppercase font-bold text-[9px] tracking-widest">Grade</span><span className="font-bold text-masuma-dark">Japanese OE Std</span></div>
