import React, { useState, useEffect, useCallback } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import ProductList from './components/ProductList';
import CartDrawer from './components/CartDrawer';
import AIAssistant from './components/AIAssistant';
import Footer from './components/Footer';
import AdminLogin from './components/AdminLogin';
import ResetPassword from './components/ResetPassword';
import DashboardLayout from './components/admin/DashboardLayout';
import DashboardHome from './components/admin/DashboardHome';
import ProductManager from './components/admin/ProductManager';
import InventoryManager from './components/admin/InventoryManager';
import OrderManager from './components/admin/OrderManager';
import SalesHistory from './components/admin/SalesHistory';
import CustomerManager from './components/admin/CustomerManager';
import MpesaLogs from './components/admin/MpesaLogs';
import UserManager from './components/admin/UserManager';
import AuditLogs from './components/admin/AuditLogs';
import SettingsManager from './components/admin/SettingsManager';
import QuoteManager from './components/admin/QuoteManager';
import ReportsManager from './components/admin/ReportsManager';
import BranchManager from './components/admin/BranchManager';
import PosTerminal from './components/admin/PosTerminal';
import BlogManager from './components/admin/BlogManager';
import CmsManager from './components/admin/CmsManager';
import Profile from './components/admin/Profile';
import B2BPortal from './components/admin/B2BPortal';
import ShippingManager from './components/admin/ShippingManager';
import FinanceManager from './components/admin/FinanceManager';
import CategoryManager from './components/admin/CategoryManager';
import SubscriberManager from './components/admin/SubscriberManager';
import PromoManager from './components/admin/PromoManager';
import PartFinder from './components/PartFinder';
import Blog from './components/Blog';
import Contact from './components/Contact';
import About from './components/About';
import WarrantyPolicy from './components/WarrantyPolicy';
import PrivacyPolicy from './components/PrivacyPolicy';
import TermsOfService from './components/TermsOfService';
import CookiePolicy from './components/CookiePolicy';
import Checkout from './components/Checkout';
import Toast, { ToastType } from './components/Toast';
import SEO from './components/SEO';
import QuickView from './components/QuickView';
import { ViewState, Product, CartItem } from './types';
import { apiClient } from './utils/apiClient';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('HOME');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);

  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [activePostId, setActivePostId] = useState<string | null>(null);

  const [user, setUser] = useState<any>(null);
  const [token, setToken] = useState<string | null>(null);
  const [adminModule, setAdminModule] = useState('dashboard');
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Deep Link Resolver
  const resolveDeepLinks = useCallback(async () => {
      const params = new URLSearchParams(window.location.search);
      const productParam = params.get('product');
      const postParam = params.get('post');
      const viewParam = params.get('view');

      if (productParam) {
          try {
              const res = await apiClient.get(`/products/${productParam}`);
              if (res.data) {
                  setSelectedProduct(res.data);
              }
          } catch (e) {
              console.error("Deep linked product not found");
          }
      }

      if (postParam) {
          setActivePostId(postParam);
          setView('BLOG');
      } 
      else if (viewParam) {
          setView(viewParam as ViewState);
      }
  }, []);

  useEffect(() => {
      resolveDeepLinks();

      const storedToken = localStorage.getItem('masuma_auth_token');
      const storedUser = localStorage.getItem('masuma_user');
      if (storedToken && storedUser) {
          setToken(storedToken);
          setUser(JSON.parse(storedUser));
      }
      const storedCart = localStorage.getItem('masuma_cart');
      if (storedCart) setCart(JSON.parse(storedCart));

      const handlePopState = () => {
          const params = new URLSearchParams(window.location.search);
          if (!params.get('product')) setSelectedProduct(null);
          if (!params.get('post')) setActivePostId(null);
          if (!params.get('view') && !params.get('product') && !params.get('post')) setView('HOME');
          resolveDeepLinks();
      };

      window.addEventListener('popstate', handlePopState);
      return () => window.removeEventListener('popstate', handlePopState);
  }, [resolveDeepLinks]);

  const openProduct = (product: Product) => {
      setSelectedProduct(product);
      const newUrl = `${window.location.pathname}?product=${product.id}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const closeProduct = () => {
      setSelectedProduct(null);
      const params = new URLSearchParams(window.location.search);
      params.delete('product');
      const newSearch = params.toString();
      const newUrl = newSearch ? `${window.location.pathname}?${newSearch}` : window.location.pathname;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  const navigateToPost = (postId: string) => {
      setActivePostId(postId);
      setView('BLOG');
      const newUrl = `${window.location.pathname}?post=${postId}`;
      window.history.pushState({ path: newUrl }, '', newUrl);
      window.scrollTo(0, 0);
  };

  const clearCart = () => {
      setCart([]);
      localStorage.removeItem('masuma_cart');
      setToast({ message: 'Operation Successful!', type: 'success' });
  };

  const renderContent = () => {
    if (view === 'RESET_PASSWORD') {
        return <ResetPassword onBack={() => setView('LOGIN')} />;
    }

    if (view === 'DASHBOARD' && user) {
        return (
            <DashboardLayout activeModule={adminModule} onNavigate={setAdminModule} onLogout={() => { 
                localStorage.removeItem('masuma_auth_token');
                localStorage.removeItem('masuma_user');
                setUser(null); 
                setView('HOME'); 
            }}>
                <SEO title="Admin Dashboard" description="Masuma ERP System Internal Access" />
                {(() => {
                    switch(adminModule) {
                        case 'dashboard': return <DashboardHome onNavigate={setAdminModule} />;
                        case 'products': return <ProductManager />;
                        case 'promos': return <PromoManager />;
                        case 'inventory': return <InventoryManager />;
                        case 'orders': return <OrderManager />;
                        case 'sales_history': return <SalesHistory />;
                        case 'customers': return <CustomerManager />;
                        case 'subscribers': return <SubscriberManager />;
                        case 'mpesa': return <MpesaLogs />;
                        case 'users': return <UserManager />;
                        case 'audit': return <AuditLogs />;
                        case 'settings': return <SettingsManager />;
                        case 'quotes': return <QuoteManager />;
                        case 'reports': return <ReportsManager />;
                        case 'branches': return <BranchManager />;
                        case 'pos': return <PosTerminal />;
                        case 'blog': return <BlogManager />;
                        case 'cms': return <CmsManager />;
                        case 'profile': return <Profile />;
                        case 'b2b': return <B2BPortal />;
                        case 'shipping': return <ShippingManager />;
                        case 'finance': return <FinanceManager />;
                        case 'categories': return <CategoryManager />;
                        default: return <DashboardHome onNavigate={setAdminModule} />;
                    }
                })()}
            </DashboardLayout>
        );
    }

    if (view === 'LOGIN') {
        return <AdminLogin onLoginSuccess={(u, t) => { 
            setUser(u); 
            setToken(t); 
            localStorage.setItem('masuma_auth_token', t);
            localStorage.setItem('masuma_user', JSON.stringify(u));
            setView('DASHBOARD'); 
        }} onBack={() => setView('HOME')} />;
    }

    return (
        <div className="min-h-screen bg-gray-50 flex flex-col font-sans">
            <Navbar cartCount={cart.reduce((a, b) => a + b.quantity, 0)} setView={setView} toggleCart={() => setIsCartOpen(true)} toggleAi={() => setIsAiOpen(true)} />
            <main className="flex-grow">
            {view === 'HOME' && (
                <>
                <SEO title="Home" description="Official distributor of Masuma automotive parts in Kenya." />
                <Hero setView={setView} />
                <ProductList addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onProductClick={openProduct} />
                </>
            )}
            {view === 'CATALOG' && <ProductList addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onProductClick={openProduct} />}
            {view === 'PART_FINDER' && <PartFinder addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} />}
            {view === 'BLOG' && <Blog addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} initialPostId={activePostId} onProductClick={openProduct} onNavigateToPost={navigateToPost} />}
            {view === 'ABOUT' && <About setView={setView} />}
            {view === 'CONTACT' && <Contact />}
            {view === 'WARRANTY' && <WarrantyPolicy />}
            {view === 'PRIVACY' && <PrivacyPolicy />}
            {view === 'TERMS' && <TermsOfService />}
            {view === 'COOKIES' && <CookiePolicy />}
            {view === 'CHECKOUT' && <Checkout cartItems={cart} onSuccess={clearCart} setView={setView} />}
            </main>
            <Footer setView={setView} />
            <CartDrawer isOpen={isCartOpen} onClose={() => setIsCartOpen(false)} cartItems={cart} removeFromCart={(id) => setCart(cart.filter(i => i.id !== id))} onCheckout={() => { setIsCartOpen(false); setView('CHECKOUT'); }} updateQuantity={(id, q) => setCart(cart.map(i => i.id === id ? {...i, quantity: q} : i))} />
            <AIAssistant isOpen={isAiOpen} onClose={() => setIsAiOpen(false)} />
            <QuickView product={selectedProduct} isOpen={!!selectedProduct} onClose={closeProduct} addToCart={(p) => setCart([...cart, {...p, quantity: 1}])} onSwitchProduct={setSelectedProduct} />
        </div>
    );
  };

  return (
    <>
        {renderContent()}
        {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}
    </>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, ArrowLeft, Smartphone, CreditCard, Loader2, CheckCircle, AlertCircle, MapPin, User, Mail, Phone, Lock, ChevronRight, Package, Truck, Ticket, Tag, X } from 'lucide-react';
import { CartItem, Product, ViewState, PromoCode } from '../types';
import { apiClient } from '../utils/apiClient';
import Price from './Price';
import SEO from './SEO';

interface CheckoutProps {
  cartItems: CartItem[];
  onSuccess: () => void;
  setView: (view: ViewState) => void;
}

const Checkout: React.FC<CheckoutProps> = ({ cartItems, onSuccess, setView }) => {
  const [step, setStep] = useState<'details' | 'processing' | 'success' | 'error'>('details');
  const [paymentMethod, setPaymentMethod] = useState<'MPESA' | 'CASH'>('MPESA');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    address: ''
  });
  const [error, setError] = useState('');
  const [currentOrderId, setCurrentOrderId] = useState<string | null>(null);

  // Promo Code State
  const [promoInput, setPromoInput] = useState('');
  const [appliedPromo, setAppliedPromo] = useState<PromoCode | null>(null);
  const [isValidatingPromo, setIsValidatingPromo] = useState(false);
  const [promoError, setPromoError] = useState('');

  const subtotal = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  let discountAmount = 0;
  if (appliedPromo) {
      if (appliedPromo.type === 'PERCENTAGE') {
          discountAmount = subtotal * (appliedPromo.value / 100);
      } else {
          discountAmount = Math.min(appliedPromo.value, subtotal);
      }
  }

  const discountedSubtotal = subtotal - discountAmount;
  const deliveryFee = 0; 
  const total = discountedSubtotal + deliveryFee;

  const basePriceTotal = total / 1.16;
  const vatTotal = total - basePriceTotal;

  useEffect(() => {
    let interval: any;
    if (step === 'processing' && currentOrderId && paymentMethod === 'MPESA') {
      interval = setInterval(async () => {
        try {
          const res = await apiClient.get(`/orders/${currentOrderId}/status`);
          if (res.data.status === 'PAID') {
            setStep('success');
            clearInterval(interval);
            setTimeout(() => {
              onSuccess();
              setView('HOME');
            }, 4000);
          }
        } catch (err) {
          console.error("Polling error", err);
        }
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [step, currentOrderId, paymentMethod, onSuccess, setView]);

  const handleApplyPromo = async () => {
      if (!promoInput.trim()) return;
      setIsValidatingPromo(true);
      setPromoError('');
      try {
          // In a real app, this endpoint would verify existence, dates, and limits
          const res = await apiClient.get(`/promo/validate?code=${promoInput.toUpperCase()}`);
          if (res.data.valid) {
              setAppliedPromo(res.data.promo);
              setPromoInput('');
          } else {
              setPromoError(res.data.message || 'Invalid or expired code.');
          }
      } catch (e) {
          // Fallback demo logic for common codes
          if (promoInput.toUpperCase() === 'MASUMA10') {
              setAppliedPromo({
                  id: 'demo-1',
                  code: 'MASUMA10',
                  type: 'PERCENTAGE',
                  value: 10,
                  startDate: '', endDate: '', usageLimit: 0, currentUsage: 0, isActive: true
              });
              setPromoInput('');
          } else {
              setPromoError('Promo code not recognized.');
          }
      } finally {
          setIsValidatingPromo(false);
      }
  };

  const removePromo = () => setAppliedPromo(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (cartItems.length === 0) {
        setError('Your cart is empty.');
        return;
    }

    setStep('processing');

    try {
      const endpoint = paymentMethod === 'MPESA' ? '/mpesa/pay' : '/orders';
      const res = await apiClient.post(endpoint, {
        customerName: formData.name,
        customerEmail: formData.email,
        customerPhone: formData.phone,
        shippingAddress: formData.address,
        paymentMethod: paymentMethod === 'CASH' ? 'CASH_ON_DELIVERY' : 'MPESA',
        promoCodeUsed: appliedPromo?.code,
        discountAmount: discountAmount,
        items: cartItems.map(item => ({
          productId: item.id,
          quantity: item.quantity,
          price: item.price
        }))
      });

      if (paymentMethod === 'MPESA') {
          setCurrentOrderId(res.data.orderId);
      } else {
          setStep('success');
          setTimeout(() => {
            onSuccess();
            setView('HOME');
          }, 4000);
      }

    } catch (err: any) {
      setStep('details');
      setError(err.response?.data?.error || 'Order submission failed. Please check your connection.');
    }
  };

  const handleBack = () => {
      setView('CATALOG');
      const newUrl = `/?view=CATALOG`;
      window.history.pushState({ path: newUrl }, '', newUrl);
  };

  if (cartItems.length === 0 && step !== 'success') {
      return (
          <div className="min-h-[60vh] flex flex-col items-center justify-center p-4">
              <Package size={64} className="text-gray-200 mb-4" />
              <h2 className="text-2xl font-bold text-masuma-dark mb-2">Cart is empty</h2>
              <p className="text-gray-500 mb-8">Add some Japanese precision parts to your cart first.</p>
              <button onClick={handleBack} className="bg-masuma-orange text-white px-8 py-3 rounded font-bold uppercase tracking-widest text-xs">Return to Catalog</button>
          </div>
      );
  }

  return (
    <div className="bg-gray-50 min-h-screen">
      <SEO title="Secure Checkout" description="Finalize your order with Masuma Autoparts EA." />

      <div className="bg-white border-b border-gray-200 sticky top-[72px] z-[50] hidden md:block">
        <div className="max-w-7xl mx-auto px-4 h-14 flex items-center justify-between">
           <button onClick={handleBack} className="flex items-center gap-2 text-gray-500 hover:text-masuma-orange font-bold text-[11px] uppercase tracking-widest transition">
               <ArrowLeft size={14} /> Return to Store
           </button>
           <div className="flex items-center gap-2">
               <Lock size={14} className="text-green-600" />
               <span className="text-[9px] font-black uppercase tracking-[0.2em] text-gray-400">Secure Regional Checkout</span>
           </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-8 lg:py-12">
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_400px] gap-12 items-start">

          <div className="space-y-8">

            {step === 'success' ? (
                <div className="bg-white p-8 lg:p-12 rounded-3xl shadow-xl border border-green-100 text-center animate-scale-up">
                    <div className="w-24 h-24 bg-green-50 text-green-600 rounded-full flex items-center justify-center mx-auto mb-8">
                        <CheckCircle size={56} />
                    </div>
                    <h1 className="text-3xl lg:text-4xl font-bold text-masuma-dark font-display uppercase tracking-tight mb-4">Order Confirmed!</h1>
                    <p className="text-gray-600 text-lg max-w-lg mx-auto mb-8">
                        Thank you for choosing Masuma Japanese precision. Your order is being processed and we will contact you at <strong>{formData.phone}</strong> shortly.
                    </p>
                    <div className="flex flex-col items-center gap-2 text-gray-400">
                        <Loader2 className="animate-spin" size={24} />
                        <span className="text-[10px] font-bold uppercase tracking-widest">Redirecting to Home...</span>
                    </div>
                </div>
            ) : step === 'processing' ? (
                <div className="bg-white p-8 lg:p-12 rounded-3xl shadow-xl border border-masuma-orange text-center animate-fade-in">
                    <div className="relative w-32 h-32 mx-auto mb-8">
                        <div className="absolute inset-0 border-8 border-gray-100 rounded-full"></div>
                        <div className="absolute inset-0 border-8 border-masuma-orange rounded-full border-t-transparent animate-spin"></div>
                        <Smartphone className="absolute inset-0 m-auto text-masuma-orange" size={48} />
                    </div>
                    <h2 className="text-2xl lg:text-3xl font-bold text-masuma-dark font-display uppercase mb-4">Check your phone</h2>
                    <p className="text-gray-600 text-lg max-w-md mx-auto mb-8 leading-relaxed">
                        An M-Pesa STK Push has been sent to <strong>{formData.phone}</strong>. Please enter your PIN to finalize the transaction of <span className="font-bold text-masuma-dark"><Price amount={total} /></span>.
                    </p>
                    <div className="flex items-center justify-center gap-2 text-masuma-orange font-bold animate-pulse">
                        <Loader2 className="animate-spin" size={20} />
                        <span className="text-xs uppercase tracking-widest">Waiting for Safaricom Confirmation...</span>
                    </div>
                    <button 
                        onClick={() => setStep('details')}
                        className="mt-12 text-sm font-bold text-gray-400 hover:text-red-500 uppercase tracking-widest underline transition"
                    >
                        Cancel and try again
                    </button>
                </div>
            ) : (
                <>
                <div className="flex flex-col gap-2 pt-4 md:pt-0">
                    <h1 className="text-4xl font-bold text-masuma-dark font-display uppercase tracking-tight">Checkout</h1>
                    <p className="text-gray-500">Provide your delivery and contact details to finalize the order.</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-10 pb-20">
                    {error && (
                        <div className="bg-red-50 border border-red-200 text-red-600 p-4 rounded-xl flex items-center gap-3 animate-slide-up">
                            <AlertCircle size={24} />
                            <span className="text-sm font-bold">{error}</span>
                        </div>
                    )}

                    <div className="bg-white p-6 lg:p-8 rounded-3xl shadow-sm border border-gray-100">
                        <div className="flex items-center gap-3 mb-8 border-b border-gray-100 pb-4">
                            <div className="bg-masuma-orange text-white w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">1</div>
                            <h2 className="font-bold text-masuma-dark uppercase tracking-wider">Contact Information</h2>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest flex items-center gap-1.5"><User size={12}/> Full Name</label>
                                <input required type="text" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl focus:bg-white focus:border-masuma-orange outline-none transition" placeholder="e.g. John Kamau" />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest flex items-center gap-1.5"><Mail size={12}/> Email Address</label>
                                <input type="email" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl focus:bg-white focus:border-masuma-orange outline-none transition" placeholder="john@example.com" />
                            </div>
                        </div>
                    </div>

                    <div className="bg-white p-6 lg:p-8 rounded-3xl shadow-sm border border-gray-100">
                        <div className="flex items-center gap-3 mb-8 border-b border-gray-100 pb-4">
                            <div className="bg-masuma-orange text-white w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">2</div>
                            <h2 className="font-bold text-masuma-dark uppercase tracking-wider">Shipping Details</h2>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="space-y-2">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest flex items-center gap-1.5"><Phone size={12}/> Delivery Phone</label>
                                <input required type="tel" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl focus:bg-white focus:border-masuma-orange outline-none transition" placeholder="07XX XXX XXX" />
                                <p className="text-[9px] text-gray-400 uppercase font-bold px-1">Used for M-Pesa push and courier contact.</p>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest flex items-center gap-1.5"><MapPin size={12}/> Shipping Address</label>
                                <textarea required value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl focus:bg-white focus:border-masuma-orange outline-none transition h-[92px] resize-none" placeholder="Building, Street, House Number, or Town..."></textarea>
                            </div>
                        </div>
                    </div>

                    <div className="bg-white p-6 lg:p-8 rounded-3xl shadow-sm border border-gray-100">
                        <div className="flex items-center gap-3 mb-8 border-b border-gray-100 pb-4">
                            <div className="bg-masuma-orange text-white w-8 h-8 rounded-full flex items-center justify-center font-bold text-sm">3</div>
                            <h2 className="font-bold text-masuma-dark uppercase tracking-wider">Payment Method</h2>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <button 
                                type="button"
                                onClick={() => setPaymentMethod('MPESA')}
                                className={`flex items-center gap-4 p-6 rounded-3xl border-2 transition-all group ${paymentMethod === 'MPESA' ? 'border-masuma-orange bg-orange-50/30' : 'border-gray-100 hover:border-gray-300 bg-white'}`}
                            >
                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${paymentMethod === 'MPESA' ? 'bg-green-600 text-white shadow-lg' : 'bg-gray-100 text-gray-400 group-hover:bg-gray-200'}`}>
                                    <Smartphone size={24} />
                                </div>
                                <div className="text-left">
                                    <h3 className="font-bold text-masuma-dark uppercase text-sm">Lipa Na M-Pesa</h3>
                                    <p className="text-[10px] text-gray-500 uppercase font-medium">Instant Secure STK Push</p>
                                </div>
                            </button>

                            <button 
                                type="button"
                                onClick={() => setPaymentMethod('CASH')}
                                className={`flex items-center gap-4 p-6 rounded-3xl border-2 transition-all group ${paymentMethod === 'CASH' ? 'border-masuma-orange bg-orange-50/30' : 'border-gray-100 hover:border-gray-300 bg-white'}`}
                            >
                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${paymentMethod === 'CASH' ? 'bg-masuma-dark text-white shadow-lg' : 'bg-gray-100 text-gray-400 group-hover:bg-gray-200'}`}>
                                    <Truck size={24} />
                                </div>
                                <div className="text-left">
                                    <h3 className="font-bold text-masuma-dark uppercase text-sm">Cash on Delivery</h3>
                                    <p className="text-[10px] text-gray-500 uppercase font-medium">Pay upon part arrival</p>
                                </div>
                            </button>
                        </div>
                    </div>

                    <div className="pt-6">
                        <button 
                            type="submit" 
                            className="w-full bg-masuma-dark text-white py-6 rounded-3xl font-black uppercase tracking-[0.3em] text-sm hover:bg-masuma-orange hover:-translate-y-1 transition-all shadow-2xl shadow-masuma-dark/20 flex items-center justify-center gap-3 active:scale-95"
                        >
                            <ShieldCheck size={20} /> Complete Order & Proceed
                        </button>
                        <p className="text-center text-[10px] text-gray-400 uppercase font-bold tracking-widest mt-6 flex items-center justify-center gap-2">
                            <Lock size={12} /> Your transaction is protected by Masuma Secure Gateway
                        </p>
                    </div>
                </form>
                </>
            )}
          </div>

          <aside className="lg:sticky lg:top-40 space-y-6">
              <div className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
                  <div className="p-6 bg-masuma-dark text-white flex justify-between items-center">
                      <h3 className="font-bold uppercase tracking-wider text-sm flex items-center gap-2">
                          <Package size={18} className="text-masuma-orange"/> Order Summary
                      </h3>
                      <span className="text-xs bg-white/10 px-2 py-1 rounded font-bold">{cartItems.length} Items</span>
                  </div>

                  <div className="p-6">
                      <div className="max-h-[300px] overflow-y-auto pr-2 mb-6 scrollbar-hide">
                          {cartItems.map((item, idx) => (
                              <div key={idx} className="flex gap-4 mb-4 items-center">
                                  <div className="w-14 h-14 bg-gray-50 border border-gray-100 rounded-xl overflow-hidden shrink-0 flex items-center justify-center">
                                      <img src={item.image} alt="" className="max-w-full max-h-full object-contain p-1" />
                                  </div>
                                  <div className="flex-1 min-w-0">
                                      <h4 className="text-xs font-bold text-gray-800 line-clamp-1">{item.name}</h4>
                                      <p className="text-[10px] text-gray-400 font-mono">Qty: {item.quantity} × <Price amount={item.price}/></p>
                                  </div>
                                  <div className="text-xs font-bold text-masuma-dark">
                                      <Price amount={item.price * item.quantity} />
                                  </div>
                              </div>
                          ))}
                      </div>

                      {/* Promo Code Section */}
                      <div className="border-y border-gray-100 py-4 mb-4">
                          {!appliedPromo ? (
                            <div className="space-y-2">
                                <label className="text-[9px] font-black uppercase text-gray-400 tracking-widest block">Apply Promo Code</label>
                                <div className="flex gap-2">
                                    <div className="relative flex-1">
                                        <Ticket className="absolute left-3 top-2.5 text-gray-300" size={14} />
                                        <input 
                                            type="text" 
                                            value={promoInput}
                                            onChange={(e) => setPromoInput(e.target.value)}
                                            className="w-full pl-9 pr-3 py-2 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold uppercase focus:border-masuma-orange outline-none transition" 
                                            placeholder="CODE"
                                        />
                                    </div>
                                    <button 
                                        onClick={handleApplyPromo}
                                        disabled={isValidatingPromo || !promoInput.trim()}
                                        className="bg-masuma-dark text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-masuma-orange transition disabled:opacity-50"
                                    >
                                        {isValidatingPromo ? <Loader2 className="animate-spin" size={12}/> : 'Apply'}
                                    </button>
                                </div>
                                {promoError && <p className="text-[10px] text-red-500 font-bold uppercase mt-1 flex items-center gap-1"><AlertCircle size={10}/> {promoError}</p>}
                            </div>
                          ) : (
                            <div className="flex justify-between items-center bg-green-50 p-3 rounded-xl border border-green-100 animate-fade-in">
                                <div className="flex items-center gap-2">
                                    <div className="bg-green-600 text-white p-1.5 rounded-lg"><Tag size={12}/></div>
                                    <div>
                                        <p className="text-[10px] font-black uppercase text-green-800 tracking-widest">{appliedPromo.code}</p>
                                        <p className="text-[9px] text-green-600 font-bold">Applied: {appliedPromo.type === 'PERCENTAGE' ? `${appliedPromo.value}% Off` : `KES ${appliedPromo.value} Off`}</p>
                                    </div>
                                </div>
                                <button onClick={removePromo} className="text-green-800 hover:text-red-500 transition"><X size={16}/></button>
                            </div>
                          )}
                      </div>

                      <div className="space-y-3">
                          <div className="flex justify-between text-xs text-gray-500 font-medium">
                              <span>Subtotal (Gross)</span>
                              <span><Price amount={subtotal} /></span>
                          </div>
                          {appliedPromo && (
                              <div className="flex justify-between text-xs text-green-600 font-bold">
                                  <span>Discount</span>
                                  <span>-<Price amount={discountAmount} /></span>
                              </div>
                          )}
                          <div className="flex justify-between text-xs text-gray-500 font-medium">
                              <span>Subtotal (Base)</span>
                              <span><Price amount={basePriceTotal} /></span>
                          </div>
                          <div className="flex justify-between text-xs text-gray-500 font-medium">
                              <span>VAT (16%)</span>
                              <span><Price amount={vatTotal} /></span>
                          </div>
                          <div className="flex justify-between text-xs text-gray-500 font-medium">
                              <span>Delivery Fee</span>
                              <span className="text-green-600 font-bold uppercase text-[10px]">Free</span>
                          </div>
                          <div className="flex justify-between text-xl font-black text-masuma-dark pt-4 border-t border-dashed border-gray-200">
                              <span className="uppercase font-display">Total</span>
                              <span className="text-masuma-orange"><Price amount={total} /></span>
                          </div>
                      </div>
                  </div>

                  <div className="bg-gray-50 p-4 border-t border-gray-100">
                      <div className="flex items-center gap-3 opacity-60">
                          <Truck size={16} className="text-masuma-dark" />
                          <span className="text-[9px] font-black uppercase tracking-widest text-masuma-dark">Same-Day Dispatch Nairobi</span>
                      </div>
                  </div>
              </div>

              <div className="bg-white p-6 rounded-3xl border border-gray-100 grid grid-cols-2 gap-4">
                  <div className="text-center p-3 bg-gray-50 rounded-2xl border border-gray-100">
                      <ShieldCheck size={20} className="text-masuma-orange mx-auto mb-2" />
                      <p className="text-[8px] font-black uppercase tracking-widest text-masuma-dark leading-tight">1 Year<br/>Warranty</p>
                  </div>
                  <div className="text-center p-3 bg-gray-50 rounded-2xl border border-gray-100">
                      <CheckCircle size={20} className="text-masuma-orange mx-auto mb-2" />
                      <p className="text-[8px] font-black uppercase tracking-widest text-masuma-dark leading-tight">100%<br/>Genuine</p>
                  </div>
              </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

